```typescript
import { Worker, Site, WorkLog, AppConfig, LogType } from '../types';

const KEYS = {
  WORKERS: 'carmagne_workers',
  SITES: 'carmagne_sites',
  LOGS: 'carmagne_logs',
  CONFIG: 'carmagne_config',
};

// Initial Seed Data - LISTA 1: TRABAJADORES
const INITIAL_WORKERS: Worker[] = [
  { id: 'W001', name: 'Antonio García', dni: '12345678A', role: 'Jefe de Obra', phone: '600102030', qrCode: 'QR_W001', pin: '1234', active: true },
  { id: 'W002', name: 'María Martínez', dni: '87654321B', role: 'Oficial 1ª', phone: '600405060', qrCode: 'QR_W002', pin: '0000', active: true },
  { id: 'W003', name: 'José López', dni: '11223344C', role: 'Peón Especialista', phone: '600708090', qrCode: 'QR_W003', pin: '5555', active: true },
  { id: 'W004', name: 'Lucía Fernández', dni: '99887766D', role: 'Arquitecta Técnica', phone: '600112233', qrCode: 'QR_W004', pin: '9876', active: true },
  { id: 'W005', name: 'Manuel González', dni: '55667788E', role: 'Encargado General', phone: '600445566', qrCode: 'QR_W005', pin: '1111', active: true },
  { id: 'W006', name: 'Sofía Ruiz', dni: '44332211F', role: 'Electricista', phone: '600998877', qrCode: 'QR_W006', pin: '2024', active: true }
];

// Initial Seed Data - LISTA 2: OBRAS
const INITIAL_SITES: Site[] = [
  { 
    id: 'S001', 
    name: 'Residencial Las Flores', 
    address: 'Av. de la Libertad 45', 
    coordinates: { latitude: 40.416775, longitude: -3.703790 },
    active: true 
  },
  { 
    id: 'S002', 
    name: 'Torre Empresarial Norte', 
    address: 'Polígono Industrial A-4, Parcela 3', 
    coordinates: { latitude: 40.456775, longitude: -3.653790 },
    active: true 
  },
  { 
    id: 'S003', 
    name: 'Rehabilitación Centro Histórico', 
    address: 'Calle Mayor 12', 
    coordinates: { latitude: 40.415225, longitude: -3.707500 },
    active: true 
  },
  { 
    id: 'S004', 
    name: 'Centro Comercial Vallesur', 
    address: 'Ctra. Nacional VI, km 20', 
    coordinates: { latitude: 40.500000, longitude: -3.800000 },
    active: true 
  }
];

const INITIAL_CONFIG: AppConfig = {
  adminPhone: '34631400010', 
  googleSheetUrl: 'https://docs.google.com/spreadsheets/d/Mg...',
};

// Helpers
const load = <T>(key: string, initial: T): T => {
  const saved = localStorage.getItem(key);
  return saved ? JSON.parse(saved) : initial;
};

const save = <T>(key: string, data: T): void => {
  localStorage.setItem(key, JSON.stringify(data));
};

// Service Methods
export const StorageService = {
  getWorkers: (): Worker[] => load(KEYS.WORKERS, INITIAL_WORKERS),
  saveWorkers: (workers: Worker[]) => save(KEYS.WORKERS, workers),

  getSites: (): Site[] => load(KEYS.SITES, INITIAL_SITES),
  saveSites: (sites: Site[]) => save(KEYS.SITES, sites),

  getLogs: (): WorkLog[] => load(KEYS.LOGS, []),
  addLog: (log: WorkLog) => {
    const logs = load<WorkLog[]>(KEYS.LOGS, []);
    save(KEYS.LOGS, [log, ...logs]); // Newest first
  },

  getConfig: (): AppConfig => load(KEYS.CONFIG, INITIAL_CONFIG),
  saveConfig: (config: AppConfig) => save(KEYS.CONFIG, config),

  // Mock function to simulate Google Sheets export
  exportToCSV: (logs: WorkLog[]): string => {
    const headers = ['ID Registro', 'Nombre Trabajador', 'ID Trabajador', 'Obra', 'Tipo', 'Fecha', 'Hora', 'Latitud', 'Longitud', 'Google Maps', 'URL Selfie'];
    const rows = logs.map(l => [
      l.id,
      l.workerName,
      l.workerId,
      l.siteName,
      l.type,
      l.dateStr,
      l.timeStr,
      l.location.latitude,
      l.location.longitude,
      `https://www.google.com/maps?q=${l.location.latitude},${l.location.longitude}`,
      l.photoUrl ? 'IMAGEN_ADJUNTA' : 'N/A'
    ]);
    return [headers.join(','), ...rows.map(r => r.join(','))].join('\n');
  }
};
