```typescript
import React, { useState, useEffect } from 'react';
import { 
  User, MapPin, CheckCircle, 
  LogOut, Coffee, ArrowRight, ShieldAlert, Lock, QrCode, Fingerprint, Delete
} from 'lucide-react';
import { StorageService } from './services/storageService';
import { LocationService } from './services/locationService';
import { Worker, Site, WorkLog, LogType, GeoLocationData } from './types';
import { AdminPanel } from './components/AdminPanel';

// App Steps
enum Step {
  IDENTIFY = 0,
  AUTHENTICATE = 1,
  SELECT_SITE = 2,
  SELECT_ACTION = 3,
  SUCCESS = 5
}

function App() {
  const [isAdmin, setIsAdmin] = useState(false);
  const [currentStep, setCurrentStep] = useState<Step>(Step.IDENTIFY);

  // Selection State
  const [selectedWorker, setSelectedWorker] = useState<Worker | null>(null);
  const [selectedSite, setSelectedSite] = useState<Site | null>(null);
  const [selectedAction, setSelectedAction] = useState<LogType | null>(null);
  const [location, setLocation] = useState<GeoLocationData | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  // Authentication State
  const [pinInput, setPinInput] = useState('');
  const [biometricsAvailable, setBiometricsAvailable] = useState(false);

  // Data
  const [workers, setWorkers] = useState<Worker[]>([]);
  const [sites, setSites] = useState<Site[]>([]);

  // QR Simulation Input
  const [qrInput, setQrInput] = useState('');

  useEffect(() => {
    // Load initial data
    setWorkers(StorageService.getWorkers());
    setSites(StorageService.getSites());

    // Check for Biometrics Support (simulated using WebAuthn availability)
    if (window.PublicKeyCredential) {
      window.PublicKeyCredential.isUserVerifyingPlatformAuthenticatorAvailable()
        .then(isAvailable => {
          setBiometricsAvailable(isAvailable);
        })
        .catch(err => console.error("Bio check failed", err));
    }
  }, []);

  const handleQrScan = (code: string) => {
    let searchId = code;

    // Check if the QR is the JSON format requested {id_trabajador: '...', ...}
    try {
      const parsed = JSON.parse(code);
      if (parsed.id_trabajador) {
        searchId = parsed.id_trabajador;
      }
    } catch (e) {
      // Not JSON, assume simple ID string (legacy)
    }

    const worker = workers.find(w => w.qrCode === searchId || w.id === searchId);
    if (worker) {
      setSelectedWorker(worker);
      setPinInput('');
      setCurrentStep(Step.AUTHENTICATE); // Move to Auth instead of Site
      setError('');
    } else {
      setError('Código QR no reconocido.');
    }
  };

  const handleManualSelect = (workerId: string) => {
    const worker = workers.find(w => w.id === workerId);
    if (worker) {
      setSelectedWorker(worker);
      setPinInput('');
      setCurrentStep(Step.AUTHENTICATE); // Move to Auth instead of Site
    }
  };

  const handlePinInput = (digit: string) => {
    if (pinInput.length < 4) {
      const newPin = pinInput + digit;
      setPinInput(newPin);

      // Auto-submit on 4 digits
      if (newPin.length === 4) {
        verifyAuth(newPin);
      }
    }
  };

  const handlePinClear = () => {
    setPinInput('');
    setError('');
  };

  const verifyAuth = (pinToVerify: string) => {
    if (selectedWorker && selectedWorker.pin === pinToVerify) {
      setCurrentStep(Step.SELECT_SITE);
      setError('');
    } else {
      setError('PIN Incorrecto');
      setTimeout(() => setPinInput(''), 500);
    }
  };

  const handleBiometricAuth = async () => {
    try {
      setError('');
      // We simulate a biometric check using WebAuthn.
      // In a real PWA, this would check against a registered credential ID.
      // Here, we just check if the OS allows us to prompt the user (TouchID/FaceID).

      // This will trigger the browser's native auth dialog
      const publicKeyCredentialCreationOptions: PublicKeyCredentialCreationOptions = {
        challenge: Uint8Array.from(
            "RANDOM_CHALLENGE_STRING", c => c.charCodeAt(0)),
        rp: {
            name: "CARMAGNE SOLU",
            id: window.location.hostname,
        },
        user: {
            id: Uint8Array.from(
                "USER_ID", c => c.charCodeAt(0)),
            name: selectedWorker?.name || "worker",
            displayName: selectedWorker?.name || "Worker",
        },
        pubKeyCredParams: [{alg: -7, type: "public-key"}],
        authenticatorSelection: {
            authenticatorAttachment: "platform",
            userVerification: "required"
        },
        timeout: 60000,
        attestation: "direct"
      };

      // We use 'create' here just to force the OS prompt for "Identity Verification"
      // In production, you would use navigator.credentials.get() with a stored ID.
      await navigator.credentials.create({
        publicKey: publicKeyCredentialCreationOptions
      });

      // If we get here, the user passed the OS biometric check
      setCurrentStep(Step.SELECT_SITE);

    } catch (err) {
      console.error(err);
      setError('Autenticación biométrica fallida o cancelada.');
    }
  };

  const handleSiteSelect = (siteId: string) => {
    const site = sites.find(s => s.id === siteId);
    if (site) {
      setSelectedSite(site);
      setCurrentStep(Step.SELECT_ACTION);
      // Start getting location early in background
      LocationService.getCurrentPosition()
        .then(loc => setLocation(loc))
        .catch(err => console.warn("Background loc failed", err));
    }
  };

  const handleActionSelect = async (type: LogType) => {
    setSelectedAction(type);
    setLoading(true);
    setError('');

    try {
      // 1. Ensure Location
      let loc = location;
      if (!loc) {
        loc = await LocationService.getCurrentPosition();
        setLocation(loc);
      }

      // 2. Submit Log directly (Camera step removed)
      await submitLog(loc!, type, undefined);

    } catch (err: any) {
      setLoading(false);
      setError('Error obteniendo ubicación GPS. Active el GPS y reintente.');
    }
  };

  const submitLog = async (loc: GeoLocationData, type: LogType, photoUrl?: string) => {
    if (!selectedWorker || !selectedSite) return;

    setLoading(true);
    const now = new Date();
    const config = StorageService.getConfig();

    const newLog: WorkLog = {
      id: `LOG-${Date.now()}`,
      workerId: selectedWorker.id,
      workerName: selectedWorker.name,
      siteId: selectedSite.id,
      siteName: selectedSite.name,
      type: type,
      timestamp: now.getTime(),
      dateStr: now.toLocaleDateString('es-ES'),
      timeStr: now.toLocaleTimeString('es-ES'),
      location: loc,
      photoUrl: photoUrl, // Will be undefined now
      sentToWhatsapp: true,
      syncedToSheets: false // Simulation
    };

    // Save locally
    StorageService.addLog(newLog);

    // Prepare WhatsApp Message with Google Maps Link
    const mapsLink = `https://www.google.com/maps?q=${loc.latitude},${loc.longitude}`;
    const message = `*FICHAJE CARMAGNE 2024*\n` +
      `👷 ${selectedWorker.name} (ID: ${selectedWorker.id})\n` +
      `🏗️ ${selectedSite.name}\n` +
      `🔄 *${type}*\n` +
      `📅 ${newLog.dateStr} - ${newLog.timeStr}\n` +
      `📍 ${loc.address || 'Ubicación'}\n` +
      `🗺️ ${mapsLink}\n` + 
      `🆔 ${newLog.id}`;

    const whatsappUrl = `https://wa.me/${config.adminPhone}?text=${encodeURIComponent(message)}`;

    // Finish
    setCurrentStep(Step.SUCCESS);
    setLoading(false);

    // Open WhatsApp automatically
    setTimeout(() => {
      window.open(whatsappUrl, '_blank');
    }, 1000);
  };

