A continuación, actualizo el código interno para habilitar esta sincronización en la nube:

Para lograr que el Google Sheets se vea profesional, organizado por pestañas (una para cada trabajador) y con colores automáticos según el tipo de fichaje (Verde para entrada, Rojo para salida, etc.), **no necesitamos cambiar la App**, sino actualizar el **"Cerebro" (el Script)** que creaste en Google Sheets.

Aquí tienes el nuevo código mejorado para tu Google Apps Script.

### Pasos para actualizarlo:

1.  Ve a tu Google Sheet.
2.  Menú **Extensiones** > **Apps Script**.
3.  Borra **todo** el código antiguo.
4.  Copia y pega este nuevo código avanzado:

```javascript
function doPost(e) {
  var lock = LockService.getScriptLock();
  lock.tryLock(10000);

  try {
    var doc = SpreadsheetApp.getActiveSpreadsheet();
    var rawData = e.postData.contents;
    var data = JSON.parse(rawData);

    // --- 1. PESTAÑA MAESTRA (Base de datos completa oculta/backup) ---
    // Guardamos todo junto por seguridad, pero esta hoja la puedes ignorar
    var masterSheetName = 'BASEDATOS_GLOBAL';
    var masterSheet = doc.getSheetByName(masterSheetName);

    if (!masterSheet) {
      masterSheet = doc.insertSheet(masterSheetName);
      masterSheet.appendRow(['ID', 'Trabajador', 'Acción', 'Fecha', 'Hora', 'Obra', 'Modo', 'Reporte', 'Mapa', 'Alerta']);
      masterSheet.setTabColor("#000000"); // Color negro
    }

    masterSheet.appendRow([
      data.id, data.workerName, data.type, data.dateStr, data.timeStr, 
      data.siteName, data.workMode, data.workReport, 
      'https://maps.google.com/?q=' + data.location.latitude + ',' + data.location.longitude,
      data.locationWarning ? 'SI' : ''
    ]);

    // --- 2. PESTAÑA INDIVIDUAL DEL TRABAJADOR ---
    // El nombre de la pestaña será el nombre del trabajador
    var workerName = data.workerName.trim().toUpperCase();
    // Limpieza de caracteres por seguridad
    if (workerName.length > 50) workerName = workerName.substring(0, 50);

    var workerSheet = doc.getSheetByName(workerName);

    // Si es la primera vez que ficha este trabajador, creamos su pestaña y la ponemos bonita
    if (!workerSheet) {
      workerSheet = doc.insertSheet(workerName);

      // CREAR ENCABEZADOS PROFESIONALES
      var headers = [['FECHA', 'HORA', 'ACCIÓN', 'OBRA', 'MODO TRABAJO', 'REPORTE / NOTAS', 'UBICACIÓN', 'INCIDENCIA']];
      var headerRange = workerSheet.getRange('A1:H1');
      headerRange.setValues(headers);

      // ESTILO DEL ENCABEZADO (Azul Carmagne, Texto Blanco, Negrita, Centrado)
      headerRange.setBackground('#1e293b')
                 .setFontColor('#ffffff')
                 .setFontWeight('bold')
                 .setHorizontalAlignment('center')
                 .setVerticalAlignment('middle');

      // Congelar la primera fila para que siempre se vea al bajar
      workerSheet.setFrozenRows(1); 

      // Ajustar anchos de columna para que se lea bien
      workerSheet.setColumnWidth(1, 100); // Fecha
      workerSheet.setColumnWidth(2, 80);  // Hora
      workerSheet.setColumnWidth(3, 150); // Acción
      workerSheet.setColumnWidth(4, 200); // Obra
      workerSheet.setColumnWidth(6, 250); // Reporte más ancho
    }

    // --- 3. INSERTAR DATOS ---
    workerSheet.appendRow([
      data.dateStr,
      data.timeStr,
      data.type,      // ENTRADA, SALIDA...
      data.siteName,
      data.workMode || 'HORAS',
      data.workReport || '',
      'Ver Mapa',    // Texto temporal, abajo lo convertimos en link
      data.locationWarning ? '⚠️ LEJOS (>500m)' : ''
    ]);

    // --- 4. FORMATO CONDICIONAL Y VISUAL (COLORES) ---
    var lastRow = workerSheet.getLastRow();
    var rowRange = workerSheet.getRange(lastRow, 1, 1, 8);
    var mapCell = workerSheet.getRange(lastRow, 7); // Columna G

    // Crear el hipervínculo bonito en la celda de mapa
    var mapUrl = 'https://maps.google.com/?q=' + data.location.latitude + ',' + data.location.longitude;
    mapCell.setFormula('=HYPERLINK("' + mapUrl + '"; "📍 Ver Mapa")');

    // COLORES AUTOMÁTICOS SEGÚN ACCIÓN
    if (data.type == 'ENTRADA') {
      // Verde suave para entradas
      rowRange.setBackground('#dcfce7').setFontColor('#14532d'); 
    } else if (data.type == 'SALIDA') {
      // Rojo suave para salidas
      rowRange.setBackground('#fee2e2').setFontColor('#7f1d1d');
    } else if (data.type.indexOf('DESCANSO') > -1) {
      // Amarillo para descansos
      rowRange.setBackground('#fef9c3').setFontColor('#713f12');
    }

    // Centrar datos de fecha y hora
    workerSheet.getRange(lastRow, 1, 1, 2).setHorizontalAlignment('center');

    return ContentService.createTextOutput(JSON.stringify({"result":"success"})).setMimeType(ContentService.MimeType.JSON);

  } catch (e) {
    return ContentService.createTextOutput(JSON.stringify({"error": e.toString()})).setMimeType(ContentService.MimeType.JSON);
  } finally {
    lock.releaseLock();
  }
}
```

