      if (workerLogs.length > 0) {
        reports.push({
          workerId: worker.id,
          workerName: worker.name,
          totalPresenceMs: totalPresence,
          totalBreakMs: totalBreaks,
          netWorkMs: Math.max(0, totalPresence - totalBreaks),
          daysWorked: daysSet.size
        });
      }
    });

    return reports;
