      return log.workerId === summary.workerId && d.getFullYear() === year && (d.getMonth() + 1) === month;
    }).sort((a, b) => a.timestamp - b.timestamp);

    // Header
    doc.setFillColor(15, 23, 42); // slate-900
    doc.rect(0, 0, 210, 40, 'F');

