                       placeholder="PIN"
                     />
                     <input 
                       type="password" 
                       value={regPinConfirm}
                       onChange={(e) => setRegPinConfirm(e.target.value.replace(/\D/g,'').slice(0,4))}
                       className="w-full bg-slate-950 border border-slate-800 text-white rounded-lg p-3.5 text-center tracking-widest text-lg focus:border-amber-500 focus:outline-none transition-colors"
                       placeholder="Repetir"
