                </div>
              </div>
            )}
          </div>
        </div>

        <h3 className="text-slate-400 text-sm font-bold uppercase tracking-wider px-2 mt-2">Acciones Rápidas</h3>

        <div className="grid grid-cols-1 gap-4 flex-1">
           <button 
             onClick={() => setCurrentStep(Step.SELECT_SITE)}
             className="group relative overflow-hidden bg-slate-800 hover:bg-slate-700 border border-slate-700 hover:border-blue-500/50 transition-all p-6 rounded-2xl shadow-lg flex items-center justify-between"
           >
             <div className="relative z-10 text-left">
               <span className="block text-xl font-bold text-white group-hover:text-blue-400 transition-colors">Nuevo Fichaje</span>
               <span className="text-slate-400 text-sm">Entrada, Salida o Pausa</span>
             </div>
             <div className="relative z-10 bg-slate-900 p-3 rounded-full text-blue-500 group-hover:scale-110 transition-transform duration-300 shadow-inner">
               <Clock size={24} />
             </div>
           </button>

           <button 
             onClick={() => setCurrentStep(Step.WORKER_HISTORY)}
             className="group relative overflow-hidden bg-slate-800 hover:bg-slate-700 border border-slate-700 hover:border-purple-500/50 transition-all p-6 rounded-2xl shadow-lg flex items-center justify-between"
           >
             <div className="relative z-10 text-left">
               <span className="block text-xl font-bold text-white group-hover:text-purple-400 transition-colors">Mi Historial</span>
               <span className="text-slate-400 text-sm">Ver mis horas y actividad</span>
             </div>
             <div className="relative z-10 bg-slate-900 p-3 rounded-full text-purple-500 group-hover:scale-110 transition-transform duration-300 shadow-inner">
               <History size={24} />
             </div>
           </button>
        </div>
      </div>
    );
  };

  const renderWorkerHistory = () => {
    const { totalMs, logs: dayLogs } = getDailyStats(historyDate);

    return (
      <div className="flex flex-col gap-4 animate-fadeIn h-full">
