              <p className="text-slate-400 text-xs">Completa los datos personales.</p>
            </div>

            <div className="flex flex-col gap-4 bg-slate-900 p-6 rounded-2xl border border-slate-800 shadow-xl">
               <div>
                 <label className="block text-[10px] uppercase text-slate-500 font-bold mb-1.5 tracking-wider">Nombre Completo *</label>
                 <input 
                   type="text" 
                   value={regName}
                   onChange={(e) => setRegName(e.target.value)}
                   className="w-full bg-slate-950 border border-slate-800 text-white rounded-lg p-3.5 focus:border-blue-500 focus:outline-none transition-colors text-sm"
                   placeholder="Ej: Juan Pérez"
                 />
               </div>

               <div className="grid grid-cols-2 gap-4">
                 <div>
                   <label className="block text-[10px] uppercase text-slate-500 font-bold mb-1.5 tracking-wider">DNI/NIE *</label>
                   <input 
                     type="text" 
                     value={regDni}
                     onChange={(e) => setRegDni(e.target.value)}
                     className="w-full bg-slate-950 border border-slate-800 text-white rounded-lg p-3.5 focus:border-blue-500 focus:outline-none transition-colors text-sm"
                     placeholder="12345678X"
                   />
                 </div>
                 <div>
                   <label className="block text-[10px] uppercase text-slate-500 font-bold mb-1.5 tracking-wider">Teléfono</label>
                   <input 
                     type="tel" 
                     value={regPhone}
                     onChange={(e) => setRegPhone(e.target.value)}
                     className="w-full bg-slate-950 border border-slate-800 text-white rounded-lg p-3.5 focus:border-blue-500 focus:outline-none transition-colors text-sm"
                     placeholder="600..."
                   />
                 </div>
               </div>

               <div>
                 <label className="block text-[10px] uppercase text-slate-500 font-bold mb-1.5 tracking-wider">Cargo / Puesto</label>
                 <input 
                   type="text" 
                   value={regRole}
                   onChange={(e) => setRegRole(e.target.value)}
                   className="w-full bg-slate-950 border border-slate-800 text-white rounded-lg p-3.5 focus:border-blue-500 focus:outline-none transition-colors text-sm"
                   placeholder="Ej: Oficial 1ª"
                 />
               </div>

               <div className="border-t border-slate-800 my-2 pt-4">
                  <div className="flex items-center gap-2 mb-4 text-blue-500">
                     <Lock size={14} />
                     <span className="font-bold text-xs uppercase tracking-wide">Seguridad (PIN)</span>
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                     <input 
                       type="password" 
                       value={regPin}
                       onChange={(e) => setRegPin(e.target.value.replace(/\D/g,'').slice(0,4))}
                       className="w-full bg-slate-950 border border-slate-800 text-white rounded-lg p-3.5 text-center tracking-widest text-lg focus:border-blue-500 focus:outline-none transition-colors"
                       placeholder="PIN"
                     />
                     <input 
                       type="password" 
                       value={regPinConfirm}
                       onChange={(e) => setRegPinConfirm(e.target.value.replace(/\D/g,'').slice(0,4))}
                       className="w-full bg-slate-950 border border-slate-800 text-white rounded-lg p-3.5 text-center tracking-widest text-lg focus:border-blue-500 focus:outline-none transition-colors"
                       placeholder="Repetir"
                     />
                  </div>
               </div>
            </div>

            <button 
              onClick={handleRegistration}
              className="bg-emerald-600 hover:bg-emerald-500 text-white p-4 rounded-xl flex items-center justify-center gap-2 shadow-lg font-bold text-sm uppercase tracking-wide mt-2 transition-colors"
            >
              {loading ? 'Guardando...' : <><Save size={18} /> Crear Ficha</>}
            </button>
          </div>
        )}

        {/* STEP 2: AUTHENTICATION */}
        {currentStep === Step.AUTHENTICATE && (
          <div className="flex flex-col gap-6 animate-fadeIn items-center justify-center flex-1">
             <button onClick={resetApp} className="text-slate-400 hover:text-white self-start absolute top-0 text-sm font-medium transition">
              ← Cambiar Usuario
            </button>

            <div className="text-center mb-6 mt-4">
               <div className="w-24 h-24 bg-slate-900 rounded-full flex items-center justify-center mx-auto mb-6 border border-slate-800 shadow-2xl">
                 <Lock size={32} className="text-blue-500" />
               </div>
               <h2 className="text-2xl font-bold text-white mb-1">Hola, {selectedWorker?.name.split(' ')[0]}</h2>
               <p className="text-slate-400 text-sm">Introduce tu código de acceso</p>
            </div>

            {/* PIN Dots */}
            <div className="flex gap-4 mb-8">
              {[0, 1, 2, 3].map(i => (
                <div 
                  key={i} 
                  className={`w-3 h-3 rounded-full transition-all duration-300 ${
                    i < pinInput.length ? 'bg-blue-500 scale-125 shadow-[0_0_10px_rgba(59,130,246,0.5)]' : 'bg-slate-800'
                  }`}
                />
              ))}
            </div>

            {/* Numeric Keypad */}
            <div className="grid grid-cols-3 gap-4 w-full max-w-[280px]">
              {[1, 2, 3, 4, 5, 6, 7, 8, 9].map(num => (
                <button
                  key={num}
                  onClick={() => handlePinInput(num.toString())}
                  className="h-16 rounded-2xl bg-slate-900 text-white text-xl font-bold hover:bg-slate-800 active:bg-blue-600 active:text-white transition-all shadow-lg border border-slate-800"
                >
                  {num}
                </button>
              ))}
              <div className="flex items-center justify-center">
                {biometricsAvailable && (
                   <button 
                     onClick={handleBiometricAuth}
                     className="h-14 w-14 rounded-full bg-slate-800 text-blue-400 flex items-center justify-center hover:bg-slate-700 hover:text-white transition shadow-lg border border-slate-700"
                   >
                     <Fingerprint size={24} />
                   </button>
                )}
              </div>
              <button
                onClick={() => handlePinInput('0')}
                className="h-16 rounded-2xl bg-slate-900 text-white text-xl font-bold hover:bg-slate-800 active:bg-blue-600 active:text-white transition-all shadow-lg border border-slate-800"
              >
                0
              </button>
              <button
                onClick={handlePinClear}
                className="h-16 flex items-center justify-center text-rose-500 hover:text-rose-400 transition"
              >
                <Delete size={24} />
              </button>
            </div>
          </div>
        )}

        {/* WORKER DASHBOARD */}
        {currentStep === Step.WORKER_DASHBOARD && renderWorkerDashboard()}

        {/* WORKER HISTORY */}
        {currentStep === Step.WORKER_HISTORY && renderWorkerHistory()}

        {/* STEP 3: SITE SELECTION */}
        {currentStep === Step.SELECT_SITE && (
          <div className="flex flex-col gap-6 animate-fadeIn">
            <button onClick={() => setCurrentStep(Step.WORKER_DASHBOARD)} className="text-slate-400 hover:text-white self-start mb-2 flex items-center gap-1 text-sm font-medium transition">
              <ChevronLeft size={16} /> Volver
            </button>

            <div className="text-center pb-4">
               <div className="inline-flex items-center gap-2 bg-emerald-950/50 text-emerald-400 px-3 py-1.5 rounded-full text-[10px] font-bold uppercase tracking-widest border border-emerald-900/50 mb-3">
                 <CheckCircle size={10} /> Identidad Verificada
               </div>
               <h2 className="text-2xl font-bold text-white">Selecciona Obra</h2>
            </div>

            <div className="grid gap-3">
              {sites.filter(s => s.active).map(site => (
                <button
                  key={site.id}
                  onClick={() => handleSiteSelect(site.id)}
                  className="group bg-slate-900 hover:bg-slate-800 border border-slate-800 hover:border-blue-500/50 p-5 rounded-xl text-left transition-all relative overflow-hidden"
                >
                  <div className="absolute top-0 right-0 p-4 opacity-5 group-hover:opacity-10 text-white transition-opacity">
                    <MapPin size={64} />
                  </div>
                  <h3 className="text-lg font-bold text-white mb-1 relative z-10">{site.name}</h3>
                  <p className="text-xs text-slate-400 flex items-center gap-2 relative z-10 font-medium">
                    <MapPin size={12} className="text-blue-500" /> {site.address}
                  </p>
                </button>
              ))}
            </div>
          </div>
        )}

        {/* STEP 4: ACTION SELECTION */}
        {currentStep === Step.SELECT_ACTION && (
          <div className="flex flex-col gap-4 animate-fadeIn h-full">
            <button onClick={() => setCurrentStep(Step.SELECT_SITE)} className="text-slate-400 hover:text-white self-start text-sm font-medium transition">
              ← Cambiar Obra
            </button>

            <div className="bg-slate-900 p-5 rounded-2xl border border-slate-800 mb-4 shadow-lg">
              <div className="flex items-center gap-2 mb-3">
                 <div className="bg-slate-800 p-1.5 rounded text-blue-500"><Briefcase size={14}/></div>
                 <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Ubicación Actual</p>
              </div>
              <div className="flex justify-between items-end">
                <div>
                  <p className="text-white font-bold text-lg leading-tight">{selectedSite?.name}</p>
                  <p className="text-slate-500 text-xs mt-1">{selectedWorker?.name}</p>
                </div>
                {location && <div className="bg-emerald-950/30 text-emerald-500 px-2 py-1 rounded text-[10px] font-bold border border-emerald-900/30 flex items-center gap-1"><MapPin size={10}/> GPS ACTIVO</div>}
              </div>
            </div>

            {loading ? (
               <div className="flex-1 flex flex-col justify-center items-center text-white">
                 <div className="w-16 h-16 border-4 border-blue-500 border-t-transparent rounded-full animate-spin mb-6"></div>
                 <p className="text-sm font-medium tracking-wide animate-pulse">Confirmando Ubicación...</p>
               </div>
            ) : (
              <div className="grid grid-cols-1 gap-4 flex-1 content-center">
                <button
                  onClick={() => handleActionSelect(LogType.ENTRADA)}
                  className="group bg-emerald-600 hover:bg-emerald-500 text-white p-6 rounded-2xl shadow-lg transform active:scale-[0.98] transition-all flex items-center justify-between overflow-hidden relative"
                >
                  <div className="absolute inset-0 bg-gradient-to-r from-white/0 via-white/5 to-white/0 translate-x-[-100%] group-hover:translate-x-[100%] transition-transform duration-1000"></div>
                  <div className="text-left relative z-10">
                    <span className="block text-2xl font-black tracking-tight">ENTRADA</span>
                    <span className="text-emerald-100 text-xs font-medium uppercase tracking-wide">Iniciar jornada</span>
                  </div>
                  <div className="bg-emerald-700/50 p-3 rounded-xl relative z-10">
                    <LogOut className="rotate-180" size={32} />
                  </div>
                </button>

                <div className="grid grid-cols-2 gap-4">
                  <button
                    onClick={() => handleActionSelect(LogType.INICIO_DESCANSO)}
                    className="bg-amber-600 hover:bg-amber-500 text-white p-5 rounded-2xl shadow-lg transform active:scale-[0.98] transition-all flex flex-col justify-between h-32"
                  >
                    <div className="bg-amber-700/50 self-start p-2 rounded-lg"><Coffee size={24} /></div>
                    <span className="font-bold text-left leading-tight text-sm">INICIO<br/>DESCANSO</span>
                  </button>
                  <button
                    onClick={() => handleActionSelect(LogType.FIN_DESCANSO)}
                    className="bg-blue-600 hover:bg-blue-500 text-white p-5 rounded-2xl shadow-lg transform active:scale-[0.98] transition-all flex flex-col justify-between h-32"
                  >
                    <div className="bg-blue-700/50 self-start p-2 rounded-lg relative">
                      <Coffee size={24} />
                      <div className="absolute -bottom-1 -right-1 bg-white text-blue-600 rounded-full p-0.5"><LogOut size={10}/></div>
                    </div>
                    <span className="font-bold text-left leading-tight text-sm">FIN<br/>DESCANSO</span>
                  </button>
                </div>

                <button
                  onClick={() => handleActionSelect(LogType.SALIDA)}
                  className="group bg-rose-600 hover:bg-rose-500 text-white p-6 rounded-2xl shadow-lg transform active:scale-[0.98] transition-all flex items-center justify-between"
                >
                  <div className="text-left">
                    <span className="block text-2xl font-black tracking-tight">SALIDA</span>
                    <span className="text-rose-200 text-xs font-medium uppercase tracking-wide">Terminar jornada</span>
                  </div>
                  <div className="bg-rose-700/50 p-3 rounded-xl">
                    <LogOut size={32} />
                  </div>
                </button>
              </div>
            )}
          </div>
        )}

        {/* STEP 4.5: EXIT REPORT */}
        {currentStep === Step.REPORT_EXIT && (
           <div className="flex flex-col gap-6 animate-fadeIn h-full">
             <button onClick={() => setCurrentStep(Step.SELECT_ACTION)} className="text-slate-400 text-sm hover:text-white self-start flex items-center gap-1">
               <ChevronLeft size={16} /> Volver
             </button>

             <div className="text-center">
               <h2 className="text-2xl font-bold text-white mb-2">Resumen de Jornada</h2>
               <p className="text-slate-400 text-sm">Completa la información antes de salir.</p>
             </div>

             {/* Mode Selector */}
             <div className="bg-slate-900 p-4 rounded-xl border border-slate-800">
               <label className="block text-[10px] uppercase text-slate-500 font-bold mb-3 tracking-wider">Modo de Trabajo</label>
               <div className="flex gap-2">
                 <button 
                   onClick={() => setExitWorkMode('HORAS')}
                   className={`flex-1 py-3 px-2 rounded-lg font-bold text-sm transition border-2 ${
                     exitWorkMode === 'HORAS' 
                       ? 'bg-blue-600 border-blue-400 text-white' 
                       : 'bg-slate-950 border-slate-800 text-slate-500 hover:text-slate-300'
                   }`}
                 >
                   ⏱️ Por Horas
                 </button>
                 <button 
                   onClick={() => setExitWorkMode('DESTAJO')}
                   className={`flex-1 py-3 px-2 rounded-lg font-bold text-sm transition border-2 ${
                     exitWorkMode === 'DESTAJO' 
                       ? 'bg-purple-600 border-purple-400 text-white' 
                       : 'bg-slate-950 border-slate-800 text-slate-500 hover:text-slate-300'
                   }`}
                 >
                   🧱 A Destajo
                 </button>
               </div>
             </div>

             {/* Report Input */}
             <div className="flex-1 bg-slate-900 p-4 rounded-xl border border-slate-800 flex flex-col shadow-inner">
                <div className="flex justify-between items-center mb-3">
                  <label className="text-[10px] uppercase text-slate-500 font-bold flex items-center gap-2 tracking-wider">
                    <FileText size={14}/> Parte de Trabajo
                  </label>
                  <button 
                    onClick={toggleVoiceRecognition}
                    className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-[10px] font-bold uppercase tracking-wider transition ${
                       isListening ? 'bg-rose-500 text-white animate-pulse' : 'bg-slate-800 text-slate-400 hover:text-white'
                    }`}
                  >
                    {isListening ? <><MicOff size={12}/> Detener</> : <><Mic size={12}/> Dictar voz</>}
                  </button>
                </div>

                <textarea 
                  value={exitReportText}
                  onChange={(e) => setExitReportText(e.target.value)}
                  placeholder={isListening ? "Escuchando..." : "Escribe o dicta qué has hecho hoy..."}
                  className="w-full flex-1 bg-slate-950 text-white p-4 rounded-lg border border-slate-800 focus:border-blue-500 focus:outline-none resize-none leading-relaxed text-sm"
                />
             </div>

             <button 
               onClick={() => executeLogSubmission(LogType.SALIDA, exitReportText, exitWorkMode)}
               className="bg-emerald-600 hover:bg-emerald-500 text-white p-4 rounded-xl flex items-center justify-center gap-3 shadow-lg font-bold text-lg uppercase tracking-wide transition-colors"
             >
               <Save size={20} /> Guardar y Salir
             </button>
           </div>
        )}

        {/* STEP 5: SUCCESS */}
        {currentStep === Step.SUCCESS && (
          <div className="flex-1 flex flex-col items-center justify-center text-center animate-fadeIn p-6">
            <div className="bg-emerald-500 rounded-full p-6 text-slate-950 mb-6 shadow-2xl shadow-emerald-500/20">
              <CheckCircle size={64} />
            </div>
            <h2 className="text-3xl font-black text-white mb-2 tracking-tight">¡Registrado!</h2>
            <p className="text-slate-400 mb-8 max-w-xs mx-auto text-sm">
              Tu fichaje se ha guardado correctamente.
            </p>

            <div className="w-full bg-slate-900 rounded-2xl p-6 mb-8 text-left border border-slate-800 shadow-xl">
               <div className="flex justify-between mb-3 border-b border-slate-800 pb-3">
                 <span className="text-slate-500 text-xs uppercase font-bold tracking-wider">Trabajador</span>
                 <span className="text-white font-bold text-sm">{selectedWorker?.name}</span>
               </div>
               <div className="flex justify-between mb-3 border-b border-slate-800 pb-3">
                 <span className="text-slate-500 text-xs uppercase font-bold tracking-wider">Acción</span>
                 <span className={`font-bold text-sm ${
                    selectedAction === LogType.ENTRADA ? 'text-emerald-400' : 
                    selectedAction === LogType.SALIDA ? 'text-rose-400' : 'text-amber-400'
                 }`}>{selectedAction}</span>
               </div>
               <div className="flex justify-between items-center">
                 <span className="text-slate-500 text-xs uppercase font-bold tracking-wider">Estado</span>
                 <span className="text-blue-400 font-bold flex items-center gap-1.5 text-[10px] bg-blue-950/30 px-2 py-1 rounded border border-blue-900/30 uppercase tracking-wide">
                   <Cloud size={12} /> Sincronizado
                 </span>
               </div>
            </div>

            <button 
              onClick={resetApp}
              className="w-full bg-blue-600 hover:bg-blue-500 text-white font-bold py-4 rounded-xl shadow-lg transition uppercase tracking-widest text-sm"
            >
              Finalizar
            </button>
          </div>
        )}
      </main>

      <footer className="p-4 text-center text-slate-600 text-[10px] font-medium tracking-wider uppercase">
        &copy; 2024 CARMAGNE INSTAL. V1.5.0
      </footer>
    </div>
  );
}

export default App;
