                  </div>
                  <button onClick={() => initiateDeleteWorker(w)} className="text-slate-400 hover:text-rose-500 p-2 hover:bg-rose-50 rounded-lg transition"><Trash2 size={20} /></button>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* REPORTS TAB */}
