        {/* STEP 2: AUTHENTICATION */}
        {currentStep === Step.AUTHENTICATE && (
          <div className="flex flex-col gap-6 animate-fadeIn items-center justify-center flex-1">
             <button onClick={resetApp} className="text-slate-400 hover:text-white self-start absolute top-0 text-sm font-medium transition">
              ← Cambiar Usuario
            </button>

            <div className="text-center mb-6 mt-4">
