                  <div className="text-left relative z-10">
                    <span className="block text-2xl font-black tracking-tight">ENTRADA</span>
                    <span className="text-emerald-100 text-xs font-medium uppercase tracking-wide">Iniciar jornada</span>
                  </div>
                  <div className="bg-emerald-700/50 p-3 rounded-xl relative z-10">
                    <LogOut className="rotate-180" size={32} />
                  </div>
                </button>

                <div className="grid grid-cols-2 gap-4">
                  <button
                    onClick={() => handleActionSelect(LogType.INICIO_DESCANSO)}
                    className="bg-amber-600 hover:bg-amber-500 text-white p-5 rounded-2xl shadow-lg transform active:scale-[0.98] transition-all flex flex-col justify-between h-32"
                  >
                    <div className="bg-amber-700/50 self-start p-2 rounded-lg"><Coffee size={24} /></div>
                    <span className="font-bold text-left leading-tight text-sm">INICIO<br/>DESCANSO</span>
                  </button>
                  <button
                    onClick={() => handleActionSelect(LogType.FIN_DESCANSO)}
                    className="bg-blue-600 hover:bg-blue-500 text-white p-5 rounded-2xl shadow-lg transform active:scale-[0.98] transition-all flex flex-col justify-between h-32"
                  >
                    <div className="bg-blue-700/50 self-start p-2 rounded-lg relative">
                      <Coffee size={24} />
                      <div className="absolute -bottom-1 -right-1 bg-white text-blue-600 rounded-full p-0.5"><LogOut size={10}/></div>
                    </div>
                    <span className="font-bold text-left leading-tight text-sm">FIN<br/>DESCANSO</span>
                  </button>
                </div>

                <button
                  onClick={() => handleActionSelect(LogType.SALIDA)}
                  className="group bg-rose-600 hover:bg-rose-500 text-white p-6 rounded-2xl shadow-lg transform active:scale-[0.98] transition-all flex items-center justify-between"
                >
                  <div className="text-left">
                    <span className="block text-2xl font-black tracking-tight">SALIDA</span>
                    <span className="text-rose-200 text-xs font-medium uppercase tracking-wide">Terminar jornada</span>
                  </div>
                  <div className="bg-rose-700/50 p-3 rounded-xl">
                    <LogOut size={32} />
                  </div>
                </button>
              </div>
            )}
          </div>
        )}

        {/* STEP 4.5: EXIT REPORT */}
        {currentStep === Step.REPORT_EXIT && (
           <div className="flex flex-col gap-6 animate-fadeIn h-full">
             <button onClick={() => setCurrentStep(Step.SELECT_ACTION)} className="text-slate-400 text-sm hover:text-white self-start flex items-center gap-1">
               <ChevronLeft size={16} /> Volver
             </button>

             <div className="text-center">
               <h2 className="text-2xl font-bold text-white mb-2">Resumen de Jornada</h2>
               <p className="text-slate-400 text-sm">Completa la información antes de salir.</p>
             </div>

             {/* Mode Selector */}
             <div className="bg-slate-900 p-4 rounded-xl border border-slate-800">
               <label className="block text-[10px] uppercase text-slate-500 font-bold mb-3 tracking-wider">Modo de Trabajo</label>
               <div className="flex gap-2">
                 <button 
                   onClick={() => setExitWorkMode('HORAS')}
                   className={`flex-1 py-3 px-2 rounded-lg font-bold text-sm transition border-2 ${
                     exitWorkMode === 'HORAS' 
                       ? 'bg-blue-600 border-blue-400 text-white' 
                       : 'bg-slate-950 border-slate-800 text-slate-500 hover:text-slate-300'
                   }`}
                 >
                   ⏱️ Por Horas
                 </button>
                 <button 
                   onClick={() => setExitWorkMode('DESTAJO')}
                   className={`flex-1 py-3 px-2 rounded-lg font-bold text-sm transition border-2 ${
                     exitWorkMode === 'DESTAJO' 
                       ? 'bg-purple-600 border-purple-400 text-white' 
                       : 'bg-slate-950 border-slate-800 text-slate-500 hover:text-slate-300'
                   }`}
                 >
                   🧱 A Destajo
                 </button>
               </div>
             </div>

             {/* Report Input */}
             <div className="flex-1 bg-slate-900 p-4 rounded-xl border border-slate-800 flex flex-col shadow-inner">
                <div className="flex justify-between items-center mb-3">
                  <label className="text-[10px] uppercase text-slate-500 font-bold flex items-center gap-2 tracking-wider">
                    <FileText size={14}/> Parte de Trabajo
                  </label>
                  <button 
                    onClick={toggleVoiceRecognition}
                    className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-[10px] font-bold uppercase tracking-wider transition ${
                       isListening ? 'bg-rose-500 text-white animate-pulse' : 'bg-slate-800 text-slate-400 hover:text-white'
                    }`}
                  >
                    {isListening ? <><MicOff size={12}/> Detener</> : <><Mic size={12}/> Dictar voz</>}
                  </button>
                </div>

                <textarea 
                  value={exitReportText}
                  onChange={(e) => setExitReportText(e.target.value)}
                  placeholder={isListening ? "Escuchando..." : "Escribe o dicta qué has hecho hoy..."}
                  className="w-full flex-1 bg-slate-950 text-white p-4 rounded-lg border border-slate-800 focus:border-blue-500 focus:outline-none resize-none leading-relaxed text-sm"
                />
             </div>

             <button 
               onClick={() => executeLogSubmission(LogType.SALIDA, exitReportText, exitWorkMode)}
               className="bg-emerald-600 hover:bg-emerald-500 text-white p-4 rounded-xl flex items-center justify-center gap-3 shadow-lg font-bold text-lg uppercase tracking-wide transition-colors"
             >
               <Save size={20} /> Guardar y Salir
             </button>
           </div>
        )}

        {/* STEP 5: SUCCESS */}
        {currentStep === Step.SUCCESS && (
          <div className="flex-1 flex flex-col items-center justify-center text-center animate-fadeIn p-6">
            <div className="bg-emerald-500 rounded-full p-6 text-slate-950 mb-6 shadow-2xl shadow-emerald-500/20">
              <CheckCircle size={64} />
            </div>
            <h2 className="text-3xl font-black text-white mb-2 tracking-tight">¡Registrado!</h2>
            <p className="text-slate-400 mb-8 max-w-xs mx-auto text-sm">
              Tu fichaje se ha guardado correctamente.
            </p>

            <div className="w-full bg-slate-900 rounded-2xl p-6 mb-8 text-left border border-slate-800 shadow-xl">
               <div className="flex justify-between mb-3 border-b border-slate-800 pb-3">
                 <span className="text-slate-500 text-xs uppercase font-bold tracking-wider">Trabajador</span>
                 <span className="text-white font-bold text-sm">{selectedWorker?.name}</span>
               </div>
               <div className="flex justify-between mb-3 border-b border-slate-800 pb-3">
                 <span className="text-slate-500 text-xs uppercase font-bold tracking-wider">Acción</span>
                 <span className={`font-bold text-sm ${
                    selectedAction === LogType.ENTRADA ? 'text-emerald-400' : 
                    selectedAction === LogType.SALIDA ? 'text-rose-400' : 'text-amber-400'
                 }`}>{selectedAction}</span>
               </div>
               <div className="flex justify-between items-center">
                 <span className="text-slate-500 text-xs uppercase font-bold tracking-wider">Estado</span>
                 <span className="text-blue-400 font-bold flex items-center gap-1.5 text-[10px] bg-blue-950/30 px-2 py-1 rounded border border-blue-900/30 uppercase tracking-wide">
                   <Cloud size={12} /> Sincronizado
                 </span>
               </div>
            </div>

            <button 
              onClick={resetApp}
              className="w-full bg-blue-600 hover:bg-blue-500 text-white font-bold py-4 rounded-xl shadow-lg transition uppercase tracking-widest text-sm"
            >
              Finalizar
            </button>
          </div>
        )}
      </main>

      <footer className="p-4 text-center text-slate-600 text-[10px] font-medium tracking-wider uppercase">
        &copy; 2024 CARMAGNE INSTAL. V1.6.0
      </footer>
    </div>
  );
}

export default App;
