      setLoading(false);
      setSelectedWorker(newWorker);
      setPinInput('');
      setCurrentStep(Step.AUTHENTICATE);
      setRegName(''); setRegDni(''); setRegPhone(''); setRegRole(''); setRegPin(''); setRegPinConfirm('');
    } catch (err: any) {
      console.error("Fallo registro:", err);
      setLoading(false);
      setError('Error guardando en la nube. Verifica tu conexión.');
      alert("⚠️ Error: No se pudo guardar el usuario en la base de datos.");
    }
  };

  const handlePinInput = (digit: string) => {
    if (pinInput.length < 4) {
      const newPin = pinInput + digit;
      setPinInput(newPin);
      if (newPin.length === 4) {
        verifyAuth(newPin);
      }
    }
  };

  const handlePinClear = () => {
    setPinInput('');
    setError('');
  };

  const verifyAuth = (pinToVerify: string) => {
    if (selectedWorker && selectedWorker.pin === pinToVerify) {
      setCurrentStep(Step.WORKER_DASHBOARD);
      setError('');
    } else {
      setError('PIN Incorrecto');
      setTimeout(() => setPinInput(''), 500);
    }
  };

  const handleBiometricAuth = async () => {
    try {
      setError('');
      const publicKeyCredentialCreationOptions: PublicKeyCredentialCreationOptions = {
        challenge: Uint8Array.from("RANDOM_CHALLENGE_STRING", c => c.charCodeAt(0)),
        rp: { name: "CARMAGNE SOLU", id: window.location.hostname },
        user: {
            id: Uint8Array.from("USER_ID", c => c.charCodeAt(0)),
            name: selectedWorker?.name || "worker",
            displayName: selectedWorker?.name || "Worker",
        },
        pubKeyCredParams: [{alg: -7, type: "public-key"}],
        authenticatorSelection: { authenticatorAttachment: "platform", userVerification: "required" },
        timeout: 60000,
        attestation: "direct"
      };

      await navigator.credentials.create({ publicKey: publicKeyCredentialCreationOptions });
      setCurrentStep(Step.WORKER_DASHBOARD); 

    } catch (err) {
      console.error(err);
      setError('Autenticación biométrica fallida o cancelada.');
    }
  };

  const handleSiteSelect = (siteId: string) => {
    const site = sites.find(s => s.id === siteId);
    if (site) {
      setSelectedSite(site);
      setCurrentStep(Step.SELECT_ACTION);
      LocationService.getCurrentPosition()
        .then(loc => setLocation(loc))
        .catch(err => console.warn("Background loc failed", err));
    }
  };

  const handleActionSelect = async (type: LogType) => {
    setSelectedAction(type);
    setLoading(true);
    setError('');

    let loc = location;
    try {
      if (!loc) {
        loc = await LocationService.getCurrentPosition();
        setLocation(loc);
      }
    } catch (err) { }
    setLoading(false);

    if (type === LogType.SALIDA) {
      setExitWorkMode(selectedWorker?.defaultMode || 'HORAS');
      setExitReportText('');
      setCurrentStep(Step.REPORT_EXIT);
    } else {
      executeLogSubmission(type, undefined, 'HORAS');
    }
  };

  const toggleVoiceRecognition = () => {
    if (isListening) {
      setIsListening(false);
      return;
    }

    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) {
      alert("Tu navegador no soporta reconocimiento de voz. Usa Chrome o Safari.");
      return;
    }

    const recognition = new SpeechRecognition();
    recognition.lang = 'es-ES';
    recognition.continuous = false;
    recognition.interimResults = false;

    setIsListening(true);

    recognition.onresult = (event: any) => {
      const transcript = event.results[0][0].transcript;
      setExitReportText(prev => (prev ? prev + '. ' + transcript : transcript));
      setIsListening(false);
    };

    recognition.onerror = (event: any) => {
      console.error(event.error);
      setIsListening(false);
    };

    recognition.onend = () => {
      setIsListening(false);
    };

    recognition.start();
  };

  const executeLogSubmission = async (type: LogType, report?: string, mode?: WorkMode) => {
    setLoading(true);
    try {
      let loc = location;
      if (!loc) {
        loc = await LocationService.getCurrentPosition();
        setLocation(loc);
      }

      let distance = 0;
      let warning = false;

      if (selectedSite && selectedSite.coordinates) {
        distance = LocationService.calculateDistance(
          loc!.latitude,
          loc!.longitude,
          selectedSite.coordinates.latitude,
          selectedSite.coordinates.longitude
        );

        if (distance > MAX_DISTANCE_METERS) {
          warning = true;
        }
      }

      await submitLog(loc!, type, distance, warning, undefined, report, mode);

    } catch (err: any) {
      setLoading(false);
      setError('Error obteniendo ubicación GPS. Active el GPS y reintente.');
    }
  };

  const submitLog = async (
    loc: GeoLocationData, 
    type: LogType, 
    distance: number, 
    warning: boolean, 
    photoUrl?: string,
    report?: string,
    mode?: WorkMode
  ) => {
    if (!selectedWorker || !selectedSite) return;

    setLoading(true);
    const now = new Date();

    const newLog: WorkLog = {
      id: `LOG-${Date.now()}`,
      workerId: selectedWorker.id,
      workerName: selectedWorker.name,
      siteId: selectedSite.id,
      siteName: selectedSite.name,
      type: type,
      timestamp: now.getTime(),
      dateStr: now.toLocaleDateString('es-ES'),
      timeStr: now.toLocaleTimeString('es-ES'),
      location: loc,
      photoUrl: photoUrl,
      sentToWhatsapp: false,
      syncedToSheets: false,
      distanceMeters: distance,
      locationWarning: warning,
      workReport: report,
      workMode: mode
    };

    StorageService.addLog(newLog);

    StorageService.syncLog(newLog).then(success => {
      if (success) {
        newLog.syncedToSheets = true;
        StorageService.updateLog(newLog);
      }
    });

    setCurrentStep(Step.SUCCESS);
    setLoading(false);
  };

  const resetApp = () => {
    setCurrentStep(Step.IDENTIFY);
    setSelectedWorker(null);
    setSelectedSite(null);
    setSelectedAction(null);
    setLocation(null);
    setPinInput('');
  };

  // --- RENDERERS ---

  const renderWorkerDashboard = () => {
    const status = getCurrentStatus();
    return (
      <div className="flex flex-col gap-6 animate-fadeIn h-full">
        <div className="flex justify-between items-center px-2">
          <span className="text-xl font-bold text-white tracking-tight">{selectedWorker?.name}</span>
          <button onClick={resetApp} className="text-slate-400 hover:text-white transition p-2 bg-slate-800 rounded-full border border-slate-700">
            <LogOut size={18} />
          </button>
        </div>

        {/* ELEGANT STATUS CARD */}
        <div className={`relative overflow-hidden rounded-2xl p-6 shadow-xl border border-slate-700/50 ${
          status?.status === 'TRABAJANDO' ? 'bg-gradient-to-br from-slate-900 to-emerald-950/30' :
          status?.status === 'EN DESCANSO' ? 'bg-gradient-to-br from-slate-900 to-amber-950/30' :
          'bg-gradient-to-br from-slate-900 to-slate-800'
        }`}>
          <div className="relative z-10 flex flex-col items-center text-center">
            <div className={`text-[10px] font-bold tracking-[0.2em] uppercase mb-2 ${
               status?.status === 'TRABAJANDO' ? 'text-emerald-400' :
               status?.status === 'EN DESCANSO' ? 'text-amber-400' :
               'text-slate-500'
            }`}>Estado Actual</div>

            <h2 className="text-3xl font-black text-white mb-2 tracking-tight">
              {status?.status || 'SIN ACTIVIDAD'}
            </h2>

            {status?.status !== 'FUERA' && (
              <div className="mt-2 space-y-1">
                <p className="text-slate-300 font-medium">{status?.site}</p>
                <div className="flex items-center justify-center gap-2 text-xs text-slate-400 bg-slate-950/50 px-3 py-1 rounded-full border border-slate-700">
                  <Clock size={12}/> 
                  <span>Desde: {new Date(status?.since || 0).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
                </div>
              </div>
            )}
          </div>
        </div>

        <h3 className="text-slate-400 text-sm font-bold uppercase tracking-wider px-2 mt-2">Acciones Rápidas</h3>

        <div className="grid grid-cols-1 gap-4 flex-1">
           <button 
             onClick={() => setCurrentStep(Step.SELECT_SITE)}
             className="group bg-slate-800 hover:bg-slate-700 border border-slate-700 hover:border-blue-500/50 transition-all p-6 rounded-2xl shadow-lg flex items-center justify-between"
           >
             <div className="text-left">
               <span className="block text-xl font-bold text-white group-hover:text-blue-400 transition-colors">Nuevo Fichaje</span>
               <span className="text-slate-400 text-sm">Entrada, Salida o Pausa</span>
             </div>
             <div className="bg-slate-900 p-3 rounded-full text-blue-500 group-hover:scale-110 transition-transform duration-300 shadow-inner">
               <Clock size={24} />
             </div>
           </button>

           <button 
             onClick={() => setCurrentStep(Step.WORKER_HISTORY)}
             className="group bg-slate-800 hover:bg-slate-700 border border-slate-700 hover:border-purple-500/50 transition-all p-6 rounded-2xl shadow-lg flex items-center justify-between"
           >
             <div className="text-left">
               <span className="block text-xl font-bold text-white group-hover:text-purple-400 transition-colors">Mi Historial</span>
               <span className="text-slate-400 text-sm">Ver mis horas y actividad</span>
             </div>
             <div className="bg-slate-900 p-3 rounded-full text-purple-500 group-hover:scale-110 transition-transform duration-300 shadow-inner">
               <History size={24} />
             </div>
           </button>
        </div>
      </div>
    );
  };

  // --- SPLASH SCREEN ---
  if (isAppLoading) {
    return (
      <div className="fixed inset-0 bg-slate-950 z-[100] flex flex-col items-center justify-center animate-fadeIn">
         <div className="flex flex-col items-center">
            <h1 className="text-4xl font-black text-white tracking-tighter mb-2">CARMAGNE</h1>
            <div className="h-1 w-24 bg-blue-600 rounded-full mb-3"></div>
            <p className="text-blue-500 font-bold tracking-[0.4em] text-sm">INSTAL 2024</p>
         </div>
      </div>
    );
  }

  // Render Admin
  if (isAdmin) {
    return <AdminPanel onBack={() => setIsAdmin(false)} />;
  }

  // (The rest of the JSX structure remains similar but with new color classes applied below)
  // ...
  // Full JSX return with updated colors:
  return (
    <div className="min-h-screen bg-slate-950 flex flex-col font-sans selection:bg-blue-500/30">
      {/* Install Tutorial Modal */}
      {showInstallGuide && <InstallTutorial onClose={() => setShowInstallGuide(false)} />}

      {/* Admin Login Modal */}
      {showAdminLogin && (
        <div className="fixed inset-0 z-50 bg-slate-950/90 backdrop-blur-md flex items-center justify-center p-4 animate-fadeIn">
           <div className="bg-slate-900 w-full max-w-sm rounded-2xl border border-slate-800 shadow-2xl p-8 relative">
              <button onClick={() => setShowAdminLogin(false)} className="absolute top-4 right-4 text-slate-500 hover:text-white transition">
                 <X size={20} />
              </button>

              <div className="flex flex-col items-center mb-8">
                 <h2 className="text-xl font-bold text-white uppercase tracking-wider mb-2">Acceso Seguro</h2>
                 <div className="h-1 w-12 bg-blue-600 rounded-full"></div>
              </div>

              <input 
                 type="password"
                 value={adminPasswordInput}
                 onChange={(e) => setAdminPasswordInput(e.target.value)}
                 className="w-full bg-slate-950 border border-slate-800 rounded-xl p-4 text-white text-center font-bold tracking-[0.5em] text-xl mb-6 focus:border-blue-500 focus:outline-none transition-colors"
                 placeholder="Contraseña"
                 autoFocus
              />

              {adminError && <div className="text-rose-500 text-xs font-bold text-center mb-6">{adminError}</div>}

              <button 
                 onClick={verifyAdminPassword}
                 className="w-full bg-blue-600 hover:bg-blue-500 text-white font-bold py-4 rounded-xl transition shadow-lg uppercase tracking-widest text-sm"
              >
                 ENTRAR
              </button>
           </div>
        </div>
      )}

      {/* Header */}
      <header className="glass p-4 flex justify-between items-center sticky top-0 z-20">
        <div>
          <h1 className="text-xl font-black tracking-tight leading-none text-white">CARMAGNE</h1>
          <p className="text-[10px] font-bold text-blue-500 tracking-[0.2em] uppercase mt-0.5">INSTAL 2024</p>
        </div>
        <button 
          onClick={handleAdminAccessRequest} 
          className="p-2.5 bg-slate-800 text-slate-400 rounded-full hover:bg-slate-700 hover:text-blue-400 transition-all border border-slate-700/50"
        >
          <Lock size={16} />
        </button>
      </header>

      {/* Main Content Area */}
      <main className="flex-1 flex flex-col p-4 max-w-md mx-auto w-full relative">
        {/* Error Alert */}
        {error && (
          <div className="mb-6 p-4 bg-rose-950/80 border border-rose-900 text-rose-200 rounded-xl flex items-center gap-3 animate-bounce z-50 shadow-lg">
            <ShieldAlert size={20} />
            <span className="text-xs font-bold">{error}</span>
          </div>
        )}

        {/* STEP 1: IDENTIFICATION */}
        {currentStep === Step.IDENTIFY && (
          <div className="flex flex-col gap-6 animate-fadeIn">
            <button 
              onClick={() => setShowInstallGuide(true)}
              className="mx-auto text-[10px] uppercase font-bold tracking-wider bg-slate-900 text-blue-400 px-4 py-1.5 rounded-full border border-blue-900/30 flex items-center gap-2 hover:bg-slate-800 transition"
            >
              <Smartphone size={12} /> Instalar App
            </button>

            <div className="text-center py-4">
              <h2 className="text-2xl font-bold text-white mb-2 tracking-tight">Bienvenido</h2>
              <p className="text-slate-400 text-sm">Identifícate para comenzar.</p>
            </div>

            <button 
              onClick={() => setCurrentStep(Step.REGISTER)}
              className="group bg-slate-800 hover:bg-slate-700 border border-slate-700 hover:border-blue-500/50 text-white p-5 rounded-2xl flex items-center justify-center gap-3 shadow-lg transform active:scale-[0.98] transition-all"
            >
              <div className="bg-blue-600/20 p-2 rounded-lg group-hover:bg-blue-600/30 transition">
                 <UserPlus size={20} className="text-blue-400" />
              </div>
              <span className="font-bold text-base">Registrar Nuevo Personal</span>
            </button>

            <div className="relative my-4">
              <div className="absolute inset-0 flex items-center">
                <div className="w-full border-t border-slate-800"></div>
              </div>
              <div className="relative flex justify-center text-[10px] uppercase font-bold tracking-widest">
                <span className="px-3 bg-slate-950 text-slate-500">Personal Registrado</span>
              </div>
            </div>

            <div className="grid gap-3 max-h-[55vh] overflow-y-auto custom-scrollbar pr-1">
              {workers.filter(w => w.active).map(worker => (
                <button
                  key={worker.id}
                  onClick={() => handleManualSelect(worker.id)}
                  className="bg-slate-900 hover:bg-slate-800 p-4 rounded-xl flex items-center justify-between border border-slate-800 hover:border-blue-500/30 transition group"
                >
                  <div className="flex items-center gap-4">
                    <div className="bg-slate-800 p-2.5 rounded-full text-slate-400 group-hover:text-blue-400 transition-colors">
                      <User size={18} />
                    </div>
                    <div className="text-left">
                      <p className="font-bold text-white group-hover:text-blue-400 transition text-sm">{worker.name}</p>
                      <p className="text-[10px] font-mono text-slate-500 uppercase">ID: {worker.id}</p>
                    </div>
                  </div>
                  <ArrowRight size={16} className="text-slate-700 group-hover:text-blue-500 transition-transform group-hover:translate-x-1" />
                </button>
              ))}
            </div>
          </div>
        )}

        {/* STEP: REGISTRATION */}
        {currentStep === Step.REGISTER && (
          <div className="flex flex-col gap-6 animate-fadeIn">
            <button onClick={() => {setCurrentStep(Step.IDENTIFY); setError('');}} className="text-slate-400 hover:text-white self-start flex items-center gap-1 text-sm font-medium transition">
              <ChevronLeft size={16} /> Cancelar
            </button>
            <div className="text-center">
              <h2 className="text-xl font-bold text-white mb-1">Nueva Ficha</h2>
              <p className="text-slate-400 text-xs">Completa los datos personales.</p>
            </div>
            {/* Form simplified for brevity, same logic but dark slate styling */}
            <div className="flex flex-col gap-4 bg-slate-900 p-6 rounded-2xl border border-slate-800 shadow-xl">
               <div>
                 <label className="block text-[10px] uppercase text-slate-500 font-bold mb-1.5 tracking-wider">Nombre Completo *</label>
                 <input type="text" value={regName} onChange={(e) => setRegName(e.target.value)} className="w-full bg-slate-950 border border-slate-800 text-white rounded-lg p-3.5 focus:border-blue-500 outline-none transition-colors text-sm"/>
               </div>
               <div className="grid grid-cols-2 gap-4">
                 <div>
                   <label className="block text-[10px] uppercase text-slate-500 font-bold mb-1.5 tracking-wider">DNI/NIE *</label>
                   <input type="text" value={regDni} onChange={(e) => setRegDni(e.target.value)} className="w-full bg-slate-950 border border-slate-800 text-white rounded-lg p-3.5 focus:border-blue-500 outline-none transition-colors text-sm"/>
                 </div>
                 <div>
                   <label className="block text-[10px] uppercase text-slate-500 font-bold mb-1.5 tracking-wider">Teléfono</label>
                   <input type="tel" value={regPhone} onChange={(e) => setRegPhone(e.target.value)} className="w-full bg-slate-950 border border-slate-800 text-white rounded-lg p-3.5 focus:border-blue-500 outline-none transition-colors text-sm"/>
                 </div>
               </div>
               <div>
                 <label className="block text-[10px] uppercase text-slate-500 font-bold mb-1.5 tracking-wider">Cargo</label>
                 <input type="text" value={regRole} onChange={(e) => setRegRole(e.target.value)} className="w-full bg-slate-950 border border-slate-800 text-white rounded-lg p-3.5 focus:border-blue-500 outline-none transition-colors text-sm"/>
               </div>
               <div className="border-t border-slate-800 my-2 pt-4">
                  <div className="flex items-center gap-2 mb-4 text-blue-500">
                     <Lock size={14} />
                     <span className="font-bold text-xs uppercase tracking-wide">Seguridad (PIN)</span>
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                     <input type="password" value={regPin} onChange={(e) => setRegPin(e.target.value.replace(/\D/g,'').slice(0,4))} className="w-full bg-slate-950 border border-slate-800 text-white rounded-lg p-3.5 text-center tracking-widest text-lg focus:border-blue-500 outline-none" placeholder="PIN"/>
                     <input type="password" value={regPinConfirm} onChange={(e) => setRegPinConfirm(e.target.value.replace(/\D/g,'').slice(0,4))} className="w-full bg-slate-950 border border-slate-800 text-white rounded-lg p-3.5 text-center tracking-widest text-lg focus:border-blue-500 outline-none" placeholder="Repetir"/>
                  </div>
               </div>
            </div>
            <button onClick={handleRegistration} className="bg-emerald-600 hover:bg-emerald-500 text-white p-4 rounded-xl flex items-center justify-center gap-2 shadow-lg font-bold text-sm uppercase tracking-wide mt-2 transition-colors">{loading ? 'Guardando...' : <><Save size={18} /> Crear Ficha</>}</button>
          </div>
        )}

        {/* STEP 2: AUTHENTICATION */}
        {currentStep === Step.AUTHENTICATE && (
          <div className="flex flex-col gap-6 animate-fadeIn items-center justify-center flex-1">
             <button onClick={resetApp} className="text-slate-400 hover:text-white self-start absolute top-0 text-sm font-medium transition">← Cambiar Usuario</button>
            <div className="text-center mb-6 mt-4">
               <div className="w-24 h-24 bg-slate-900 rounded-full flex items-center justify-center mx-auto mb-6 border border-slate-800 shadow-2xl">
                 <Lock size={32} className="text-blue-500" />
               </div>
               <h2 className="text-2xl font-bold text-white mb-1">Hola, {selectedWorker?.name.split(' ')[0]}</h2>
               <p className="text-slate-400 text-sm">Introduce tu código de acceso</p>
            </div>
            <div className="flex gap-4 mb-8">
              {[0, 1, 2, 3].map(i => (
                <div key={i} className={`w-3 h-3 rounded-full transition-all duration-300 ${i < pinInput.length ? 'bg-blue-500 scale-125 shadow-glow' : 'bg-slate-800'}`}/>
              ))}
            </div>
            <div className="grid grid-cols-3 gap-4 w-full max-w-[280px]">
              {[1, 2, 3, 4, 5, 6, 7, 8, 9].map(num => (
                <button key={num} onClick={() => handlePinInput(num.toString())} className="h-16 rounded-2xl bg-slate-900 text-white text-xl font-bold hover:bg-slate-800 active:bg-blue-600 transition-all shadow-lg border border-slate-800">{num}</button>
              ))}
              <div className="flex items-center justify-center">
                {biometricsAvailable && (
                   <button onClick={handleBiometricAuth} className="h-14 w-14 rounded-full bg-slate-800 text-blue-400 flex items-center justify-center hover:bg-slate-700 transition shadow-lg border border-slate-700"><Fingerprint size={24} /></button>
                )}
              </div>
              <button onClick={() => handlePinInput('0')} className="h-16 rounded-2xl bg-slate-900 text-white text-xl font-bold hover:bg-slate-800 active:bg-blue-600 transition-all shadow-lg border border-slate-800">0</button>
              <button onClick={handlePinClear} className="h-16 flex items-center justify-center text-rose-500 hover:text-rose-400 transition"><Delete size={24} /></button>
            </div>
          </div>
        )}

        {/* WORKER DASHBOARD & HISTORY (Using Render Functions above) */}
        {currentStep === Step.WORKER_DASHBOARD && renderWorkerDashboard()}
        {currentStep === Step.WORKER_HISTORY && renderWorkerHistory()}

        {/* STEP 3: SITE SELECTION */}
        {currentStep === Step.SELECT_SITE && (
          <div className="flex flex-col gap-6 animate-fadeIn">
            <button onClick={() => setCurrentStep(Step.WORKER_DASHBOARD)} className="text-slate-400 hover:text-white self-start mb-2 flex items-center gap-1 text-sm font-medium transition"><ChevronLeft size={16} /> Volver</button>
            <div className="text-center pb-4">
               <div className="inline-flex items-center gap-2 bg-emerald-950/50 text-emerald-400 px-3 py-1.5 rounded-full text-[10px] font-bold uppercase tracking-widest border border-emerald-900/50 mb-3"><CheckCircle size={10} /> Identidad Verificada</div>
               <h2 className="text-2xl font-bold text-white">Selecciona Obra</h2>
            </div>
            <div className="grid gap-3">
              {sites.filter(s => s.active).map(site => (
                <button key={site.id} onClick={() => handleSiteSelect(site.id)} className="group bg-slate-900 hover:bg-slate-800 border border-slate-800 hover:border-blue-500/50 p-5 rounded-xl text-left transition-all relative overflow-hidden">
                  <div className="absolute top-0 right-0 p-4 opacity-5 group-hover:opacity-10 text-white transition-opacity"><MapPin size={64} /></div>
                  <h3 className="text-lg font-bold text-white mb-1 relative z-10">{site.name}</h3>
                  <p className="text-xs text-slate-400 flex items-center gap-2 relative z-10 font-medium"><MapPin size={12} className="text-blue-500" /> {site.address}</p>
                </button>
              ))}
            </div>
          </div>
        )}

        {/* STEP 4: ACTION SELECTION */}
        {currentStep === Step.SELECT_ACTION && (
          <div className="flex flex-col gap-4 animate-fadeIn h-full">
            <button onClick={() => setCurrentStep(Step.SELECT_SITE)} className="text-slate-400 hover:text-white self-start text-sm font-medium transition">← Cambiar Obra</button>
            <div className="bg-slate-900 p-5 rounded-2xl border border-slate-800 mb-4 shadow-lg">
              <div className="flex items-center gap-2 mb-3">
                 <div className="bg-slate-800 p-1.5 rounded text-blue-500"><Briefcase size={14}/></div>
                 <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Ubicación Actual</p>
              </div>
              <div className="flex justify-between items-end">
                <div><p className="text-white font-bold text-lg leading-tight">{selectedSite?.name}</p><p className="text-slate-500 text-xs mt-1">{selectedWorker?.name}</p></div>
                {location && <div className="bg-emerald-950/30 text-emerald-500 px-2 py-1 rounded text-[10px] font-bold border border-emerald-900/30 flex items-center gap-1"><MapPin size={10}/> GPS ACTIVO</div>}
              </div>
            </div>
            {loading ? (
               <div className="flex-1 flex flex-col justify-center items-center text-white">
                 <div className="w-16 h-16 border-4 border-blue-500 border-t-transparent rounded-full animate-spin mb-6"></div>
                 <p className="text-sm font-medium tracking-wide animate-pulse">Confirmando Ubicación...</p>
               </div>
            ) : (
              <div className="grid grid-cols-1 gap-4 flex-1 content-center">
                <button onClick={() => handleActionSelect(LogType.ENTRADA)} className="group bg-emerald-600 hover:bg-emerald-500 text-white p-6 rounded-2xl shadow-lg transform active:scale-[0.98] transition-all flex items-center justify-between overflow-hidden relative">
                  <div className="text-left relative z-10"><span className="block text-2xl font-black tracking-tight">ENTRADA</span><span className="text-emerald-100 text-xs font-medium uppercase tracking-wide">Iniciar jornada</span></div>
                  <div className="bg-emerald-700/50 p-3 rounded-xl relative z-10"><LogOut className="rotate-180" size={32} /></div>
                </button>
                <div className="grid grid-cols-2 gap-4">
                  <button onClick={() => handleActionSelect(LogType.INICIO_DESCANSO)} className="bg-amber-600 hover:bg-amber-500 text-white p-5 rounded-2xl shadow-lg transform active:scale-[0.98] transition-all flex flex-col justify-between h-32">
                    <div className="bg-amber-700/50 self-start p-2 rounded-lg"><Coffee size={24} /></div><span className="font-bold text-left leading-tight text-sm">INICIO<br/>DESCANSO</span>
                  </button>
                  <button onClick={() => handleActionSelect(LogType.FIN_DESCANSO)} className="bg-blue-600 hover:bg-blue-500 text-white p-5 rounded-2xl shadow-lg transform active:scale-[0.98] transition-all flex flex-col justify-between h-32">
                    <div className="bg-blue-700/50 self-start p-2 rounded-lg relative"><Coffee size={24} /><div className="absolute -bottom-1 -right-1 bg-white text-blue-600 rounded-full p-0.5"><LogOut size={10}/></div></div><span className="font-bold text-left leading-tight text-sm">FIN<br/>DESCANSO</span>
                  </button>
                </div>
                <button onClick={() => handleActionSelect(LogType.SALIDA)} className="group bg-rose-600 hover:bg-rose-500 text-white p-6 rounded-2xl shadow-lg transform active:scale-[0.98] transition-all flex items-center justify-between">
                  <div className="text-left"><span className="block text-2xl font-black tracking-tight">SALIDA</span><span className="text-rose-200 text-xs font-medium uppercase tracking-wide">Terminar jornada</span></div>
                  <div className="bg-rose-700/50 p-3 rounded-xl"><LogOut size={32} /></div>
                </button>
              </div>
            )}
          </div>
        )}

        {/* STEP 4.5: EXIT REPORT */}
        {currentStep === Step.REPORT_EXIT && (
           <div className="flex flex-col gap-6 animate-fadeIn h-full">
             <button onClick={() => setCurrentStep(Step.SELECT_ACTION)} className="text-slate-400 text-sm hover:text-white self-start flex items-center gap-1"><ChevronLeft size={16} /> Volver</button>
             <div className="text-center"><h2 className="text-2xl font-bold text-white mb-2">Resumen de Jornada</h2><p className="text-slate-400 text-sm">Completa la información antes de salir.</p></div>
             <div className="bg-slate-900 p-4 rounded-xl border border-slate-800">
               <label className="block text-[10px] uppercase text-slate-500 font-bold mb-3 tracking-wider">Modo de Trabajo</label>
               <div className="flex gap-2">
                 <button onClick={() => setExitWorkMode('HORAS')} className={`flex-1 py-3 px-2 rounded-lg font-bold text-sm transition border-2 ${exitWorkMode === 'HORAS' ? 'bg-blue-600 border-blue-400 text-white' : 'bg-slate-950 border-slate-800 text-slate-500'}`}>⏱️ Por Horas</button>
                 <button onClick={() => setExitWorkMode('DESTAJO')} className={`flex-1 py-3 px-2 rounded-lg font-bold text-sm transition border-2 ${exitWorkMode === 'DESTAJO' ? 'bg-purple-600 border-purple-400 text-white' : 'bg-slate-950 border-slate-800 text-slate-500'}`}>🧱 A Destajo</button>
               </div>
             </div>
             <div className="flex-1 bg-slate-900 p-4 rounded-xl border border-slate-800 flex flex-col shadow-inner">
                <div className="flex justify-between items-center mb-3">
                  <label className="text-[10px] uppercase text-slate-500 font-bold flex items-center gap-2 tracking-wider"><FileText size={14}/> Parte de Trabajo</label>
                  <button onClick={toggleVoiceRecognition} className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-[10px] font-bold uppercase tracking-wider transition ${isListening ? 'bg-rose-500 text-white animate-pulse' : 'bg-slate-800 text-slate-400 hover:text-white'}`}>{isListening ? <><MicOff size={12}/> Detener</> : <><Mic size={12}/> Dictar voz</>}</button>
                </div>
                <textarea value={exitReportText} onChange={(e) => setExitReportText(e.target.value)} placeholder={isListening ? "Escuchando..." : "Escribe o dicta qué has hecho hoy..."} className="w-full flex-1 bg-slate-950 text-white p-4 rounded-lg border border-slate-800 focus:border-blue-500 focus:outline-none resize-none leading-relaxed text-sm"/>
             </div>
             <button onClick={() => executeLogSubmission(LogType.SALIDA, exitReportText, exitWorkMode)} className="bg-emerald-600 hover:bg-emerald-500 text-white p-4 rounded-xl flex items-center justify-center gap-3 shadow-lg font-bold text-lg uppercase tracking-wide transition-colors"><Save size={20} /> Guardar y Salir</button>
           </div>
        )}

        {/* STEP 5: SUCCESS */}
        {currentStep === Step.SUCCESS && (
          <div className="flex-1 flex flex-col items-center justify-center text-center animate-fadeIn p-6">
            <div className="bg-emerald-500 rounded-full p-6 text-slate-950 mb-6 shadow-2xl shadow-emerald-500/20"><CheckCircle size={64} /></div>
            <h2 className="text-3xl font-black text-white mb-2 tracking-tight">¡Registrado!</h2>
            <p className="text-slate-400 mb-8 max-w-xs mx-auto text-sm">Tu fichaje se ha guardado correctamente.</p>
            <div className="w-full bg-slate-900 rounded-2xl p-6 mb-8 text-left border border-slate-800 shadow-xl">
               <div className="flex justify-between mb-3 border-b border-slate-800 pb-3"><span className="text-slate-500 text-xs uppercase font-bold tracking-wider">Trabajador</span><span className="text-white font-bold text-sm">{selectedWorker?.name}</span></div>
               <div className="flex justify-between mb-3 border-b border-slate-800 pb-3"><span className="text-slate-500 text-xs uppercase font-bold tracking-wider">Acción</span><span className={`font-bold text-sm ${selectedAction === LogType.ENTRADA ? 'text-emerald-400' : selectedAction === LogType.SALIDA ? 'text-rose-400' : 'text-amber-400'}`}>{selectedAction}</span></div>
               <div className="flex justify-between items-center"><span className="text-slate-500 text-xs uppercase font-bold tracking-wider">Estado</span><span className="text-blue-400 font-bold flex items-center gap-1.5 text-[10px] bg-blue-950/30 px-2 py-1 rounded border border-blue-900/30 uppercase tracking-wide"><Cloud size={12} /> Sincronizado</span></div>
            </div>
            <button onClick={resetApp} className="w-full bg-blue-600 hover:bg-blue-500 text-white font-bold py-4 rounded-xl shadow-lg transition uppercase tracking-widest text-sm">Finalizar</button>
          </div>
        )}
      </main>

      <footer className="p-4 text-center text-slate-600 text-[10px] font-medium tracking-wider uppercase">
        &copy; 2024 CARMAGNE INSTAL.
      </footer>
    </div>
  );
}

export default App;
