              ))}
              <div className="flex items-center justify-center">
                {biometricsAvailable && (
                   <button 
                     onClick={handleBiometricAuth}
                     className="h-14 w-14 rounded-full bg-slate-800 text-blue-400 flex items-center justify-center hover:bg-slate-700 hover:text-white transition shadow-lg border border-slate-700"
                   >
                     <Fingerprint size={24} />
                   </button>
                )}
              </div>
              <button
                onClick={() => handlePinInput('0')}
                className="h-16 rounded-2xl bg-slate-900 text-white text-xl font-bold hover:bg-slate-800 active:bg-blue-600 active:text-white transition-all shadow-lg border border-slate-800"
              >
                0
              </button>
              <button
                onClick={handlePinClear}
                className="h-16 flex items-center justify-center text-rose-500 hover:text-rose-400 transition"
