## App.tsx

**Cambios Críticos:**
1.  **Eliminada la lista de trabajadores:** Ya no se puede seleccionar nombre.
2.  **Login por Teléfono:** Nueva pantalla inicial donde se pide el número. Si existe -> pide PIN. Si no -> lleva al registro.
3.  **Estilo Azul/Oscuro:** Eliminado todo rastro de amarillo (`yellow-400`).
4.  **Logo eliminado:** Solo texto tipográfico.

```tsx
import React, { useState, useEffect } from 'react';
import { 
  User, MapPin, CheckCircle, 
  LogOut, Coffee, ArrowRight, ShieldAlert, Lock, Fingerprint, Delete, UserPlus, Save, ChevronLeft, Calendar, History, Clock, Smartphone, X, Mic, MicOff, FileText, Cloud, ExternalLink, Briefcase, Phone, KeyRound
} from 'lucide-react';
import { StorageService } from './services/storageService';
import { LocationService } from './services/locationService';
import { Worker, Site, WorkLog, LogType, GeoLocationData, WorkMode } from './types';
import { AdminPanel } from './components/AdminPanel';
import { InstallTutorial } from './components/InstallTutorial';

// App Steps
enum Step {
  LOGIN_PHONE = 0,    // Nuevo paso 0: Pedir teléfono
  AUTHENTICATE = 1,   // Paso 1: Pedir PIN
  WORKER_DASHBOARD = 15,
  WORKER_HISTORY = 16,
  SELECT_SITE = 2,
  SELECT_ACTION = 3,
  REPORT_EXIT = 4, 
  SUCCESS = 5,
  REGISTER = 99,
  RECOVERY = 100
}

// Geofencing
const MAX_DISTANCE_METERS = 500;

function App() {
  // Splash Screen State
  const [isAppLoading, setIsAppLoading] = useState(true);

  const [isAdmin, setIsAdmin] = useState(false);
  const [currentStep, setCurrentStep] = useState<Step>(Step.LOGIN_PHONE);

  // Install Tutorial State
  const [showInstallGuide, setShowInstallGuide] = useState(false);

  // Admin Login State
  const [showAdminLogin, setShowAdminLogin] = useState(false);
  const [adminPasswordInput, setAdminPasswordInput] = useState('');
  const [adminError, setAdminError] = useState('');

  // Login State
  const [loginPhone, setLoginPhone] = useState('');

  // Selection State
  const [selectedWorker, setSelectedWorker] = useState<Worker | null>(null);
  const [selectedSite, setSelectedSite] = useState<Site | null>(null);
  const [selectedAction, setSelectedAction] = useState<LogType | null>(null);
  const [location, setLocation] = useState<GeoLocationData | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  // Exit Report State
  const [exitReportText, setExitReportText] = useState('');
  const [exitWorkMode, setExitWorkMode] = useState<WorkMode>('HORAS');
  const [isListening, setIsListening] = useState(false);

  // Authentication State
  const [pinInput, setPinInput] = useState('');
  const [biometricsAvailable, setBiometricsAvailable] = useState(false);

  // Registration State
  const [regName, setRegName] = useState('');
  const [regDni, setRegDni] = useState('');
  const [regPhone, setRegPhone] = useState('');
  const [regRole, setRegRole] = useState('');
  const [regPin, setRegPin] = useState('');
  const [regPinConfirm, setRegPinConfirm] = useState('');

  // History State
  const [historyDate, setHistoryDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [workerLogs, setWorkerLogs] = useState<WorkLog[]>([]);

  // Data
  const [workers, setWorkers] = useState<Worker[]>([]);
  const [sites, setSites] = useState<Site[]>([]);

  useEffect(() => {
    const timer = setTimeout(() => {
      setIsAppLoading(false);
    }, 2500);

    setWorkers(StorageService.getWorkers());
    setSites(StorageService.getSites());
    setWorkerLogs(StorageService.getLogs()); 

    const unsubWorkers = StorageService.subscribeToWorkers((data) => setWorkers(data));
    const unsubSites = StorageService.subscribeToSites((data) => setSites(data));
    const unsubLogs = StorageService.subscribeToLogs((data) => setWorkerLogs(data));

    if (window.PublicKeyCredential) {
      window.PublicKeyCredential.isUserVerifyingPlatformAuthenticatorAvailable()
        .then(isAvailable => {
          setBiometricsAvailable(isAvailable);
        })
        .catch(err => console.error("Bio check failed", err));
    }

    return () => {
      clearTimeout(timer);
      unsubWorkers();
      unsubSites();
      unsubLogs();
    };
  }, []);

  useEffect(() => {
    if (currentStep === Step.WORKER_DASHBOARD || currentStep === Step.WORKER_HISTORY) {
      setWorkerLogs(StorageService.getLogs());
    }
  }, [currentStep]);

  // Admin Login Handler
  const handleAdminAccessRequest = () => {
    setShowAdminLogin(true);
    setAdminPasswordInput('');
    setAdminError('');
  };

  const verifyAdminPassword = () => {
    const config = StorageService.getConfig();
    const storedPass = config.adminPassword || 'admin';
    if (adminPasswordInput === storedPass) {
      setIsAdmin(true);
      setShowAdminLogin(false);
    } else {
      setAdminError('Contraseña incorrecta');
      setAdminPasswordInput('');
    }
  };

  // --- NUEVA LÓGICA LOGIN ---
  const handlePhoneLogin = () => {
    if(!loginPhone || loginPhone.length < 6) {
      setError("Ingresa un teléfono válido");
      return;
    }

    // Buscar trabajador por teléfono
    const worker = workers.find(w => w.phone && w.phone.replace(/\s/g, '') === loginPhone.replace(/\s/g, ''));

    if (worker) {
      if (!worker.active) {
        setError("Esta cuenta está desactivada. Contacta al administrador.");
        return;
      }
      setSelectedWorker(worker);
      setPinInput('');
      setError('');
      setCurrentStep(Step.AUTHENTICATE);
    } else {
      if(confirm("Este número no está registrado. ¿Quieres crear una cuenta nueva?")) {
        setRegPhone(loginPhone);
        setError('');
        setCurrentStep(Step.REGISTER);
      }
    }
  };

  const handleRegistration = async () => {
    if (!regName || !regDni || !regPin || !regPhone) {
      setError('Todos los campos son obligatorios.');
      return;
    }
    // Doble check de teléfono
    const exists = workers.find(w => w.phone === regPhone);
    if (exists) {
      setError('Este teléfono ya está registrado.');
      return;
    }

    if (regPin.length !== 4) {
      setError('El PIN debe tener 4 dígitos.');
      return;
    }
    if (regPin !== regPinConfirm) {
      setError('Los PINs no coinciden.');
      return;
    }

    setLoading(true);
    setError('');

    const newId = `W${Math.floor(1000 + Math.random() * 9000)}`;
    const newWorker: Worker = {
      id: newId,
      name: regName,
      dni: regDni,
      phone: regPhone,
      role: regRole || 'Trabajador',
      pin: regPin,
      qrCode: `QR_${newId}`,
      active: true,
      defaultMode: 'HORAS'
    };

    try {
      await StorageService.registerNewWorker(newWorker);
      setLoading(false);
      setSelectedWorker(newWorker);
      setPinInput('');
      setCurrentStep(Step.AUTHENTICATE);

      // Limpiar
      setRegName(''); setRegDni(''); setRegPhone(''); setRegRole(''); setRegPin(''); setRegPinConfirm('');
    } catch (err: any) {
      setLoading(false);
      setError('Error de conexión. No se pudo crear la cuenta.');
      alert("Error: No se pudo guardar en la base de datos.");
    }
  };

  const handlePinInput = (digit: string) => {
    if (pinInput.length < 4) {
      const newPin = pinInput + digit;
      setPinInput(newPin);
      if (newPin.length === 4) {
        verifyAuth(newPin);
      }
    }
  };

  const handlePinClear = () => {
    setPinInput('');
    setError('');
  };

  const verifyAuth = (pinToVerify: string) => {
    if (selectedWorker && selectedWorker.pin === pinToVerify) {
      setCurrentStep(Step.WORKER_DASHBOARD);
      setError('');
    } else {
      setError('PIN Incorrecto');
      setTimeout(() => setPinInput(''), 500);
    }
  };

  const handleBiometricAuth = async () => {
    try {
      setError('');
      const publicKeyCredentialCreationOptions: PublicKeyCredentialCreationOptions = {
        challenge: Uint8Array.from("RANDOM_CHALLENGE_STRING", c => c.charCodeAt(0)),
        rp: { name: "CARMAGNE SOLU", id: window.location.hostname },
        user: {
            id: Uint8Array.from("USER_ID", c => c.charCodeAt(0)),
            name: selectedWorker?.name || "worker",
            displayName: selectedWorker?.name || "Worker",
        },
        pubKeyCredParams: [{alg: -7, type: "public-key"}],
        authenticatorSelection: { authenticatorAttachment: "platform", userVerification: "required" },
        timeout: 60000,
        attestation: "direct"
      };

      await navigator.credentials.create({ publicKey: publicKeyCredentialCreationOptions });
      setCurrentStep(Step.WORKER_DASHBOARD); 

    } catch (err) {
      console.error(err);
      setError('Autenticación biométrica fallida o cancelada.');
    }
  };

  const handleSiteSelect = (siteId: string) => {
    const site = sites.find(s => s.id === siteId);
    if (site) {
      setSelectedSite(site);
      setCurrentStep(Step.SELECT_ACTION);
      LocationService.getCurrentPosition()
        .then(loc => setLocation(loc))
        .catch(err => console.warn("Background loc failed", err));
    }
  };

  const handleActionSelect = async (type: LogType) => {
    setSelectedAction(type);
    setLoading(true);
    setError('');

    let loc = location;
    try {
      if (!loc) {
        loc = await LocationService.getCurrentPosition();
        setLocation(loc);
      }
    } catch (err) {
      // Continue without location
    }
    setLoading(false);

    if (type === LogType.SALIDA) {
      setExitWorkMode(selectedWorker?.defaultMode || 'HORAS');
      setExitReportText('');
      setCurrentStep(Step.REPORT_EXIT);
    } else {
      executeLogSubmission(type, undefined, 'HORAS');
    }
  };

  const toggleVoiceRecognition = () => {
    if (isListening) {
      setIsListening(false);
      return;
    }

    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) {
      alert("Tu navegador no soporta reconocimiento de voz. Usa Chrome o Safari.");
      return;
    }

    const recognition = new SpeechRecognition();
    recognition.lang = 'es-ES';
    recognition.continuous = false;
    recognition.interimResults = false;

    setIsListening(true);

    recognition.onresult = (event: any) => {
      const transcript = event.results[0][0].transcript;
      setExitReportText(prev => (prev ? prev + '. ' + transcript : transcript));
      setIsListening(false);
    };

    recognition.onerror = (event: any) => {
      console.error(event.error);
      setIsListening(false);
    };

    recognition.onend = () => {
      setIsListening(false);
    };

    recognition.start();
  };

  const executeLogSubmission = async (type: LogType, report?: string, mode?: WorkMode) => {
    setLoading(true);
    try {
      let loc = location;
      if (!loc) {
        loc = await LocationService.getCurrentPosition();
        setLocation(loc);
      }

      let distance = 0;
      let warning = false;

      if (selectedSite && selectedSite.coordinates) {
        distance = LocationService.calculateDistance(
          loc!.latitude,
          loc!.longitude,
          selectedSite.coordinates.latitude,
          selectedSite.coordinates.longitude
        );

        if (distance > MAX_DISTANCE_METERS) {
          warning = true;
        }
      }

      await submitLog(loc!, type, distance, warning, undefined, report, mode);

    } catch (err: any) {
      setLoading(false);
      setError('Error obteniendo ubicación GPS. Active el GPS y reintente.');
    }
  };

  const submitLog = async (
    loc: GeoLocationData, 
    type: LogType, 
    distance: number, 
    warning: boolean, 
    photoUrl?: string,
    report?: string,
    mode?: WorkMode
  ) => {
    if (!selectedWorker || !selectedSite) return;

    setLoading(true);
    const now = new Date();

    const newLog: WorkLog = {
      id: `LOG-${Date.now()}`,
      workerId: selectedWorker.id,
      workerName: selectedWorker.name,
      siteId: selectedSite.id,
      siteName: selectedSite.name,
      type: type,
      timestamp: now.getTime(),
      dateStr: now.toLocaleDateString('es-ES'),
      timeStr: now.toLocaleTimeString('es-ES'),
      location: loc,
      photoUrl: photoUrl,
      sentToWhatsapp: false,
      syncedToSheets: false,
      distanceMeters: distance,
      locationWarning: warning,
      workReport: report,
      workMode: mode
    };

    try {
      await StorageService.addLog(newLog);
      StorageService.syncLog(newLog).then(success => {
        if (success) {
          newLog.syncedToSheets = true;
          StorageService.updateLog(newLog);
        }
      });
      setCurrentStep(Step.SUCCESS);
    } catch (err: any) {
      console.error(err);
      alert("Error al guardar: " + err.message);
    } finally {
      setLoading(false);
    }
  };

  const resetApp = () => {
    // Al cerrar sesión volvemos al teléfono
    setCurrentStep(Step.LOGIN_PHONE);
    setSelectedWorker(null);
    setSelectedSite(null);
    setSelectedAction(null);
    setLocation(null);
    setPinInput('');
    setLoginPhone('');
    setError('');
  };

  // --- WORKER HELPERS ---
  const getDailyStats = (dateStr: string) => {
    if (!selectedWorker) return { totalMs: 0, logs: [] };
    const targetDate = new Date(dateStr);
    const dayLogs = workerLogs.filter(l => {
      if (l.workerId !== selectedWorker.id) return false;
      const logDate = new Date(l.timestamp);
      return logDate.toDateString() === targetDate.toDateString();
    }).sort((a,b) => a.timestamp - b.timestamp);

    let totalPresence = 0;
    let totalBreaks = 0;
    let lastEntry = null;
    let lastBreak = null;

    dayLogs.forEach(log => {
      if (log.type === LogType.ENTRADA) lastEntry = log.timestamp;
      if (log.type === LogType.SALIDA && lastEntry) {
        totalPresence += (log.timestamp - lastEntry);
        lastEntry = null;
      }
      if (log.type === LogType.INICIO_DESCANSO) lastBreak = log.timestamp;
      if (log.type === LogType.FIN_DESCANSO && lastBreak) {
        totalBreaks += (log.timestamp - lastBreak);
        lastBreak = null;
      }
    });

    return {
      totalMs: Math.max(0, totalPresence - totalBreaks),
      logs: dayLogs
    };
  };

  const getCurrentStatus = () => {
    if (!selectedWorker) return null;
    const myLogs = workerLogs.filter(l => l.workerId === selectedWorker.id).sort((a,b) => b.timestamp - a.timestamp);

    const activityLogs = myLogs.filter(l => l.type !== LogType.REGISTRO);
    if (activityLogs.length === 0) return { status: 'FUERA', site: '-', since: null };

    const lastLog = activityLogs[0];
    const isToday = new Date(lastLog.timestamp).toDateString() === new Date().toDateString();

    if (lastLog.type === LogType.ENTRADA || lastLog.type === LogType.FIN_DESCANSO) {
      return { status: 'TRABAJANDO', site: lastLog.siteName, since: lastLog.timestamp, isToday };
    } else if (lastLog.type === LogType.INICIO_DESCANSO) {
      return { status: 'EN DESCANSO', site: lastLog.siteName, since: lastLog.timestamp, isToday };
    } else {
      return { status: 'FUERA', site: '-', since: lastLog.timestamp, isToday };
    }
  };

  const msToTime = (ms: number) => {
    const hrs = Math.floor(ms / 3600000);
    const mins = Math.floor((ms % 3600000) / 60000);
    return `${hrs}h ${mins}m`;
  };

  // --- RENDERERS ---

  const renderWorkerDashboard = () => {
    const status = getCurrentStatus();
    return (
      <div className="flex flex-col gap-6 animate-fadeIn h-full">
        <div className="flex justify-between items-center px-2">
          <span className="text-xl font-bold text-white tracking-tight">{selectedWorker?.name}</span>
          <button onClick={resetApp} className="text-slate-400 hover:text-white transition p-2 bg-slate-800 rounded-full border border-slate-700">
            <LogOut size={18} />
          </button>
        </div>

        {/* ELEGANT STATUS CARD */}
        <div className={`relative overflow-hidden rounded-2xl p-6 shadow-xl border border-slate-700/50 ${
          status?.status === 'TRABAJANDO' ? 'bg-gradient-to-br from-slate-900 to-emerald-950/30' :
          status?.status === 'EN DESCANSO' ? 'bg-gradient-to-br from-slate-900 to-amber-950/30' :
          'bg-gradient-to-br from-slate-900 to-slate-800'
        }`}>
          <div className="relative z-10 flex flex-col items-center text-center">
            <div className={`text-[10px] font-bold tracking-[0.2em] uppercase mb-2 ${
               status?.status === 'TRABAJANDO' ? 'text-emerald-400' :
               status?.status === 'EN DESCANSO' ? 'text-amber-400' :
               'text-slate-500'
            }`}>Estado Actual</div>

            <h2 className="text-3xl font-black text-white mb-2 tracking-tight">
              {status?.status || 'SIN ACTIVIDAD'}
            </h2>

            {status?.status !== 'FUERA' && (
              <div className="mt-2 space-y-1">
                <p className="text-slate-300 font-medium">{status?.site}</p>
                <div className="flex items-center justify-center gap-2 text-xs text-slate-400 bg-slate-950/50 px-3 py-1 rounded-full border border-slate-700">
                  <Clock size={12}/> 
                  <span>Desde: {new Date(status?.since || 0).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
                </div>
              </div>
            )}
          </div>
        </div>

        <h3 className="text-slate-400 text-sm font-bold uppercase tracking-wider px-2 mt-2">Acciones Rápidas</h3>

        <div className="grid grid-cols-1 gap-4 flex-1">
           <button 
             onClick={() => setCurrentStep(Step.SELECT_SITE)}
             className="group bg-slate-800 hover:bg-slate-700 border border-slate-700 hover:border-blue-500/50 transition-all p-6 rounded-2xl shadow-lg flex items-center justify-between"
           >
             <div className="text-left">
               <span className="block text-xl font-bold text-white group-hover:text-blue-400 transition-colors">Nuevo Fichaje</span>
               <span className="text-slate-400 text-sm">Entrada, Salida o Pausa</span>
             </div>
             <div className="bg-slate-900 p-3 rounded-full text-blue-500 group-hover:scale-110 transition-transform duration-300 shadow-inner">
               <Clock size={24} />
             </div>
           </button>

           <button 
             onClick={() => setCurrentStep(Step.WORKER_HISTORY)}
             className="group bg-slate-800 hover:bg-slate-700 border border-slate-700 hover:border-purple-500/50 transition-all p-6 rounded-2xl shadow-lg flex items-center justify-between"
           >
             <div className="text-left">
               <span className="block text-xl font-bold text-white group-hover:text-purple-400 transition-colors">Mi Historial</span>
               <span className="text-slate-400 text-sm">Ver mis horas y actividad</span>
             </div>
             <div className="bg-slate-900 p-3 rounded-full text-purple-500 group-hover:scale-110 transition-transform duration-300 shadow-inner">
               <History size={24} />
             </div>
           </button>
        </div>
      </div>
    );
  };

  const renderWorkerHistory = () => {
    const { totalMs, logs: dayLogs } = getDailyStats(historyDate);

    return (
      <div className="flex flex-col gap-4 animate-fadeIn h-full">
        <button onClick={() => setCurrentStep(Step.WORKER_DASHBOARD)} className="text-slate-400 hover:text-white self-start flex items-center gap-1 text-sm font-medium transition-colors">
          <ChevronLeft size={16} /> Volver
        </button>

        <h2 className="text-2xl font-bold text-white text-center tracking-tight">Mi Actividad</h2>

        <div className="bg-slate-800 p-4 rounded-xl flex items-center gap-4 border border-slate-700 shadow-md">
          <div className="bg-slate-900 p-2 rounded-lg text-blue-500">
            <Calendar size={20} />
          </div>
          <div className="flex-1">
            <label className="text-[10px] text-slate-400 font-bold uppercase tracking-wider block mb-1">Fecha</label>
            <input 
              type="date" 
              value={historyDate}
              onChange={(e) => setHistoryDate(e.target.value)}
              className="bg-transparent text-white font-bold text-lg w-full outline-none"
            />
          </div>
        </div>

        <div className="bg-gradient-to-br from-slate-800 to-slate-900 p-6 rounded-xl border border-slate-700 text-center shadow-lg relative overflow-hidden">
           <p className="text-slate-400 text-xs font-bold uppercase tracking-widest">Total Trabajado</p>
           <div className="flex items-end justify-center gap-3 mt-2">
             <Clock size={28} className="text-blue-500 mb-1.5"/>
             <span className="text-4xl font-black text-white tracking-tighter">{msToTime(totalMs)}</span>
           </div>
           {totalMs > 0 && <p className="text-[10px] text-slate-500 mt-2 font-medium">Tiempo neto (sin descansos)</p>}
        </div>

        <div className="flex-1 overflow-y-auto custom-scrollbar mt-2 px-1">
          <h3 className="text-xs text-slate-500 font-bold uppercase mb-4 tracking-wider pl-2">Línea de Tiempo</h3>
          {dayLogs.length === 0 ? (
            <div className="text-center text-slate-600 py-12 italic text-sm">No hay registros para este día.</div>
          ) : (
            <div className="relative border-l-2 border-slate-800 ml-4 space-y-6 pb-4">
              {dayLogs.map((log) => (
