                 </button>
                 <button 
                   onClick={() => setExitWorkMode('DESTAJO')}
                   className={`flex-1 py-3 px-2 rounded-lg font-bold text-sm transition border-2 ${
                     exitWorkMode === 'DESTAJO' 
                       ? 'bg-purple-600 border-purple-400 text-white' 
                       : 'bg-slate-950 border-slate-800 text-slate-500 hover:text-slate-300'
                   }`}
                 >
                   🧱 A Destajo
                 </button>
               </div>
             </div>

             {/* Report Input */}
             <div className="flex-1 bg-slate-900 p-4 rounded-xl border border-slate-800 flex flex-col shadow-inner">
                <div className="flex justify-between items-center mb-3">
                  <label className="text-[10px] uppercase text-slate-500 font-bold flex items-center gap-2 tracking-wider">
                    <FileText size={14}/> Parte de Trabajo
                  </label>
                  <button 
                    onClick={toggleVoiceRecognition}
                    className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-[10px] font-bold uppercase tracking-wider transition ${
                       isListening ? 'bg-rose-500 text-white animate-pulse' : 'bg-slate-800 text-slate-400 hover:text-white'
                    }`}
                  >
                    {isListening ? <><MicOff size={12}/> Detener</> : <><Mic size={12}/> Dictar voz</>}
                  </button>
                </div>

                <textarea 
                  value={exitReportText}
                  onChange={(e) => setExitReportText(e.target.value)}
                  placeholder={isListening ? "Escuchando..." : "Escribe o dicta qué has hecho hoy..."}
                  className="w-full flex-1 bg-slate-950 text-white p-4 rounded-lg border border-slate-800 focus:border-blue-500 focus:outline-none resize-none leading-relaxed text-sm"
                />
             </div>

             <button 
               onClick={() => executeLogSubmission(LogType.SALIDA, exitReportText, exitWorkMode)}
               className="bg-emerald-600 hover:bg-emerald-500 text-white p-4 rounded-xl flex items-center justify-center gap-3 shadow-lg font-bold text-lg uppercase tracking-wide transition-colors"
             >
               <Save size={20} /> Guardar y Salir
             </button>
           </div>
        )}

        {/* STEP 5: SUCCESS */}
        {currentStep === Step.SUCCESS && (
          <div className="flex-1 flex flex-col items-center justify-center text-center animate-fadeIn p-6">
            <div className="bg-emerald-500 rounded-full p-6 text-slate-950 mb-6 shadow-2xl shadow-emerald-500/20">
              <CheckCircle size={64} />
            </div>
            <h2 className="text-3xl font-black text-white mb-2 tracking-tight">¡Registrado!</h2>
            <p className="text-slate-400 mb-8 max-w-xs mx-auto text-sm">
              Tu fichaje se ha guardado correctamente.
            </p>

            <div className="w-full bg-slate-900 rounded-2xl p-6 mb-8 text-left border border-slate-800 shadow-xl">
               <div className="flex justify-between mb-3 border-b border-slate-800 pb-3">
                 <span className="text-slate-500 text-xs uppercase font-bold tracking-wider">Trabajador</span>
                 <span className="text-white font-bold text-sm">{selectedWorker?.name}</span>
               </div>
               <div className="flex justify-between mb-3 border-b border-slate-800 pb-3">
                 <span className="text-slate-500 text-xs uppercase font-bold tracking-wider">Acción</span>
                 <span className={`font-bold text-sm ${
                    selectedAction === LogType.ENTRADA ? 'text-emerald-400' : 
                    selectedAction === LogType.SALIDA ? 'text-rose-400' : 'text-amber-400'
                 }`}>{selectedAction}</span>
               </div>
               <div className="flex justify-between items-center">
                 <span className="text-slate-500 text-xs uppercase font-bold tracking-wider">Estado</span>
                 <span className="text-blue-400 font-bold flex items-center gap-1.5 text-[10px] bg-blue-950/30 px-2 py-1 rounded border border-blue-900/30 uppercase tracking-wide">
                   <Cloud size={12} /> Sincronizado
                 </span>
               </div>
            </div>

            <button 
              onClick={resetApp}
              className="w-full bg-blue-600 hover:bg-blue-500 text-white font-bold py-4 rounded-xl shadow-lg transition uppercase tracking-widest text-sm"
            >
              Finalizar
            </button>
          </div>
        )}
      </main>

      <footer className="p-4 text-center text-slate-600 text-[10px] font-medium tracking-wider uppercase">
        &copy; 2024 CARMAGNE INSTAL. V1.7.0
      </footer>
    </div>
  );
}

export default App;
