    return initial;
  }
};
const saveLocal = <T>(key: string, data: T): void => {
  try {
    localStorage.setItem(key, JSON.stringify(data));
  } catch (e) {
    console.error("Error saving local", e);
  }
};

// Helper to remove undefined values for Firebase
