    // Prioridad: Configuración guardada > Constante Hardcodeada
    const url = config.googleSheetUrl || GOOGLE_SCRIPT_URL;

    if (!url || url.length < 10) {
      console.error("SYNC ERROR: No hay URL de Google Script configurada.");
      return false;
    }

