         <p className="text-blue-400 font-bold tracking-[0.5em] text-xs uppercase">Instalaciones 2024</p>
      </div>
    );
  }

  if (isAdmin) return <AdminPanel onBack={() => setIsAdmin(false)} />;

  return (
    <div className="min-h-screen bg-brand-950 flex flex-col font-sans text-slate-100 selection:bg-blue-500/30">

