              <button onClick={() => setShowAdminLogin(false)} className="absolute top-4 right-4 text-slate-500"><X size={20} /></button>
              <h2 className="text-xl font-bold text-white text-center mb-6 tracking-wide">ACCESO SEGURO</h2>
              <input type="password" value={adminPasswordInput} onChange={(e) => setAdminPasswordInput(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-xl p-4 text-center text-xl mb-6 focus:border-blue-500 outline-none text-white" placeholder="••••••" autoFocus/>
              {adminError && <div className="text-rose-500 text-xs text-center mb-4 font-bold">{adminError}</div>}
              <button onClick={verifyAdminPassword} className="w-full bg-blue-600 text-white font-bold py-4 rounded-xl">ENTRAR</button>
           </div>
        </div>
      )}

      {/* Header */}
      <header className="glass-header p-4 flex justify-between items-center sticky top-0 z-20">
        <div>
          <h1 className="text-xl font-black tracking-tight leading-none text-white">CARMAGNE</h1>
