  const [selectedAction, setSelectedAction] = useState<LogType | null>(null);
  const [location, setLocation] = useState<GeoLocationData | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  // Exit Report
  const [exitReportText, setExitReportText] = useState('');
  const [exitWorkMode, setExitWorkMode] = useState<WorkMode>('HORAS');
  const [isListening, setIsListening] = useState(false);

  // Auth
  const [pinInput, setPinInput] = useState('');
  const [biometricsAvailable, setBiometricsAvailable] = useState(false);

  // Registration
  const [regName, setRegName] = useState('');
  const [regDni, setRegDni] = useState('');
  const [regPhone, setRegPhone] = useState('');
  const [regRole, setRegRole] = useState('');
  const [regPin, setRegPin] = useState('');
  const [regPinConfirm, setRegPinConfirm] = useState('');

  // History
  const [historyDate, setHistoryDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [workerLogs, setWorkerLogs] = useState<WorkLog[]>([]);

  // Data Cache
  const [workers, setWorkers] = useState<Worker[]>([]);
  const [sites, setSites] = useState<Site[]>([]);

  useEffect(() => {
    const timer = setTimeout(() => setIsAppLoading(false), 2500);

    setWorkers(StorageService.getWorkers());
    setSites(StorageService.getSites());
    setWorkerLogs(StorageService.getLogs()); 

    const unsubWorkers = StorageService.subscribeToWorkers((data) => setWorkers(data));
    const unsubSites = StorageService.subscribeToSites((data) => setSites(data));
    const unsubLogs = StorageService.subscribeToLogs((data) => setWorkerLogs(data));

    if (window.PublicKeyCredential) {
      window.PublicKeyCredential.isUserVerifyingPlatformAuthenticatorAvailable()
        .then(isAvailable => setBiometricsAvailable(isAvailable))
        .catch(err => console.error("Bio check failed", err));
    }

    return () => {
      clearTimeout(timer);
      unsubWorkers();
      unsubSites();
      unsubLogs();
    };
  }, []);

  // --- HANDLERS ---

  const handleAdminAccessRequest = () => {
    setShowAdminLogin(true);
    setAdminPasswordInput('');
    setAdminError('');
  };

  const verifyAdminPassword = () => {
    const config = StorageService.getConfig();
    const storedPass = config.adminPassword || 'admin';
    if (adminPasswordInput === storedPass) {
      setIsAdmin(true);
      setShowAdminLogin(false);
    } else {
      setAdminError('Contraseña incorrecta');
    }
  };

  const handlePhoneLogin = () => {
    if(!loginPhone || loginPhone.length < 6) {
      setError("Ingresa un teléfono válido");
      return;
    }
    const worker = workers.find(w => w.phone && w.phone.replace(/\s/g, '') === loginPhone.replace(/\s/g, ''));

    if (worker) {
      if (!worker.active) {
        setError("Cuenta desactivada.");
        return;
      }
      setSelectedWorker(worker);
      setPinInput('');
      setError('');
      setCurrentStep(Step.AUTHENTICATE);
    } else {
      if(confirm("Número no encontrado. ¿Crear cuenta nueva?")) {
        setRegPhone(loginPhone);
        setError('');
        setCurrentStep(Step.REGISTER);
      }
    }
  };

  const handleRegistration = async () => {
    if (!regName || !regDni || !regPin || !regPhone) {
      setError('Todos los campos son obligatorios.');
      return;
    }
    const exists = workers.find(w => w.phone === regPhone);
    if (exists) {
      setError('Teléfono ya registrado.');
      return;
    }
    if (regPin.length !== 4) {
      setError('PIN debe ser de 4 dígitos.');
      return;
    }
    if (regPin !== regPinConfirm) {
      setError('Los PINs no coinciden.');
      return;
    }

    setLoading(true);
    setError('');

    const newWorker: Worker = {
      id: `W${Math.floor(10000 + Math.random() * 90000)}`,
      name: regName,
      dni: regDni,
      phone: regPhone.trim(),
      role: regRole || 'Trabajador',
      pin: regPin,
      qrCode: `QR_${Date.now()}`,
      active: true,
      defaultMode: 'HORAS'
    };

    try {
      await StorageService.registerNewWorker(newWorker);
      setLoading(false);
      setSelectedWorker(newWorker);
      setPinInput('');
      setCurrentStep(Step.AUTHENTICATE);
      setRegName(''); setRegDni(''); setRegPhone(''); setRegRole(''); setRegPin(''); setRegPinConfirm('');
    } catch (err: any) {
      setLoading(false);
      setError('Error de conexión.');
      alert("No se pudo guardar en la base de datos.");
    }
  };

  const handlePinInput = (digit: string) => {
    if (pinInput.length < 4) {
      const newPin = pinInput + digit;
      setPinInput(newPin);
      if (newPin.length === 4) verifyAuth(newPin);
    }
  };

  const verifyAuth = (pinToVerify: string) => {
    if (selectedWorker && selectedWorker.pin === pinToVerify) {
      setCurrentStep(Step.WORKER_DASHBOARD);
      setError('');
    } else {
      setError('PIN Incorrecto');
      setTimeout(() => setPinInput(''), 500);
    }
  };

  const handleSiteSelect = (siteId: string) => {
    const site = sites.find(s => s.id === siteId);
    if (site) {
      setSelectedSite(site);
      setCurrentStep(Step.SELECT_ACTION);
      LocationService.getCurrentPosition()
        .then(loc => setLocation(loc))
        .catch(err => console.warn("Loc failed", err));
    }
  };

  const handleActionSelect = async (type: LogType) => {
    setSelectedAction(type);
    setLoading(true);
    setError('');

    try {
      let loc = location;
      if (!loc) {
        loc = await LocationService.getCurrentPosition();
        setLocation(loc);
      }
    } catch (err) {}
    setLoading(false);

    if (type === LogType.SALIDA) {
      setExitWorkMode(selectedWorker?.defaultMode || 'HORAS');
      setExitReportText('');
      setCurrentStep(Step.REPORT_EXIT);
    } else {
      executeLogSubmission(type, undefined, 'HORAS');
    }
  };

  const executeLogSubmission = async (type: LogType, report?: string, mode?: WorkMode) => {
    setLoading(true);
    try {
      let loc = location;
      if (!loc) {
        loc = await LocationService.getCurrentPosition();
        setLocation(loc);
      }
      let distance = 0;
      let warning = false;
      if (selectedSite && selectedSite.coordinates) {
        distance = LocationService.calculateDistance(loc!.latitude, loc!.longitude, selectedSite.coordinates.latitude, selectedSite.coordinates.longitude);
        if (distance > MAX_DISTANCE_METERS) warning = true;
      }
      await submitLog(loc!, type, distance, warning, undefined, report, mode);
    } catch (err: any) {
      setLoading(false);
      setError('Error GPS.');
    }
  };

  const submitLog = async (loc: GeoLocationData, type: LogType, distance: number, warning: boolean, photoUrl?: string, report?: string, mode?: WorkMode) => {
    if (!selectedWorker || !selectedSite) return;
    setLoading(true);
    const newLog: WorkLog = {
      id: `LOG-${Date.now()}`,
      workerId: selectedWorker.id,
      workerName: selectedWorker.name,
      siteId: selectedSite.id,
      siteName: selectedSite.name,
      type: type,
      timestamp: Date.now(),
      dateStr: new Date().toLocaleDateString('es-ES'),
      timeStr: new Date().toLocaleTimeString('es-ES'),
      location: loc,
      photoUrl: photoUrl,
      sentToWhatsapp: false,
      syncedToSheets: false,
      distanceMeters: distance,
      locationWarning: warning,
      workReport: report,
      workMode: mode
    };

    try {
      await StorageService.addLog(newLog);
      StorageService.syncLog(newLog).then(success => {
        if (success) {
          newLog.syncedToSheets = true;
          StorageService.updateLog(newLog);
        }
      });
      setCurrentStep(Step.SUCCESS);
    } catch (err: any) {
      alert("Error al guardar: " + err.message);
    } finally {
      setLoading(false);
    }
  };

  const resetApp = () => {
    setCurrentStep(Step.LOGIN_PHONE);
    setSelectedWorker(null);
    setSelectedSite(null);
    setSelectedAction(null);
    setLocation(null);
    setPinInput('');
    setLoginPhone('');
    setError('');
  };

  // --- VIEWS ---

  const renderWorkerDashboard = () => {
    const status = getCurrentStatus();
    return (
      <div className="flex flex-col gap-6 animate-fadeIn h-full">
        <div className="flex justify-between items-center px-2">
          <span className="text-xl font-bold text-white tracking-tight">{selectedWorker?.name}</span>
          <button onClick={resetApp} className="text-slate-400 hover:text-white transition p-2 bg-slate-800 rounded-full border border-slate-700">
            <LogOut size={18} />
          </button>
        </div>

        <div className={`relative overflow-hidden rounded-2xl p-6 shadow-xl border border-slate-700/50 ${
          status?.status === 'TRABAJANDO' ? 'bg-gradient-to-br from-slate-900 to-emerald-950/30' :
          status?.status === 'EN DESCANSO' ? 'bg-gradient-to-br from-slate-900 to-amber-950/30' :
          'bg-gradient-to-br from-slate-900 to-slate-800'
        }`}>
          <div className="relative z-10 flex flex-col items-center text-center">
            <div className={`text-[10px] font-bold tracking-[0.2em] uppercase mb-2 ${
               status?.status === 'TRABAJANDO' ? 'text-emerald-400' :
               status?.status === 'EN DESCANSO' ? 'text-amber-400' :
               'text-slate-500'
            }`}>Estado Actual</div>
            <h2 className="text-3xl font-black text-white mb-2 tracking-tight">{status?.status || 'SIN ACTIVIDAD'}</h2>
            {status?.status !== 'FUERA' && (
              <div className="mt-2 space-y-1">
                <p className="text-slate-300 font-medium">{status?.site}</p>
                <div className="flex items-center justify-center gap-2 text-xs text-slate-400 bg-slate-950/50 px-3 py-1 rounded-full border border-slate-700">
                  <Clock size={12}/><span>Desde: {new Date(status?.since || 0).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
                </div>
              </div>
            )}
          </div>
        </div>

        <h3 className="text-slate-400 text-sm font-bold uppercase tracking-wider px-2 mt-2">Acciones Rápidas</h3>
        <div className="grid grid-cols-1 gap-4 flex-1">
           <button onClick={() => setCurrentStep(Step.SELECT_SITE)} className="group bg-slate-800 hover:bg-slate-700 border border-slate-700 hover:border-brand-600/50 transition-all p-6 rounded-2xl shadow-lg flex items-center justify-between">
             <div className="text-left"><span className="block text-xl font-bold text-white group-hover:text-brand-500 transition-colors">Nuevo Fichaje</span><span className="text-slate-400 text-sm">Entrada, Salida o Pausa</span></div>
             <div className="bg-slate-900 p-3 rounded-full text-brand-500 group-hover:scale-110 transition-transform duration-300 shadow-inner"><Clock size={24} /></div>
           </button>
           <button onClick={() => setCurrentStep(Step.WORKER_HISTORY)} className="group bg-slate-800 hover:bg-slate-700 border border-slate-700 hover:border-purple-500/50 transition-all p-6 rounded-2xl shadow-lg flex items-center justify-between">
             <div className="text-left"><span className="block text-xl font-bold text-white group-hover:text-purple-400 transition-colors">Mi Historial</span><span className="text-slate-400 text-sm">Ver mis horas y actividad</span></div>
             <div className="bg-slate-900 p-3 rounded-full text-purple-500 group-hover:scale-110 transition-transform duration-300 shadow-inner"><History size={24} /></div>
           </button>
        </div>
      </div>
    );
  };

  const renderWorkerHistory = () => {
    const { totalMs, logs: dayLogs } = getDailyStats(historyDate);
    return (
      <div className="flex flex-col gap-4 animate-fadeIn h-full">
        <button onClick={() => setCurrentStep(Step.WORKER_DASHBOARD)} className="text-slate-400 hover:text-white self-start flex items-center gap-1 text-sm font-medium transition-colors"><ChevronLeft size={16} /> Volver</button>
        <h2 className="text-2xl font-bold text-white text-center tracking-tight">Mi Actividad</h2>
        <div className="bg-slate-800 p-4 rounded-xl flex items-center gap-4 border border-slate-700 shadow-md">
          <div className="bg-slate-900 p-2 rounded-lg text-brand-500"><Calendar size={20} /></div>
          <div className="flex-1"><label className="text-[10px] text-slate-400 font-bold uppercase tracking-wider block mb-1">Fecha</label><input type="date" value={historyDate} onChange={(e) => setHistoryDate(e.target.value)} className="bg-transparent text-white font-bold text-lg w-full outline-none"/></div>
        </div>
        <div className="bg-gradient-to-br from-slate-800 to-slate-900 p-6 rounded-xl border border-slate-700 text-center shadow-lg relative overflow-hidden">
           <p className="text-slate-400 text-xs font-bold uppercase tracking-widest">Total Trabajado</p>
           <div className="flex items-end justify-center gap-3 mt-2"><Clock size={28} className="text-brand-500 mb-1.5"/><span className="text-4xl font-black text-white tracking-tighter">{msToTime(totalMs)}</span></div>
        </div>
        <div className="flex-1 overflow-y-auto custom-scrollbar mt-2 px-1">
          {dayLogs.length === 0 ? <div className="text-center text-slate-600 py-12 italic text-sm">No hay registros para este día.</div> : 
            <div className="relative border-l-2 border-slate-800 ml-4 space-y-6 pb-4">
              {dayLogs.map((log) => (
                <div key={log.id} className="relative pl-6 group">
                  <div className={`absolute -left-[9px] top-1 w-4 h-4 rounded-full border-2 transition-transform group-hover:scale-110 ${log.type === LogType.ENTRADA ? 'bg-emerald-500 border-emerald-900' : log.type === LogType.SALIDA ? 'bg-rose-500 border-rose-900' : 'bg-amber-500 border-amber-900'}`}></div>
                  <div className="bg-slate-800/50 hover:bg-slate-800 p-4 rounded-xl border border-slate-700/50 transition-colors shadow-sm">
                    <div className="flex justify-between items-start mb-2"><span className={`text-[10px] font-bold px-2 py-1 rounded-md uppercase tracking-wider ${log.type === LogType.ENTRADA ? 'bg-emerald-950/50 text-emerald-400 border border-emerald-900/30' : log.type === LogType.SALIDA ? 'bg-rose-950/50 text-rose-400 border border-rose-900/30' : 'bg-amber-950/50 text-amber-400 border border-amber-900/30'}`}>{log.type}</span><span className="text-white font-mono font-bold text-sm">{log.timeStr}</span></div>
                    <p className="text-white font-semibold text-sm mb-2">{log.siteName}</p>
                  </div>
                </div>
              ))}
            </div>
          }
        </div>
      </div>
    );
  };

  const getDailyStats = (dateStr: string) => {
    if (!selectedWorker) return { totalMs: 0, logs: [] };
    const targetDate = new Date(dateStr);
    const dayLogs = workerLogs.filter(l => {
      if (l.workerId !== selectedWorker.id) return false;
      const logDate = new Date(l.timestamp);
      return logDate.toDateString() === targetDate.toDateString();
    }).sort((a,b) => a.timestamp - b.timestamp);
    let totalPresence = 0; let totalBreaks = 0; let lastEntry = null; let lastBreak = null;
    dayLogs.forEach(log => {
      if (log.type === LogType.ENTRADA) lastEntry = log.timestamp;
      if (log.type === LogType.SALIDA && lastEntry) { totalPresence += (log.timestamp - lastEntry); lastEntry = null; }
      if (log.type === LogType.INICIO_DESCANSO) lastBreak = log.timestamp;
      if (log.type === LogType.FIN_DESCANSO && lastBreak) { totalBreaks += (log.timestamp - lastBreak); lastBreak = null; }
    });
    return { totalMs: Math.max(0, totalPresence - totalBreaks), logs: dayLogs };
  };

  const getCurrentStatus = () => {
    if (!selectedWorker) return null;
    const myLogs = workerLogs.filter(l => l.workerId === selectedWorker.id && l.type !== LogType.REGISTRO).sort((a,b) => b.timestamp - a.timestamp);
    if (myLogs.length === 0) return { status: 'FUERA', site: '-', since: null };
    const lastLog = myLogs[0];
    const isToday = new Date(lastLog.timestamp).toDateString() === new Date().toDateString();
    if (lastLog.type === LogType.ENTRADA || lastLog.type === LogType.FIN_DESCANSO) return { status: 'TRABAJANDO', site: lastLog.siteName, since: lastLog.timestamp, isToday };
    if (lastLog.type === LogType.INICIO_DESCANSO) return { status: 'EN DESCANSO', site: lastLog.siteName, since: lastLog.timestamp, isToday };
    return { status: 'FUERA', site: '-', since: lastLog.timestamp, isToday };
  };

  const msToTime = (ms: number) => {
    const hrs = Math.floor(ms / 3600000);
    const mins = Math.floor((ms % 3600000) / 60000);
    return `${hrs}h ${mins}m`;
  };

  const toggleVoiceRecognition = () => {
    if (isListening) { setIsListening(false); return; }
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) { alert("Navegador no compatible"); return; }
    const recognition = new SpeechRecognition();
    recognition.lang = 'es-ES'; recognition.continuous = false;
    recognition.onresult = (event: any) => { setExitReportText(prev => (prev ? prev + '. ' + event.results[0][0].transcript : event.results[0][0].transcript)); setIsListening(false); };
    recognition.onend = () => setIsListening(false);
    setIsListening(true); recognition.start();
  };

  if (isAppLoading) {
    return (
      <div className="fixed inset-0 bg-slate-950 z-[100] flex flex-col items-center justify-center animate-fadeIn">
         <div className="flex flex-col items-center">
            <h1 className="text-5xl font-black text-white tracking-tighter mb-2">CARMAGNE</h1>
            <div className="h-1 w-24 bg-brand-600 rounded-full mb-3"></div>
            <p className="text-brand-500 font-bold tracking-[0.4em] text-sm">INSTAL 2024</p>
         </div>
      </div>
    );
  }

  if (isAdmin) return <AdminPanel onBack={() => setIsAdmin(false)} />;

  return (
    <div className="min-h-screen bg-slate-950 flex flex-col font-sans selection:bg-brand-500/30">
      {showInstallGuide && <InstallTutorial onClose={() => setShowInstallGuide(false)} />}
      {showAdminLogin && (
        <div className="fixed inset-0 z-50 bg-slate-950/90 backdrop-blur-md flex items-center justify-center p-4 animate-fadeIn">
           <div className="bg-slate-900 w-full max-w-sm rounded-2xl border border-slate-800 shadow-2xl p-8 relative">
              <button onClick={() => setShowAdminLogin(false)} className="absolute top-4 right-4 text-slate-500 hover:text-white"><X size={20} /></button>
              <div className="flex flex-col items-center mb-8"><h2 className="text-xl font-bold text-white uppercase tracking-wider mb-2">Acceso Seguro</h2><div className="h-1 w-12 bg-brand-600 rounded-full"></div></div>
              <input type="password" value={adminPasswordInput} onChange={(e) => setAdminPasswordInput(e.target.value)} className="w-full bg-slate-950 border border-slate-800 rounded-xl p-4 text-white text-center font-bold tracking-[0.5em] text-xl mb-6 focus:border-brand-500 focus:outline-none" placeholder="••••••" autoFocus/>
              {adminError && <div className="text-rose-500 text-xs font-bold text-center mb-6">{adminError}</div>}
              <button onClick={verifyAdminPassword} className="w-full bg-brand-600 hover:bg-brand-500 text-white font-bold py-4 rounded-xl transition shadow-lg uppercase tracking-widest text-sm">ENTRAR</button>
           </div>
        </div>
      )}

      <header className="glass-panel p-4 flex justify-between items-center sticky top-0 z-20 border-b border-slate-800">
        <div><h1 className="text-xl font-black tracking-tight leading-none text-white">CARMAGNE</h1><p className="text-[10px] font-bold text-brand-500 tracking-[0.2em] uppercase mt-0.5">INSTAL 2024</p></div>
        <button onClick={handleAdminAccessRequest} className="p-2.5 bg-slate-800 text-slate-400 rounded-full hover:bg-slate-700 hover:text-brand-500 transition-all border border-slate-700/50"><Lock size={16} /></button>
      </header>

      <main className="flex-1 flex flex-col p-4 max-w-md mx-auto w-full relative">
        {error && <div className="mb-6 p-4 bg-rose-950/80 border border-rose-900 text-rose-200 rounded-xl flex items-center gap-3 animate-bounce z-50 shadow-lg"><ShieldAlert size={20} /><span className="text-xs font-bold">{error}</span></div>}

        {currentStep === Step.LOGIN_PHONE && (
          <div className="flex flex-col gap-8 animate-fadeIn pt-10">
            <div className="text-center">
              <div className="bg-slate-800/50 p-6 rounded-full inline-flex mb-6 border border-slate-700 shadow-inner"><Smartphone size={40} className="text-brand-500" /></div>
              <h2 className="text-3xl font-bold text-white mb-2 tracking-tight">Iniciar Sesión</h2>
              <p className="text-slate-400 text-sm">Introduce tu móvil para fichar.</p>
            </div>
            <div className="bg-slate-900/60 backdrop-blur-sm p-6 rounded-3xl border border-slate-800 shadow-2xl">
               <label className="block text-[10px] uppercase text-slate-500 font-bold mb-3 tracking-widest">Número de Teléfono</label>
               <div className="flex gap-3 mb-6">
                 <div className="bg-slate-950 border border-slate-800 rounded-xl p-4 text-white flex items-center justify-center w-16"><Phone size={20} className="text-slate-600"/></div>
                 <input type="tel" value={loginPhone} onChange={(e) => setLoginPhone(e.target.value)} className="flex-1 bg-slate-950 border border-slate-800 text-white rounded-xl p-4 text-lg focus:border-brand-500 focus:outline-none transition-colors tracking-widest placeholder:text-slate-700" placeholder="600..."/>
               </div>
               <button onClick={handlePhoneLogin} className="w-full bg-brand-600 hover:bg-brand-500 text-white font-bold py-4 rounded-xl shadow-lg shadow-brand-900/20 transition uppercase tracking-widest text-xs flex items-center justify-center gap-2">Continuar <ArrowRight size={16} /></button>
            </div>
            <div className="flex flex-col items-center gap-6">
               <button onClick={() => setCurrentStep(Step.RECOVERY)} className="text-slate-500 text-xs font-bold hover:text-brand-400 transition flex items-center gap-2"><KeyRound size={14} /> ¿Olvidaste tu PIN?</button>
               <button onClick={() => setShowInstallGuide(true)} className="text-[10px] uppercase font-bold tracking-wider text-brand-500/80 border-b border-brand-500/20 pb-0.5 hover:text-brand-400 transition">Descargar Aplicación</button>
            </div>
          </div>
        )}

        {currentStep === Step.RECOVERY && (
           <div className="flex flex-col gap-6 animate-fadeIn pt-10 text-center">
              <button onClick={() => {setCurrentStep(Step.LOGIN_PHONE); setError('');}} className="text-slate-400 hover:text-white self-start flex items-center gap-1 text-sm font-medium transition mb-4"><ChevronLeft size={16} /> Volver</button>
              <div className="bg-slate-900 p-8 rounded-3xl border border-slate-800 shadow-xl">
                 <div className="w-20 h-20 bg-brand-950/30 rounded-full flex items-center justify-center mx-auto mb-6 ring-1 ring-brand-900/50"><KeyRound size={32} className="text-brand-400" /></div>
                 <h3 className="text-2xl font-bold text-white mb-3">Recuperar Acceso</h3>
                 <p className="text-slate-400 text-sm mb-8 leading-relaxed">Por seguridad, contacta con la central para restablecer tu PIN.</p>
                 <div className="bg-slate-950 p-5 rounded-2xl border border-slate-800 mb-6"><p className="text-[10px] uppercase font-bold text-slate-600 tracking-widest mb-1">Teléfono Soporte</p><p className="text-white text-xl font-black tracking-wider">631 40 00 10</p></div>
                 <a href="tel:631400010" className="block w-full bg-slate-800 hover:bg-slate-700 text-white font-bold py-4 rounded-xl transition border border-slate-700">Llamar ahora</a>
              </div>
           </div>
        )}

        {currentStep === Step.REGISTER && (
          <div className="flex flex-col gap-6 animate-fadeIn">
            <button onClick={() => {setCurrentStep(Step.LOGIN_PHONE); setError('');}} className="text-slate-400 hover:text-white self-start flex items-center gap-1 text-sm font-medium transition"><ChevronLeft size={16} /> Cancelar</button>
            <div className="text-center"><h2 className="text-xl font-bold text-white mb-1">Nueva Ficha</h2><p className="text-slate-400 text-xs">Registro para {regPhone}</p></div>
