  const [adminError, setAdminError] = useState('');

  // Login Data
  const [loginPhone, setLoginPhone] = useState('');
  const [selectedWorker, setSelectedWorker] = useState<Worker | null>(null);

  // Operational Data
  const [selectedSite, setSelectedSite] = useState<Site | null>(null);
  const [selectedAction, setSelectedAction] = useState<LogType | null>(null);
  const [location, setLocation] = useState<GeoLocationData | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  // Exit Report
  const [exitReportText, setExitReportText] = useState('');
  const [exitWorkMode, setExitWorkMode] = useState<WorkMode>('HORAS');
  const [isListening, setIsListening] = useState(false);

  // Auth
  const [pinInput, setPinInput] = useState('');
  const [biometricsAvailable, setBiometricsAvailable] = useState(false);

  // Registration
  const [regName, setRegName] = useState('');
  const [regDni, setRegDni] = useState('');
  const [regPhone, setRegPhone] = useState('');
  const [regRole, setRegRole] = useState('');
  const [regPin, setRegPin] = useState('');
  const [regPinConfirm, setRegPinConfirm] = useState('');

  // History
  const [historyDate, setHistoryDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [workerLogs, setWorkerLogs] = useState<WorkLog[]>([]);

  // Data Cache
  const [workers, setWorkers] = useState<Worker[]>([]);
  const [sites, setSites] = useState<Site[]>([]);

  useEffect(() => {
    const timer = setTimeout(() => setIsAppLoading(false), 2000);

    setWorkers(StorageService.getWorkers());
    setSites(StorageService.getSites());
    setWorkerLogs(StorageService.getLogs()); 

    const unsubWorkers = StorageService.subscribeToWorkers((data) => setWorkers(data));
    const unsubSites = StorageService.subscribeToSites((data) => setSites(data));
    const unsubLogs = StorageService.subscribeToLogs((data) => setWorkerLogs(data));

    if (window.PublicKeyCredential) {
      window.PublicKeyCredential.isUserVerifyingPlatformAuthenticatorAvailable()
        .then(isAvailable => setBiometricsAvailable(isAvailable))
        .catch(err => console.error("Bio check failed", err));
    }

    return () => {
      clearTimeout(timer);
      unsubWorkers();
      unsubSites();
      unsubLogs();
    };
  }, []);

  // ... Handlers (Phone Login, Registration, etc.) remain same as previous correct version ...
  // (Omitting redundant function bodies for brevity, ensuring structure is maintained)

  const handleAdminAccessRequest = () => { setShowAdminLogin(true); setAdminPasswordInput(''); setAdminError(''); };
  const verifyAdminPassword = () => { const config = StorageService.getConfig(); if (adminPasswordInput === (config.adminPassword || 'admin')) { setIsAdmin(true); setShowAdminLogin(false); } else { setAdminError('Contraseña incorrecta'); } };

  const handlePhoneLogin = () => {
    if(!loginPhone || loginPhone.length < 6) { setError("Ingresa un teléfono válido"); return; }
    const worker = workers.find(w => w.phone && w.phone.replace(/\s/g, '') === loginPhone.replace(/\s/g, ''));
    if (worker) {
      if (!worker.active) { setError("Cuenta desactivada."); return; }
      setSelectedWorker(worker); setPinInput(''); setError(''); setCurrentStep(Step.AUTHENTICATE);
    } else {
      if(confirm("Número no encontrado. ¿Crear cuenta nueva?")) { setRegPhone(loginPhone); setError(''); setCurrentStep(Step.REGISTER); }
    }
  };

  const handleRegistration = async () => {
    if (!regName || !regDni || !regPin || !regPhone) { setError('Todos los campos son obligatorios.'); return; }
    const exists = workers.find(w => w.phone === regPhone);
    if (exists) { setError('Teléfono ya registrado.'); return; }
    if (regPin.length !== 4) { setError('PIN debe ser de 4 dígitos.'); return; }
    if (regPin !== regPinConfirm) { setError('Los PINs no coinciden.'); return; }

    setLoading(true); setError('');
    const newWorker: Worker = { id: `W${Math.floor(10000 + Math.random() * 90000)}`, name: regName, dni: regDni, phone: regPhone.trim(), role: regRole || 'Trabajador', pin: regPin, qrCode: `QR_${Date.now()}`, active: true, defaultMode: 'HORAS' };

    try {
      await StorageService.registerNewWorker(newWorker);
      setLoading(false); setSelectedWorker(newWorker); setPinInput(''); setCurrentStep(Step.AUTHENTICATE);
      setRegName(''); setRegDni(''); setRegPhone(''); setRegRole(''); setRegPin(''); setRegPinConfirm('');
    } catch (err: any) {
      setLoading(false); setError('Error de conexión.'); alert("No se pudo guardar en la base de datos.");
    }
  };

  const handlePinInput = (digit: string) => { if (pinInput.length < 4) { const newPin = pinInput + digit; setPinInput(newPin); if (newPin.length === 4) verifyAuth(newPin); } };
  const handlePinClear = () => { setPinInput(''); setError(''); };
  const verifyAuth = (pinToVerify: string) => { if (selectedWorker && selectedWorker.pin === pinToVerify) { setCurrentStep(Step.WORKER_DASHBOARD); setError(''); } else { setError('PIN Incorrecto'); setTimeout(() => setPinInput(''), 500); } };
  const handleBiometricAuth = async () => { try { setError(''); await navigator.credentials.create({ publicKey: { challenge: new Uint8Array([1,2,3]), rp: {name: "Carmagne"}, user: {id: new Uint8Array([1]), name: "user", displayName: "User"}, pubKeyCredParams: [{alg: -7, type: "public-key"}] } }); setCurrentStep(Step.WORKER_DASHBOARD); } catch (err) { setError('Error biométrico.'); } };

  const handleSiteSelect = (siteId: string) => { const site = sites.find(s => s.id === siteId); if (site) { setSelectedSite(site); setCurrentStep(Step.SELECT_ACTION); LocationService.getCurrentPosition().then(loc => setLocation(loc)).catch(console.warn); } };

  const handleActionSelect = async (type: LogType) => {
    setSelectedAction(type); setLoading(true); setError('');
    try { let loc = location; if (!loc) { loc = await LocationService.getCurrentPosition(); setLocation(loc); } } catch (err) {}
    setLoading(false);
    if (type === LogType.SALIDA) { setExitWorkMode(selectedWorker?.defaultMode || 'HORAS'); setExitReportText(''); setCurrentStep(Step.REPORT_EXIT); } 
    else { executeLogSubmission(type, undefined, 'HORAS'); }
  };

  const toggleVoiceRecognition = () => {
    if (isListening) { setIsListening(false); return; }
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) { alert("Navegador no compatible"); return; }
    const recognition = new SpeechRecognition(); recognition.lang = 'es-ES'; recognition.continuous = false;
    recognition.onresult = (event: any) => { setExitReportText(prev => (prev ? prev + '. ' + event.results[0][0].transcript : event.results[0][0].transcript)); setIsListening(false); };
    recognition.onend = () => setIsListening(false); setIsListening(true); recognition.start();
  };

  const executeLogSubmission = async (type: LogType, report?: string, mode?: WorkMode) => {
    setLoading(true);
    try {
      let loc = location; if (!loc) { loc = await LocationService.getCurrentPosition(); setLocation(loc); }
      let distance = 0; let warning = false;
      if (selectedSite && selectedSite.coordinates) { distance = LocationService.calculateDistance(loc!.latitude, loc!.longitude, selectedSite.coordinates.latitude, selectedSite.coordinates.longitude); if (distance > MAX_DISTANCE_METERS) warning = true; }
      await submitLog(loc!, type, distance, warning, undefined, report, mode);
    } catch (err: any) { setLoading(false); setError('Error GPS.'); }
  };

  const submitLog = async (loc: GeoLocationData, type: LogType, distance: number, warning: boolean, photoUrl?: string, report?: string, mode?: WorkMode) => {
    if (!selectedWorker || !selectedSite) return;
    setLoading(true);
    const newLog: WorkLog = { id: `LOG-${Date.now()}`, workerId: selectedWorker.id, workerName: selectedWorker.name, siteId: selectedSite.id, siteName: selectedSite.name, type: type, timestamp: Date.now(), dateStr: new Date().toLocaleDateString('es-ES'), timeStr: new Date().toLocaleTimeString('es-ES'), location: loc, photoUrl: photoUrl, sentToWhatsapp: false, syncedToSheets: false, distanceMeters: distance, locationWarning: warning, workReport: report, workMode: mode };
    try { await StorageService.addLog(newLog); StorageService.syncLog(newLog).then(s => { if(s) { newLog.syncedToSheets = true; StorageService.updateLog(newLog); }}); setCurrentStep(Step.SUCCESS); } catch (err: any) { alert("Error al guardar: " + err.message); } finally { setLoading(false); }
  };

  const resetApp = () => { setCurrentStep(Step.LOGIN_PHONE); setSelectedWorker(null); setSelectedSite(null); setSelectedAction(null); setLocation(null); setPinInput(''); setLoginPhone(''); setError(''); };

  // --- HELPERS ---
  const getDailyStats = (dateStr: string) => { if (!selectedWorker) return { totalMs: 0, logs: [] }; const targetDate = new Date(dateStr); const dayLogs = workerLogs.filter(l => l.workerId === selectedWorker.id && new Date(l.timestamp).toDateString() === targetDate.toDateString()).sort((a,b) => a.timestamp - b.timestamp); let totalPresence = 0; let totalBreaks = 0; let lastEntry = null; let lastBreak = null; dayLogs.forEach(log => { if (log.type === LogType.ENTRADA) lastEntry = log.timestamp; if (log.type === LogType.SALIDA && lastEntry) { totalPresence += (log.timestamp - lastEntry); lastEntry = null; } if (log.type === LogType.INICIO_DESCANSO) lastBreak = log.timestamp; if (log.type === LogType.FIN_DESCANSO && lastBreak) { totalBreaks += (log.timestamp - lastBreak); lastBreak = null; } }); return { totalMs: Math.max(0, totalPresence - totalBreaks), logs: dayLogs }; };
  const getCurrentStatus = () => { if (!selectedWorker) return null; const myLogs = workerLogs.filter(l => l.workerId === selectedWorker.id && l.type !== LogType.REGISTRO).sort((a,b) => b.timestamp - a.timestamp); if (myLogs.length === 0) return { status: 'FUERA', site: '-', since: null }; const lastLog = myLogs[0]; const isToday = new Date(lastLog.timestamp).toDateString() === new Date().toDateString(); if (lastLog.type === LogType.ENTRADA || lastLog.type === LogType.FIN_DESCANSO) return { status: 'TRABAJANDO', site: lastLog.siteName, since: lastLog.timestamp, isToday }; if (lastLog.type === LogType.INICIO_DESCANSO) return { status: 'EN DESCANSO', site: lastLog.siteName, since: lastLog.timestamp, isToday }; return { status: 'FUERA', site: '-', since: lastLog.timestamp, isToday }; };
  const msToTime = (ms: number) => { const hrs = Math.floor(ms / 3600000); const mins = Math.floor((ms % 3600000) / 60000); return `${hrs}h ${mins}m`; };

  // --- RENDERERS ---

  const renderWorkerDashboard = () => {
