        <div className={`relative overflow-hidden rounded-2xl p-6 shadow-xl border border-slate-700/50 ${status?.status === 'TRABAJANDO' ? 'bg-gradient-to-br from-slate-900 to-emerald-950/30' : status?.status === 'EN DESCANSO' ? 'bg-gradient-to-br from-slate-900 to-amber-950/30' : 'bg-gradient-to-br from-slate-900 to-slate-800'}`}>
          <div className="relative z-10 flex flex-col items-center text-center">
            <div className={`text-[10px] font-bold tracking-[0.2em] uppercase mb-2 ${status?.status === 'TRABAJANDO' ? 'text-emerald-400' : status?.status === 'EN DESCANSO' ? 'text-amber-400' : 'text-slate-500'}`}>Estado Actual</div>
            <h2 className="text-3xl font-black text-white mb-2 tracking-tight">{status?.status || 'SIN ACTIVIDAD'}</h2>
            {status?.status !== 'FUERA' && (<div className="mt-2 space-y-1"><p className="text-slate-300 font-medium">{status?.site}</p><div className="flex items-center justify-center gap-2 text-xs text-slate-400 bg-slate-950/50 px-3 py-1 rounded-full border border-slate-700"><Clock size={12}/><span>Desde: {new Date(status?.since || 0).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span></div></div>)}
          </div>
        </div>
        <h3 className="text-slate-400 text-sm font-bold uppercase tracking-wider px-2 mt-2">Acciones Rápidas</h3>
        <div className="grid grid-cols-1 gap-4 flex-1">
           <button onClick={() => setCurrentStep(Step.SELECT_SITE)} className="group bg-slate-800 hover:bg-slate-700 border border-slate-700 hover:border-brand-600/50 transition-all p-6 rounded-2xl shadow-lg flex items-center justify-between"><div className="text-left"><span className="block text-xl font-bold text-white group-hover:text-brand-500 transition-colors">Nuevo Fichaje</span><span className="text-slate-400 text-sm">Entrada, Salida o Pausa</span></div><div className="bg-slate-900 p-3 rounded-full text-brand-500 group-hover:scale-110 transition-transform duration-300 shadow-inner"><Clock size={24} /></div></button>
           <button onClick={() => setCurrentStep(Step.WORKER_HISTORY)} className="group bg-slate-800 hover:bg-slate-700 border border-slate-700 hover:border-purple-500/50 transition-all p-6 rounded-2xl shadow-lg flex items-center justify-between"><div className="text-left"><span className="block text-xl font-bold text-white group-hover:text-purple-400 transition-colors">Mi Historial</span><span className="text-slate-400 text-sm">Ver mis horas y actividad</span></div><div className="bg-slate-900 p-3 rounded-full text-purple-500 group-hover:scale-110 transition-transform duration-300 shadow-inner"><History size={24} /></div></button>
        </div>
      </div>
    );
  };

  const renderWorkerHistory = () => {
     const { totalMs, logs: dayLogs } = getDailyStats(historyDate);
     return (
        <div className="flex flex-col gap-4 animate-fadeIn h-full">
           <button onClick={() => setCurrentStep(Step.WORKER_DASHBOARD)} className="text-slate-400 hover:text-white flex items-center gap-1 text-sm font-medium"><ChevronLeft size={16}/> Volver</button>
           <h2 className="text-2xl font-bold text-white text-center">Mi Actividad</h2>
           <div className="bg-slate-800 p-4 rounded-xl flex items-center gap-4 border border-slate-700 shadow-md"><div className="bg-slate-900 p-2 rounded-lg text-brand-500"><Calendar size={20} /></div><div className="flex-1"><label className="text-[10px] text-slate-400 font-bold uppercase tracking-wider block mb-1">Fecha</label><input type="date" value={historyDate} onChange={(e) => setHistoryDate(e.target.value)} className="bg-transparent text-white font-bold text-lg w-full outline-none"/></div></div>
           <div className="bg-gradient-to-br from-slate-800 to-slate-900 p-6 rounded-xl border border-slate-700 text-center shadow-lg"><p className="text-slate-400 text-xs font-bold uppercase tracking-widest">Total Trabajado</p><div className="flex items-end justify-center gap-3 mt-2"><Clock size={28} className="text-brand-500 mb-1.5"/><span className="text-4xl font-black text-white tracking-tighter">{msToTime(totalMs)}</span></div></div>
           <div className="flex-1 overflow-y-auto custom-scrollbar mt-2 px-1">
              {dayLogs.length === 0 ? <div className="text-center text-slate-600 py-12 italic text-sm">No hay registros para este día.</div> : 
               <div className="relative border-l-2 border-slate-800 ml-4 space-y-6 pb-4">{dayLogs.map(log => (<div key={log.id} className="relative pl-6 group"><div className={`absolute -left-[9px] top-1 w-4 h-4 rounded-full border-2 ${log.type === LogType.ENTRADA ? 'bg-emerald-500 border-emerald-900' : log.type === LogType.SALIDA ? 'bg-rose-500 border-rose-900' : 'bg-amber-500 border-amber-900'}`}></div><div className="bg-slate-800/50 hover:bg-slate-800 p-4 rounded-xl border border-slate-700/50 transition-colors shadow-sm"><div className="flex justify-between items-start mb-2"><span className="text-[10px] font-bold px-2 py-1 rounded-md uppercase tracking-wider bg-slate-900/50 text-slate-300 border border-slate-700">{log.type}</span><span className="text-white font-mono font-bold text-sm">{log.timeStr}</span></div><p className="text-white font-semibold text-sm mb-2">{log.siteName}</p></div></div>))}</div>
