              <button onClick={() => handlePinInput('0')} className="h-20 rounded-3xl bg-slate-900 text-white text-2xl font-bold hover:bg-slate-800 active:bg-brand-600 border border-slate-800">0</button>
              <button onClick={handlePinClear} className="h-16 flex items-center justify-center text-rose-500 hover:text-rose-400"><Delete size={28} /></button>
