            <div className="text-center"><h2 className="text-xl font-bold text-white mb-1">Nueva Ficha</h2><p className="text-slate-400 text-xs">Registro para {regPhone}</p></div>
            <div className="flex flex-col gap-4 bg-slate-900 p-6 rounded-2xl border border-slate-800 shadow-xl">
               <input type="text" value={regName} onChange={(e) => setRegName(e.target.value)} className="w-full bg-slate-950 border border-slate-800 text-white rounded-lg p-3.5 focus:border-brand-500 outline-none" placeholder="Nombre Completo"/>
               <input type="text" value={regDni} onChange={(e) => setRegDni(e.target.value)} className="w-full bg-slate-950 border border-slate-800 text-white rounded-lg p-3.5 focus:border-brand-500 outline-none" placeholder="DNI"/>
               <input type="text" value={regRole} onChange={(e) => setRegRole(e.target.value)} className="w-full bg-slate-950 border border-slate-800 text-white rounded-lg p-3.5 focus:border-brand-500 outline-none" placeholder="Cargo"/>
               <div className="grid grid-cols-2 gap-4">
