                 <input type="password" value={regPinConfirm} onChange={(e) => setRegPinConfirm(e.target.value.slice(0,4))} className="w-full bg-slate-950 border border-slate-800 text-white rounded-lg p-3.5 text-center tracking-widest text-lg focus:border-brand-500 outline-none" placeholder="Repetir"/>
               </div>
            </div>
            <button onClick={handleRegistration} className="bg-emerald-600 hover:bg-emerald-500 text-white p-4 rounded-xl font-bold text-sm uppercase tracking-wide">{loading ? 'Guardando...' : 'Confirmar Registro'}</button>
          </div>
        )}

      </main>
      <footer className="p-6 text-center text-slate-600 text-[10px] font-bold tracking-widest uppercase opacity-50">&copy; 2024 CARMAGNE INSTAL</footer>
    </div>
  );
}

