## index.tsx

He actualizado este archivo para que busque el nuevo ID `main-app`. Esto es crucial: si no actualizas este archivo, la app se quedará en blanco.

```tsx
import React from 'react';
import { createRoot } from 'react-dom/client';
import App from './App';

// Buscamos el nuevo ID 'main-app' definido en el HTML actualizado
const container = document.getElementById('main-app');

if (container) {
  const root = createRoot(container);
  root.render(
    <React.StrictMode>
      <App />
    </React.StrictMode>
  );
} else {
  console.error("No se encontró el contenedor 'main-app'. Asegúrate de haber actualizado index.html");
}
```

## App.tsx

He simplificado el encabezado y asegurado que el estado inicial sea `LOGIN_PHONE`.

```tsx
import React, { useState, useEffect } from 'react';
import { 
  User, MapPin, CheckCircle, 
  LogOut, Coffee, ArrowRight, ShieldAlert, Lock, Fingerprint, Delete, UserPlus, Save, ChevronLeft, Calendar, History, Clock, Smartphone, X, Mic, MicOff, FileText, Cloud, Briefcase, Phone, KeyRound
} from 'lucide-react';
import { StorageService } from './services/storageService';
import { LocationService } from './services/locationService';
import { Worker, Site, WorkLog, LogType, GeoLocationData, WorkMode } from './types';
import { AdminPanel } from './components/AdminPanel';
import { InstallTutorial } from './components/InstallTutorial';

// App Steps
enum Step {
  LOGIN_PHONE = 0,
  AUTHENTICATE = 1,
  WORKER_DASHBOARD = 15,
  WORKER_HISTORY = 16,
  SELECT_SITE = 2,
  SELECT_ACTION = 3,
  REPORT_EXIT = 4, 
  SUCCESS = 5,
  REGISTER = 99,
  RECOVERY = 100
}

const MAX_DISTANCE_METERS = 500;

function App() {
  const [isAppLoading, setIsAppLoading] = useState(true);
  const [isAdmin, setIsAdmin] = useState(false);
  const [currentStep, setCurrentStep] = useState<Step>(Step.LOGIN_PHONE);
  const [showInstallGuide, setShowInstallGuide] = useState(false);
  const [showAdminLogin, setShowAdminLogin] = useState(false);
  const [adminPasswordInput, setAdminPasswordInput] = useState('');
  const [adminError, setAdminError] = useState('');

  // Data
  const [loginPhone, setLoginPhone] = useState('');
  const [selectedWorker, setSelectedWorker] = useState<Worker | null>(null);
  const [workers, setWorkers] = useState<Worker[]>([]);
  const [sites, setSites] = useState<Site[]>([]);
  const [workerLogs, setWorkerLogs] = useState<WorkLog[]>([]);

  // Op State
  const [selectedSite, setSelectedSite] = useState<Site | null>(null);
  const [selectedAction, setSelectedAction] = useState<LogType | null>(null);
  const [location, setLocation] = useState<GeoLocationData | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  // Exit
  const [exitReportText, setExitReportText] = useState('');
  const [exitWorkMode, setExitWorkMode] = useState<WorkMode>('HORAS');
  const [isListening, setIsListening] = useState(false);

  // Auth & Reg
  const [pinInput, setPinInput] = useState('');
  const [biometricsAvailable, setBiometricsAvailable] = useState(false);
  const [regName, setRegName] = useState('');
  const [regDni, setRegDni] = useState('');
  const [regPhone, setRegPhone] = useState('');
  const [regRole, setRegRole] = useState('');
  const [regPin, setRegPin] = useState('');
  const [regPinConfirm, setRegPinConfirm] = useState('');
  const [historyDate, setHistoryDate] = useState<string>(new Date().toISOString().split('T')[0]);

  useEffect(() => {
    const timer = setTimeout(() => setIsAppLoading(false), 2000);

    // Load & Subscribe
    setWorkers(StorageService.getWorkers());
    setSites(StorageService.getSites());
    setWorkerLogs(StorageService.getLogs()); 

    const unsubWorkers = StorageService.subscribeToWorkers((data) => setWorkers(data));
    const unsubSites = StorageService.subscribeToSites((data) => setSites(data));
    const unsubLogs = StorageService.subscribeToLogs((data) => setWorkerLogs(data));

    if (window.PublicKeyCredential) {
      window.PublicKeyCredential.isUserVerifyingPlatformAuthenticatorAvailable()
        .then(isAvailable => setBiometricsAvailable(isAvailable))
        .catch(err => console.error(err));
    }

    return () => {
      clearTimeout(timer);
      unsubWorkers();
      unsubSites();
      unsubLogs();
    };
  }, []);

  const handleAdminAccessRequest = () => { setShowAdminLogin(true); setAdminPasswordInput(''); setAdminError(''); };
  const verifyAdminPassword = () => { const config = StorageService.getConfig(); if (adminPasswordInput === (config.adminPassword || 'admin')) { setIsAdmin(true); setShowAdminLogin(false); } else { setAdminError('Contraseña incorrecta'); } };

  const handlePhoneLogin = () => {
    if(!loginPhone || loginPhone.length < 6) { setError("Teléfono inválido"); return; }
    const worker = workers.find(w => w.phone && w.phone.replace(/\s/g, '') === loginPhone.replace(/\s/g, ''));
    if (worker) {
      if (!worker.active) { setError("Cuenta desactivada"); return; }
      setSelectedWorker(worker); setPinInput(''); setError(''); setCurrentStep(Step.AUTHENTICATE);
    } else {
      if(confirm("Número no encontrado. ¿Crear cuenta nueva?")) { setRegPhone(loginPhone); setError(''); setCurrentStep(Step.REGISTER); }
    }
  };

  const handleRegistration = async () => {
    if (!regName || !regDni || !regPin || !regPhone) { setError('Campos incompletos'); return; }
    if (regPin.length !== 4 || regPin !== regPinConfirm) { setError('Error en PIN'); return; }
    setLoading(true); setError('');
    const newWorker: Worker = { id: `W${Math.floor(10000 + Math.random() * 90000)}`, name: regName, dni: regDni, phone: regPhone.trim(), role: regRole || 'Trabajador', pin: regPin, qrCode: `QR_${Date.now()}`, active: true, defaultMode: 'HORAS' };
    try { await StorageService.registerNewWorker(newWorker); setLoading(false); setSelectedWorker(newWorker); setPinInput(''); setCurrentStep(Step.AUTHENTICATE); setRegName(''); setRegDni(''); setRegPhone(''); setRegRole(''); setRegPin(''); setRegPinConfirm(''); } 
    catch (err: any) { setLoading(false); setError('Error de conexión'); alert("Error BD"); }
  };

  const handlePinInput = (digit: string) => { if (pinInput.length < 4) { const newPin = pinInput + digit; setPinInput(newPin); if (newPin.length === 4) verifyAuth(newPin); } };
  const handlePinClear = () => { setPinInput(''); setError(''); };
  const verifyAuth = (pinToVerify: string) => { if (selectedWorker && selectedWorker.pin === pinToVerify) { setCurrentStep(Step.WORKER_DASHBOARD); setError(''); } else { setError('PIN Incorrecto'); setTimeout(() => setPinInput(''), 500); } };
  const handleBiometricAuth = async () => { try { setError(''); await navigator.credentials.create({ publicKey: { challenge: new Uint8Array([1,2,3]), rp: {name: "Carmagne"}, user: {id: new Uint8Array([1]), name: "user", displayName: "User"}, pubKeyCredParams: [{alg: -7, type: "public-key"}] } }); setCurrentStep(Step.WORKER_DASHBOARD); } catch (err) { setError('Error biométrico'); } };

  const handleSiteSelect = (siteId: string) => { const site = sites.find(s => s.id === siteId); if (site) { setSelectedSite(site); setCurrentStep(Step.SELECT_ACTION); LocationService.getCurrentPosition().then(loc => setLocation(loc)).catch(console.warn); } };

  const handleActionSelect = async (type: LogType) => {
    setSelectedAction(type); setLoading(true); setError('');
    try { let loc = location; if (!loc) { loc = await LocationService.getCurrentPosition(); setLocation(loc); } } catch (err) {}
    setLoading(false);
    if (type === LogType.SALIDA) { setExitWorkMode(selectedWorker?.defaultMode || 'HORAS'); setExitReportText(''); setCurrentStep(Step.REPORT_EXIT); } 
    else { executeLogSubmission(type, undefined, 'HORAS'); }
  };

  const toggleVoiceRecognition = () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) { alert("Navegador no compatible"); return; }
    if (isListening) { setIsListening(false); return; }
    const recognition = new SpeechRecognition(); recognition.lang = 'es-ES'; recognition.continuous = false;
    recognition.onresult = (event: any) => { setExitReportText(prev => (prev ? prev + '. ' + event.results[0][0].transcript : event.results[0][0].transcript)); setIsListening(false); };
    recognition.onend = () => setIsListening(false); setIsListening(true); recognition.start();
  };

  const executeLogSubmission = async (type: LogType, report?: string, mode?: WorkMode) => {
    setLoading(true);
    try {
      let loc = location; if (!loc) { loc = await LocationService.getCurrentPosition(); setLocation(loc); }
      let distance = 0; let warning = false;
      if (selectedSite && selectedSite.coordinates) { distance = LocationService.calculateDistance(loc!.latitude, loc!.longitude, selectedSite.coordinates.latitude, selectedSite.coordinates.longitude); if (distance > MAX_DISTANCE_METERS) warning = true; }
      await submitLog(loc!, type, distance, warning, undefined, report, mode);
    } catch (err: any) { setLoading(false); setError('Error GPS'); }
  };

  const submitLog = async (loc: GeoLocationData, type: LogType, distance: number, warning: boolean, photoUrl?: string, report?: string, mode?: WorkMode) => {
    if (!selectedWorker || !selectedSite) return;
    setLoading(true);
    const newLog: WorkLog = { id: `LOG-${Date.now()}`, workerId: selectedWorker.id, workerName: selectedWorker.name, siteId: selectedSite.id, siteName: selectedSite.name, type: type, timestamp: Date.now(), dateStr: new Date().toLocaleDateString('es-ES'), timeStr: new Date().toLocaleTimeString('es-ES'), location: loc, photoUrl: photoUrl, sentToWhatsapp: false, syncedToSheets: false, distanceMeters: distance, locationWarning: warning, workReport: report, workMode: mode };
    try { await StorageService.addLog(newLog); StorageService.syncLog(newLog); setCurrentStep(Step.SUCCESS); } catch (err: any) { alert("Error: " + err.message); } finally { setLoading(false); }
  };

  const resetApp = () => { setCurrentStep(Step.LOGIN_PHONE); setSelectedWorker(null); setSelectedSite(null); setSelectedAction(null); setLocation(null); setPinInput(''); setLoginPhone(''); setError(''); };
  const getDailyStats = (dateStr: string) => { if (!selectedWorker) return { totalMs: 0, logs: [] }; const targetDate = new Date(dateStr); const dayLogs = workerLogs.filter(l => l.workerId === selectedWorker.id && new Date(l.timestamp).toDateString() === targetDate.toDateString()).sort((a,b) => a.timestamp - b.timestamp); let totalPresence = 0; let totalBreaks = 0; let lastEntry = null; let lastBreak = null; dayLogs.forEach(log => { if (log.type === LogType.ENTRADA) lastEntry = log.timestamp; if (log.type === LogType.SALIDA && lastEntry) { totalPresence += (log.timestamp - lastEntry); lastEntry = null; } if (log.type === LogType.INICIO_DESCANSO) lastBreak = log.timestamp; if (log.type === LogType.FIN_DESCANSO && lastBreak) { totalBreaks += (log.timestamp - lastBreak); lastBreak = null; } }); return { totalMs: Math.max(0, totalPresence - totalBreaks), logs: dayLogs }; };
  const getCurrentStatus = () => { if (!selectedWorker) return null; const myLogs = workerLogs.filter(l => l.workerId === selectedWorker.id && l.type !== LogType.REGISTRO).sort((a,b) => b.timestamp - a.timestamp); if (myLogs.length === 0) return { status: 'FUERA', site: '-', since: null }; const lastLog = myLogs[0]; const isToday = new Date(lastLog.timestamp).toDateString() === new Date().toDateString(); if (lastLog.type === LogType.ENTRADA || lastLog.type === LogType.FIN_DESCANSO) return { status: 'TRABAJANDO', site: lastLog.siteName, since: lastLog.timestamp, isToday }; if (lastLog.type === LogType.INICIO_DESCANSO) return { status: 'EN DESCANSO', site: lastLog.siteName, since: lastLog.timestamp, isToday }; return { status: 'FUERA', site: '-', since: lastLog.timestamp, isToday }; };
  const msToTime = (ms: number) => { const hrs = Math.floor(ms / 3600000); const mins = Math.floor((ms % 3600000) / 60000); return `${hrs}h ${mins}m`; };

  if (isAppLoading) {
    return (
      <div className="fixed inset-0 bg-slate-950 z-[100] flex flex-col items-center justify-center">
         <h1 className="text-5xl font-black text-white tracking-tighter mb-2">CARMAGNE</h1>
         <div className="h-1.5 w-24 bg-brand-600 rounded-full mb-4"></div>
         <p className="text-brand-500 font-bold tracking-[0.5em] text-xs uppercase">INSTAL 2024</p>
      </div>
    );
  }

  if (isAdmin) return <AdminPanel onBack={() => setIsAdmin(false)} />;

  return (
    <div className="min-h-screen bg-slate-950 flex flex-col font-sans text-slate-100 selection:bg-brand-500/30">
      {showInstallGuide && <InstallTutorial onClose={() => setShowInstallGuide(false)} />}
      {showAdminLogin && (
        <div className="fixed inset-0 z-50 bg-slate-950/90 flex items-center justify-center p-4">
           <div className="bg-slate-900 w-full max-w-sm rounded-2xl border border-slate-800 p-8 relative">
              <button onClick={() => setShowAdminLogin(false)} className="absolute top-4 right-4 text-slate-500"><X size={20} /></button>
              <h2 className="text-xl font-bold text-white text-center mb-6">ACCESO ADMIN</h2>
              <input type="password" value={adminPasswordInput} onChange={(e) => setAdminPasswordInput(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-xl p-4 text-center text-xl mb-6 focus:border-brand-500 outline-none text-white" placeholder="••••••" autoFocus/>
              {adminError && <div className="text-rose-500 text-xs text-center mb-4">{adminError}</div>}
              <button onClick={verifyAdminPassword} className="w-full bg-brand-600 text-white font-bold py-4 rounded-xl">ENTRAR</button>
           </div>
        </div>
      )}

      <header className="glass-panel p-4 flex justify-between items-center sticky top-0 z-20 border-b border-slate-800">
        <div><h1 className="text-xl font-black tracking-tight leading-none text-white">CARMAGNE</h1><p className="text-[10px] font-bold text-brand-500 tracking-[0.2em] uppercase mt-0.5">INSTAL 2024</p></div>
        <button onClick={handleAdminAccessRequest} className="p-2.5 bg-slate-800 text-slate-400 rounded-full border border-slate-700/50 hover:text-brand-400"><Lock size={16} /></button>
      </header>

      <main className="flex-1 flex flex-col p-4 max-w-md mx-auto w-full relative">
        {error && <div className="mb-6 p-4 bg-rose-950/80 border border-rose-900 text-rose-200 rounded-xl flex items-center gap-3"><ShieldAlert size={20} /><span className="text-xs font-bold">{error}</span></div>}

        {currentStep === Step.LOGIN_PHONE && (
          <div className="flex flex-col gap-8 animate-fadeIn pt-10">
            <div className="text-center">
              <div className="bg-slate-900/50 p-5 rounded-full inline-flex mb-4 border border-slate-800"><Smartphone size={32} className="text-brand-500" /></div>
              <h2 className="text-2xl font-bold text-white mb-2">Iniciar Sesión</h2>
              <p className="text-slate-400 text-sm">Introduce tu teléfono para acceder.</p>
            </div>
            <div className="bg-slate-900/80 p-6 rounded-3xl border border-slate-800 shadow-xl">
               <label className="block text-[10px] uppercase text-slate-500 font-bold mb-2 tracking-wider">Número de Teléfono</label>
               <div className="flex gap-3">
                 <div className="bg-slate-950 border border-slate-800 rounded-xl p-4 text-white flex items-center justify-center"><Phone size={20} className="text-slate-500"/></div>
                 <input type="tel" value={loginPhone} onChange={(e) => setLoginPhone(e.target.value)} className="w-full bg-slate-950 border border-slate-800 text-white rounded-xl p-4 text-lg focus:border-brand-500 focus:outline-none tracking-widest" placeholder="600..."/>
               </div>
               <button onClick={handlePhoneLogin} className="w-full bg-brand-600 hover:bg-brand-500 text-white font-bold py-4 rounded-xl shadow-lg mt-6 flex items-center justify-center gap-2">Continuar <ArrowRight size={16} /></button>
            </div>
            <button onClick={() => setShowInstallGuide(true)} className="mx-auto mt-8 text-[10px] bg-slate-900 text-brand-500 px-4 py-2 rounded-full border border-brand-900/30 flex items-center gap-2">Instalar App</button>
          </div>
        )}

        {/* Registration, Auth and Recovery steps follow same style ... */}
        {currentStep === Step.REGISTER && (
          <div className="flex flex-col gap-6 animate-fadeIn">
            <button onClick={() => {setCurrentStep(Step.LOGIN_PHONE); setError('');}} className="text-slate-400 flex gap-1 text-sm"><ChevronLeft size={16} /> Cancelar</button>
            <div className="text-center"><h2 className="text-xl font-bold text-white">Nueva Ficha</h2><p className="text-slate-400 text-xs">Registro para {regPhone}</p></div>
            <div className="flex flex-col gap-4 bg-slate-900 p-6 rounded-2xl border border-slate-800">
               <input type="text" value={regName} onChange={(e) => setRegName(e.target.value)} className="w-full bg-slate-950 border border-slate-800 text-white rounded-lg p-3.5 outline-none focus:border-brand-500" placeholder="Nombre Completo"/>
               <input type="text" value={regDni} onChange={(e) => setRegDni(e.target.value)} className="w-full bg-slate-950 border border-slate-800 text-white rounded-lg p-3.5 outline-none focus:border-brand-500" placeholder="DNI"/>
               <input type="tel" value={regPhone} readOnly className="w-full bg-slate-800 border border-slate-700 text-slate-400 rounded-lg p-3.5 outline-none"/>
               <input type="text" value={regRole} onChange={(e) => setRegRole(e.target.value)} className="w-full bg-slate-950 border border-slate-800 text-white rounded-lg p-3.5 outline-none focus:border-brand-500" placeholder="Cargo"/>
               <div className="grid grid-cols-2 gap-4">
                 <input type="password" value={regPin} onChange={(e) => setRegPin(e.target.value.slice(0,4))} className="w-full bg-slate-950 border border-slate-800 text-white rounded-lg p-3.5 text-center tracking-widest text-lg outline-none focus:border-brand-500" placeholder="PIN"/>
                 <input type="password" value={regPinConfirm} onChange={(e) => setRegPinConfirm(e.target.value.slice(0,4))} className="w-full bg-slate-950 border border-slate-800 text-white rounded-lg p-3.5 text-center tracking-widest text-lg outline-none focus:border-brand-500" placeholder="Repetir"/>
               </div>
            </div>
            <button onClick={handleRegistration} className="bg-emerald-600 hover:bg-emerald-500 text-white p-4 rounded-xl font-bold text-sm uppercase tracking-wide">{loading ? 'Guardando...' : 'Confirmar Registro'}</button>
          </div>
        )}

        {currentStep === Step.AUTHENTICATE && (
          <div className="flex flex-col gap-6 animate-fadeIn items-center justify-center flex-1 pt-10">
             <button onClick={resetApp} className="text-slate-400 text-sm absolute top-0">← Salir</button>
            <div className="text-center mb-8"><div className="w-24 h-24 bg-slate-900 rounded-full flex items-center justify-center mx-auto mb-6 border border-slate-800"><Lock size={32} className="text-brand-500" /></div><h2 className="text-2xl font-bold text-white mb-2">Hola, {selectedWorker?.name.split(' ')[0]}</h2><p className="text-slate-400 text-sm">Introduce tu PIN</p></div>
            <div className="flex gap-6 mb-10">{[0, 1, 2, 3].map(i => (<div key={i} className={`w-4 h-4 rounded-full transition-all ${i < pinInput.length ? 'bg-brand-500 scale-110' : 'bg-slate-800 border border-slate-700'}`}/>))}</div>
            <div className="grid grid-cols-3 gap-4 w-full max-w-[300px]">
              {[1, 2, 3, 4, 5, 6, 7, 8, 9].map(num => (<button key={num} onClick={() => handlePinInput(num.toString())} className="h-20 rounded-3xl bg-slate-900 text-white text-2xl font-bold hover:bg-slate-800 active:bg-brand-600 border border-slate-800">{num}</button>))}
              <div className="flex items-center justify-center">{biometricsAvailable && (<button onClick={handleBiometricAuth} className="h-16 w-16 rounded-full bg-slate-800 text-brand-400 flex items-center justify-center border border-slate-700"><Fingerprint size={28} /></button>)}</div>
              <button onClick={() => handlePinInput('0')} className="h-20 rounded-3xl bg-slate-900 text-white text-2xl font-bold hover:bg-slate-800 active:bg-brand-600 border border-slate-800">0</button>
              <button onClick={handlePinClear} className="h-16 flex items-center justify-center text-rose-500 hover:text-rose-400"><Delete size={28} /></button>
            </div>
            <button onClick={() => setCurrentStep(Step.RECOVERY)} className="mt-8 text-xs text-slate-500 hover:text-brand-400 flex items-center gap-1"><KeyRound size={14} /> ¿Olvidaste tu PIN?</button>
          </div>
        )}

        {currentStep === Step.RECOVERY && (
           <div className="flex flex-col gap-6 animate-fadeIn pt-10 text-center">
              <button onClick={() => {setCurrentStep(Step.LOGIN_PHONE); setError('');}} className="text-slate-400 text-sm flex gap-1 mb-4"><ChevronLeft size={16} /> Volver</button>
              <div className="bg-slate-900 p-8 rounded-2xl border border-slate-800">
                 <KeyRound size={48} className="text-brand-500 mx-auto mb-6" />
                 <h3 className="text-xl font-bold text-white mb-2">Recuperación</h3>
                 <p className="text-slate-400 text-sm mb-6">Contacta con la central para resetear tu PIN.</p>
                 <div className="bg-slate-950 p-4 rounded-xl border border-slate-800 mb-6"><p className="text-white text-lg font-bold">631 40 00 10</p></div>
                 <a href="tel:631400010" className="block w-full bg-slate-800 text-white font-bold py-3 rounded-xl">Llamar</a>
              </div>
           </div>
        )}

        {currentStep === Step.WORKER_DASHBOARD && renderWorkerDashboard()}
        {currentStep === Step.WORKER_HISTORY && renderWorkerHistory()}

        {currentStep === Step.SELECT_SITE && (
            <div className="flex flex-col gap-4">
                <button onClick={() => setCurrentStep(Step.WORKER_DASHBOARD)} className="text-slate-400 text-sm flex gap-1"><ChevronLeft size={16}/> Volver</button>
                <h2 className="text-2xl font-bold text-white text-center">Selecciona Obra</h2>
                <div className="grid gap-3">{sites.filter(s => s.active).map(site => (<button key={site.id} onClick={() => handleSiteSelect(site.id)} className="bg-slate-900 p-5 rounded-xl text-left border border-slate-800 hover:border-brand-500/50 transition"><h3 className="text-lg font-bold text-white">{site.name}</h3><p className="text-slate-400 text-xs">{site.address}</p></button>))}</div>
            </div>
        )}

        {currentStep === Step.SELECT_ACTION && (
            <div className="flex flex-col gap-4">
                <button onClick={() => setCurrentStep(Step.SELECT_SITE)} className="text-slate-400 text-sm">← Cambiar Obra</button>
                <div className="grid gap-4">
                    <button onClick={() => handleActionSelect(LogType.ENTRADA)} className="bg-emerald-600 p-6 rounded-2xl text-white font-bold flex justify-between items-center">ENTRADA <LogOut className="rotate-180"/></button>
                    <div className="grid grid-cols-2 gap-4">
                        <button onClick={() => handleActionSelect(LogType.INICIO_DESCANSO)} className="bg-amber-600 p-4 rounded-2xl text-white font-bold text-sm">INICIO<br/>DESCANSO</button>
                        <button onClick={() => handleActionSelect(LogType.FIN_DESCANSO)} className="bg-brand-600 p-4 rounded-2xl text-white font-bold text-sm">FIN<br/>DESCANSO</button>
