                <div className="flex-1 bg-slate-900 p-4 rounded-xl border border-slate-800"><div className="flex justify-between mb-2"><label className="text-[10px] font-bold text-slate-500 uppercase">Notas</label><button onClick={toggleVoiceRecognition} className={`text-[10px] font-bold uppercase px-2 py-1 rounded ${isListening ? 'bg-rose-500 text-white' : 'bg-slate-800 text-slate-400'}`}>{isListening ? 'Detener' : 'Dictar'}</button></div><textarea value={exitReportText} onChange={(e) => setExitReportText(e.target.value)} className="w-full bg-slate-950 text-white p-2 rounded border border-slate-800 h-32" placeholder="Escribe aquí..."/></div>
