                <CheckCircle size={64} className="text-emerald-500 mx-auto mb-4"/>
                <h2 className="text-2xl text-white font-bold">Registrado</h2>
                <button onClick={resetApp} className="mt-8 bg-brand-600 text-white px-8 py-3 rounded-xl font-bold">Inicio</button>
            </div>
        )}

      </main>
      <footer className="p-6 text-center text-slate-600 text-[10px] font-bold tracking-widest uppercase opacity-50">&copy; 2024 CARMAGNE INSTAL</footer>
    </div>
  );
}

