  syncWorker: async (worker: Worker) => StorageService.syncWorkerToSheets(worker),

  // --- LISTENERS ---
  subscribeToLogs: (callback: (logs: WorkLog[]) => void) => {
    const q = collection(db, "logs");
    return onSnapshot(q, (snapshot) => {
      // Use sanitize to ensure incoming data is clean
      const logs = snapshot.docs.map(doc => sanitizeForStorage(doc.data()) as WorkLog);
      logs.sort((a, b) => b.timestamp - a.timestamp);
      saveLocal(KEYS.LOGS, logs);
      callback(logs);
    }, (error) => console.error("Log sub error", error));
  },

  subscribeToWorkers: (callback: (workers: Worker[]) => void) => {
    return onSnapshot(collection(db, "workers"), (snapshot) => {
      const workers = snapshot.docs.map(doc => sanitizeForStorage(doc.data()) as Worker);
      saveLocal(KEYS.WORKERS, workers);
      callback(workers);
    }, (error) => console.error("Worker sub error", error));
  },

  subscribeToSites: (callback: (sites: Site[]) => void) => {
    return onSnapshot(collection(db, "sites"), (snapshot) => {
      const sites = snapshot.docs.map(doc => sanitizeForStorage(doc.data()) as Site);
      saveLocal(KEYS.SITES, sites);
      callback(sites);
    }, (error) => console.error("Site sub error", error));
  },

  exportToCSV: (logs: WorkLog[]): string => {
    const headers = ['ID', 'Trabajador', 'Obra', 'Tipo', 'Fecha', 'Hora', 'Modo', 'Reporte', 'Lat', 'Lon', 'Mapa'];
    const rows = logs.map(l => [
      l.id, l.workerName, l.siteName, l.type, l.dateStr, l.timeStr, l.workMode || '', 
      `"${(l.workReport || '').replace(/"/g, '""')}"`, 
      l.location.latitude, l.location.longitude,
      `https://maps.google.com/?q=${l.location.latitude},${l.location.longitude}`
    ]);
    return [headers.join(','), ...rows.map(r => r.join(','))].join('\n');
  }
};

