import { Worker, Site, WorkLog, AppConfig, LogType } from '../types';
import { db } from './firebase';
import { collection, doc, setDoc, updateDoc, query, orderBy, onSnapshot, deleteDoc } from 'firebase/firestore';

const KEYS = {
  WORKERS: 'carmagne_workers',
  SITES: 'carmagne_sites',
  LOGS: 'carmagne_logs',
  CONFIG: 'carmagne_config',
};

const GOOGLE_SCRIPT_URL = 'https://script.google.com/macros/s/AKfycbyUKGxgBNzmL6nn0q7GAQwF83gO3tkxVJMDChAmfYGmy0zMmC8ilr6HvcVrZemU0p_suQ/exec'; 

const INITIAL_CONFIG: AppConfig = {
  adminPhone: '34631400010', 
  googleSheetUrl: GOOGLE_SCRIPT_URL, 
  adminPassword: 'admin'
};

const loadLocal = <T>(key: string, initial: T): T => {
  try { const saved = localStorage.getItem(key); return saved ? JSON.parse(saved) : initial; } catch (e) { return initial; }
};
const saveLocal = <T>(key: string, data: T): void => {
  try { localStorage.setItem(key, JSON.stringify(data)); } catch (e) { console.error(e); }
};

export const StorageService = {
  getWorkers: (): Worker[] => loadLocal(KEYS.WORKERS, []),

  // --- REGISTRO BLINDADO ---
  registerNewWorker: async (worker: Worker) => {
    // 1. Intentar guardar en Firebase y esperar
    try {
      await setDoc(doc(db, "workers", worker.id), worker);

      // 2. Log de creación
      const regLog: WorkLog = {
        id: `REG-${worker.id}-${Date.now()}`,
        workerId: worker.id,
        workerName: worker.name,
        siteId: 'SYSTEM',
        siteName: 'Alta en App',
        type: LogType.REGISTRO,
        timestamp: Date.now(),
        dateStr: new Date().toLocaleDateString('es-ES'),
        timeStr: new Date().toLocaleTimeString('es-ES'),
        location: { latitude: 0, longitude: 0, accuracy: 0, address: 'Registro Móvil' },
        sentToWhatsapp: false,
        syncedToSheets: false,
        workMode: worker.defaultMode,
        workReport: `Alta nuevo usuario: ${worker.phone || 'Sin teléfono'}`
      };
      await setDoc(doc(db, "logs", regLog.id), regLog);

      // 3. Si no falla, guardar en local
      const currentWorkers = loadLocal<Worker[]>(KEYS.WORKERS, []);
      saveLocal(KEYS.WORKERS, [...currentWorkers, worker]);

    } catch (e: any) {
      console.error("Error Firebase:", e);
      throw new Error(e.message || "No se pudo conectar con el servidor.");
    }

    // 4. Enviar a Sheets (sin await para no bloquear UI si falla esto)
    StorageService.syncWorkerToSheets(worker);
  },

  saveWorkers: async (workers: Worker[]) => {
    saveLocal(KEYS.WORKERS, workers);
    try { await Promise.all(workers.map(w => setDoc(doc(db, "workers", w.id), w))); } catch (e) { console.error(e); }
  },

  deleteWorker: async (id: string) => {
    const workers = loadLocal<Worker[]>(KEYS.WORKERS, []);
    saveLocal(KEYS.WORKERS, workers.filter(w => w.id !== id));
    try { await deleteDoc(doc(db, "workers", id)); } catch (e) { console.error(e); }
  },

  getSites: (): Site[] => loadLocal(KEYS.SITES, []),
  saveSites: async (sites: Site[]) => {
    saveLocal(KEYS.SITES, sites);
    try { await Promise.all(sites.map(s => setDoc(doc(db, "sites", s.id), s))); } catch (e) { console.error(e); }
  },
  deleteSite: async (id: string) => {
    const sites = loadLocal<Site[]>(KEYS.SITES, []);
    saveLocal(KEYS.SITES, sites.filter(s => s.id !== id));
    try { await deleteDoc(doc(db, "sites", id)); } catch (e) { console.error(e); }
  },

  getLogs: (): WorkLog[] => loadLocal(KEYS.LOGS, []),
  addLog: async (log: WorkLog) => {
    const logs = loadLocal<WorkLog[]>(KEYS.LOGS, []);
    saveLocal(KEYS.LOGS, [log, ...logs]);
    try { await setDoc(doc(db, "logs", log.id), log); } catch (e: any) { 
       console.error(e); 
       throw new Error("Error de conexión al guardar.");
    }
  },
  updateLog: async (updatedLog: WorkLog) => {
    const logs = loadLocal<WorkLog[]>(KEYS.LOGS, []);
    saveLocal(KEYS.LOGS, logs.map(l => l.id === updatedLog.id ? updatedLog : l));
    try { await updateDoc(doc(db, "logs", updatedLog.id), { ...updatedLog }); } catch (e) { console.error(e); }
  },

  getConfig: (): AppConfig => loadLocal(KEYS.CONFIG, INITIAL_CONFIG),
  saveConfig: (config: AppConfig) => saveLocal(KEYS.CONFIG, config),

  syncLog: async (log: WorkLog): Promise<boolean> => {
    const config = loadLocal<AppConfig>(KEYS.CONFIG, INITIAL_CONFIG);
    const url = config.googleSheetUrl || GOOGLE_SCRIPT_URL;
    if (!url || url.length < 10) return false;
    try {
      await fetch(url, { method: 'POST', mode: 'no-cors', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ action: 'LOG', ...log }) });
      return true;
    } catch (error) { return false; }
  },

  syncWorkerToSheets: async (worker: Worker): Promise<boolean> => {
    const config = loadLocal<AppConfig>(KEYS.CONFIG, INITIAL_CONFIG);
    const url = config.googleSheetUrl || GOOGLE_SCRIPT_URL;
    if (!url || url.length < 10) return false;
    try {
      await fetch(url, { method: 'POST', mode: 'no-cors', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ action: 'REGISTER', worker: worker }) });
      return true;
    } catch (error) { return false; }
  },

  syncWorker: async (worker: Worker) => StorageService.syncWorkerToSheets(worker),

  subscribeToLogs: (callback: (logs: WorkLog[]) => void) => {
    const q = collection(db, "logs");
    return onSnapshot(q, (snapshot) => {
      const logs = snapshot.docs.map(doc => doc.data() as WorkLog);
      logs.sort((a, b) => b.timestamp - a.timestamp);
      saveLocal(KEYS.LOGS, logs);
      callback(logs);
    }, (e) => console.error("Log Sub Error", e));
  },

  subscribeToWorkers: (callback: (workers: Worker[]) => void) => {
    return onSnapshot(collection(db, "workers"), (snapshot) => {
      const workers = snapshot.docs.map(doc => doc.data() as Worker);
      saveLocal(KEYS.WORKERS, workers);
      callback(workers);
    }, (e) => console.error("Worker Sub Error", e));
  },

  subscribeToSites: (callback: (sites: Site[]) => void) => {
    return onSnapshot(collection(db, "sites"), (snapshot) => {
      const sites = snapshot.docs.map(doc => doc.data() as Site);
      saveLocal(KEYS.SITES, sites);
      callback(sites);
    }, (e) => console.error("Site Sub Error", e));
  },

  exportToCSV: (logs: WorkLog[]): string => {
    const headers = ['ID', 'Trabajador', 'Obra', 'Tipo', 'Fecha', 'Hora', 'Modo', 'Reporte', 'Lat', 'Lon', 'Mapa'];
    const rows = logs.map(l => [
      l.id, l.workerName, l.siteName, l.type, l.dateStr, l.timeStr, l.workMode || '', 
      `"${(l.workReport || '').replace(/"/g, '""')}"`, 
      l.location.latitude, l.location.longitude,
      `https://maps.google.com/?q=${l.location.latitude},${l.location.longitude}`
    ]);
    return [headers.join(','), ...rows.map(r => r.join(','))].join('\n');
  }
};

