const generateWorkerReport = (
  workerId: string,
  logs: LogEntry[],
  doc: jsPDF,
  startX: number,
  startY: number
) => {
  const filteredLogs = logs.filter(log => log.workerId === workerId);
  const totalHours = calculateTotalHours(filteredLogs);
  const totalBreakTime = calculateTotalBreakTime(filteredLogs);
  const netWorkingTime = totalHours - totalBreakTime;

  doc.setFontSize(14);
  doc.text(`Reporte de ${workerId}`, startX, startY);
  startY += 10;

  const tableHeader = ['Fecha', 'Hora', 'Tipo', 'Comentario'];
  const columnWidths = [40, 30, 30, 70]; // Adjusted widths for better fit
  const rowHeight = 10;

  // Draw Header
  doc.setFillColor(200, 200, 200); // Light gray fill
  doc.rect(startX, startY, columnWidths.reduce((a, b) => a + b, 0), rowHeight, 'F');
  doc.setFontSize(10);
  doc.setTextColor(0);
  tableHeader.forEach((header, index) => {
    doc.text(header, startX + 2 + columnWidths.slice(0, index).reduce((a, b) => a + b, 0), startY + 7);
  });
  startY += rowHeight;

  // Draw Rows
  doc.setFontSize(8);
  filteredLogs.forEach((log, index) => {
    // Alternate row colors for better readability
    if (index % 2 === 0) {
      doc.setFillColor(240, 240, 240); // Lighter gray for even rows
      doc.rect(startX, startY, columnWidths.reduce((a, b) => a + b, 0), rowHeight, 'F');
    }
    doc.setTextColor(0);
    doc.text(formatDate(log.timestamp), startX + 2, startY + 5);
    doc.text(formatTime(log.timestamp), startX + columnWidths[0] + 2, startY + 5);
    doc.text(log.type, startX + columnWidths[0] + columnWidths[1] + 2, startY + 5);
    doc.text(log.comment || '', startX + columnWidths[0] + columnWidths[1] + columnWidths[2] + 2, startY + 5);
    startY += rowHeight;
  });

  // Draw Summary
  const summaryY = startY + 10; // Extra space
  doc.setFontSize(12);
  doc.text(`Horas Totales: ${totalHours.toFixed(2)}`, startX, summaryY);
  doc.text(`Tiempo de Descanso: ${totalBreakTime.toFixed(2)}`, startX, summaryY + 10);
  doc.text(`Tiempo Neto Trabajado: ${netWorkingTime.toFixed(2)}`, startX, summaryY + 20);

  return startY; // Return the end Y position for next report
};
