  try {
    const saved = localStorage.getItem(key);
    return saved ? JSON.parse(saved) : initial;
  } catch (e) {
    return initial;
  }
};

const saveLocal = <T>(key: string, data: T): void => {
  try {
    // Safe stringify to avoid circular error in local storage too
    const cache = new Set();
    const safeData = JSON.stringify(data, (key, value) => {
      if (typeof value === 'object' && value !== null) {
        if (cache.has(value)) return;
        cache.add(value);
      }
      return value;
    });
    localStorage.setItem(key, safeData);
  } catch (e) {
    console.error("Error saving local", e);
  }
};

// --- SANITIZATION & VALIDATION ---

// Basic HTML entity encoding to prevent XSS
const sanitizeInput = (input: string): string => {
  if (!input) return '';
  return input.replace(/[&<>"']/g, (match) => {
    const escape:Record<string, string> = {
      '&': '&amp;',
      '<': '&lt;',
      '>': '&gt;',
      '"': '&quot;',
      "'": '&#39;'
    };
    return escape[match];
  }).trim();
};

const validateWorkerData = (worker: Worker): Worker => {
  if (!worker.name || worker.name.length < 2) throw new Error("Nombre inválido");
  if (!worker.pin || !/^\d{4}$/.test(worker.pin)) throw new Error("PIN inválido (debe ser 4 dígitos)");

  return {
    ...worker,
    name: sanitizeInput(worker.name),
    dni: sanitizeInput(worker.dni || ''),
    role: sanitizeInput(worker.role || ''),
    phone: sanitizeInput(worker.phone || '')
  };
};

const validateSiteData = (site: Site): Site => {
  if (!site.name || site.name.length < 2) throw new Error("Nombre de obra inválido");
  return {
    ...site,
    name: sanitizeInput(site.name),
    address: sanitizeInput(site.address)
  };
};

// Robust sanitize function to remove undefineds and circular references for Firebase
const sanitizeForFirebase = (obj: any) => {
  const seen = new WeakSet();
  const clone = (o: any): any => {
    if (o === null || typeof o !== 'object') return o;

    // Handle Date objects
    if (o instanceof Date) return o.toISOString();

    // Handle circular references
    if (seen.has(o)) return undefined;
    seen.add(o);

    if (Array.isArray(o)) {
      return o.map(clone).filter(v => v !== undefined);
    }

    const newObj: any = {};
    for (const k in o) {
      if (Object.prototype.hasOwnProperty.call(o, k)) {
        const v = clone(o[k]);
        if (v !== undefined) {
          newObj[k] = v;
        }
      }
    }
    return newObj;
  };
  return clone(obj);
};

