    try { await StorageService.registerNewWorker(newWorker); setLoading(false); setSelectedWorker(newWorker); setPinInput(''); setCurrentStep(Step.AUTHENTICATE); setRegName(''); setRegDni(''); setRegPhone(''); setRegRole(''); setRegPin(''); setRegPinConfirm(''); } catch (err: any) { setLoading(false); setError('Error de conexión'); alert("Error BD"); }
  };

  const handlePinInput = (digit: string) => { if (pinInput.length < 4) { const newPin = pinInput + digit; setPinInput(newPin); if (newPin.length === 4) verifyAuth(newPin); } };
  const handlePinClear = () => { setPinInput(''); setError(''); };
