// --- FIXED SAFE SAVE ---
const saveLocal = <T>(key: string, data: T): void => {
  try {
    // Intentar guardar. Si hay error circular, lo capturamos.
    localStorage.setItem(key, JSON.stringify(data));
  } catch (e) {
    console.warn(`Error guardando ${key} en local (posible circular ref):`, e);
  }
