    saveLocal(KEYS.WORKERS, workers.filter(w => w.id !== id));
    try { await deleteDoc(doc(db, "workers", id)); } catch (e) { console.error(e); }
  },

  // --- SITES ---
  getSites: (): Site[] => loadLocal(KEYS.SITES, INITIAL_SITES),

  saveSites: async (sites: Site[]) => {
    const safeList = sites.map(cleanSite);
    saveLocal(KEYS.SITES, safeList);
    try { 
      await Promise.all(safeList.map(s => setDoc(doc(db, "sites", s.id), s))); 
    } catch (e) { console.error(e); }
  },

  deleteSite: async (id: string) => {
