  getLogs: (): WorkLog[] => loadLocal(KEYS.LOGS, []),

  addLog: async (log: WorkLog) => {
    const safeLog = cleanLog(log);

    // 1. Save Local
    const logs = loadLocal<WorkLog[]>(KEYS.LOGS, []);
    saveLocal(KEYS.LOGS, [safeLog, ...logs]);

    // 2. Save to Firebase
    try {
      // Remove undefined fields completely for Firebase setDoc
      const firestorePayload = JSON.parse(JSON.stringify(safeLog));
      await setDoc(doc(db, "logs", safeLog.id), firestorePayload);
    } catch (e: any) {
      console.error("Firebase Add Error:", e);
      throw new Error("Error de conexión con la base de datos.");
