  const getDailyStats = (dateStr: string) => { if (!selectedWorker) return { totalMs: 0, logs: [] }; const targetDate = new Date(dateStr); const dayLogs = workerLogs.filter(l => l.workerId === selectedWorker.id && new Date(l.timestamp).toDateString() === targetDate.toDateString()).sort((a,b) => a.timestamp - b.timestamp); let totalPresence = 0; let totalBreaks = 0; let lastEntry = null; let lastBreak = null; dayLogs.forEach(log => { if (log.type === LogType.ENTRADA) lastEntry = log.timestamp; if (log.type === LogType.SALIDA && lastEntry) { totalPresence += (log.timestamp - lastEntry); lastEntry = null; } if (log.type === LogType.INICIO_DESCANSO) lastBreak = log.timestamp; if (log.type === LogType.FIN_DESCANSO && lastBreak) { totalBreaks += (log.timestamp - lastBreak); lastBreak = null; } }); return { totalMs: Math.max(0, totalPresence - totalBreaks), logs: dayLogs }; };
  const getCurrentStatus = () => { if (!selectedWorker) return null; const myLogs = workerLogs.filter(l => l.workerId === selectedWorker.id && l.type !== LogType.REGISTRO).sort((a,b) => b.timestamp - a.timestamp); if (myLogs.length === 0) return { status: 'FUERA', site: '-', since: null }; const lastLog = myLogs[0]; const isToday = new Date(lastLog.timestamp).toDateString() === new Date().toDateString(); if (lastLog.type === LogType.ENTRADA || lastLog.type === LogType.FIN_DESCANSO) return { status: 'TRABAJANDO', site: lastLog.siteName, since: lastLog.timestamp, isToday }; if (lastLog.type === LogType.INICIO_DESCANSO) return { status: 'EN DESCANSO', site: lastLog.siteName, since: lastLog.timestamp, isToday }; return { status: 'FUERA', site: '-', since: lastLog.timestamp, isToday }; };
