    const a = document.createElement('a');
    a.href = url;
    a.download = `Fichajes_CARMAGNE_${new Date().toISOString().split('T')[0]}.csv`;
    a.click();
  };

  const getFilteredLogs = () => {
    return logs.filter(log => {
      const matchWorker = filterWorker === 'ALL' || log.workerId === filterWorker;
      let matchDate = true;
      if (filterDate) {
         const [y, m, d] = filterDate.split('-');
         const dateToCompare = `${d}/${m}/${y}`;
         matchDate = log.dateStr === dateToCompare;
      }
      const matchType = filterType === 'ALL' || (filterType === 'DESCANSO' ? (log.type === LogType.INICIO_DESCANSO || log.type === LogType.FIN_DESCANSO) : log.type === filterType);
      return matchWorker && matchDate && matchType;
    });
  };

  const handleAddWorker = () => {
      if (!newWorkerName || !newWorkerPin) { alert("Nombre y PIN obligatorios"); return; }
      const newWorker: Worker = { id: `W${Math.floor(Math.random()*10000)}`, name: newWorkerName, qrCode: `QR_${Date.now()}`, active: true, pin: newWorkerPin, role: 'Trabajador', defaultMode: newWorkerMode };
      StorageService.registerNewWorker(newWorker); setNewWorkerName(''); setNewWorkerPin('');
  };
  const initiateDeleteWorker = (w: Worker) => setDeleteTarget({ type: 'worker', id: w.id, name: w.name });
  const initiateDeleteSite = (s: Site) => setDeleteTarget({ type: 'site', id: s.id, name: s.name });
  const confirmDelete = () => { if (!deleteTarget) return; if (deleteTarget.type === 'worker') StorageService.deleteWorker(deleteTarget.id); else if (deleteTarget.type === 'site') StorageService.deleteSite(deleteTarget.id); setDeleteTarget(null); };
  const handleAddSite = () => { if (!newSiteName) return; const newSite: Site = { id: `S${Math.floor(Math.random()*10000)}`, name: newSiteName, address: newSiteAddress, active: true }; StorageService.saveSites([...sites, newSite]); setNewSiteName(''); setNewSiteAddress(''); };

  // --- GUARDAR CONFIGURACIÓN ---
  const saveConfig = () => { 
    const updatedConfig = { ...config }; 
    if (newAdminPassword && newAdminPassword.trim().length > 0) {
      updatedConfig.adminPassword = newAdminPassword;
    }
    StorageService.saveConfig(updatedConfig); 
    setConfig(updatedConfig); 
    setNewAdminPassword(''); 
    alert('Configuración guardada correctamente.'); 
  };

  const generateMonthlyReport = (): WorkerMonthlyReport[] => {
      const [year, month] = reportMonth.split('-').map(Number);
      const monthlyLogs = logs.filter(log => { const d = new Date(log.timestamp); return d.getFullYear() === year && (d.getMonth() + 1) === month; });
      monthlyLogs.sort((a, b) => a.timestamp - b.timestamp);
      const reports: WorkerMonthlyReport[] = [];
      workers.forEach(worker => {
        const workerLogs = monthlyLogs.filter(l => l.workerId === worker.id);
        let totalPresence = 0; let totalBreaks = 0; let lastEntryTime: number | null = null; let lastBreakStartTime: number | null = null; let daysSet = new Set<string>();
        for (const log of workerLogs) {
          if (log.type === LogType.REGISTRO) continue;
          daysSet.add(log.dateStr);
          if (log.type === LogType.ENTRADA) if (lastEntryTime === null) lastEntryTime = log.timestamp;
          if (log.type === LogType.SALIDA) if (lastEntryTime !== null) { totalPresence += (log.timestamp - lastEntryTime); lastEntryTime = null; if (lastBreakStartTime !== null) { totalBreaks += (log.timestamp - lastBreakStartTime); lastBreakStartTime = null; } }
          if (log.type === LogType.INICIO_DESCANSO) if (lastBreakStartTime === null) lastBreakStartTime = log.timestamp;
          if (log.type === LogType.FIN_DESCANSO) if (lastBreakStartTime !== null) { totalBreaks += (log.timestamp - lastBreakStartTime); lastBreakStartTime = null; }
        }
        if (workerLogs.length > 0) reports.push({ workerId: worker.id, workerName: worker.name, totalPresenceMs: totalPresence, totalBreakMs: totalBreaks, netWorkMs: Math.max(0, totalPresence - totalBreaks), daysWorked: daysSet.size });
      });
      return reports;
  };

  const handleDownloadPDF = (summary: WorkerMonthlyReport) => {
      const doc = new jsPDF(); const [year, month] = reportMonth.split('-').map(Number);
      const workerLogs = logs.filter(log => { const d = new Date(log.timestamp); return log.workerId === summary.workerId && d.getFullYear() === year && (d.getMonth() + 1) === month; }).sort((a, b) => a.timestamp - b.timestamp);
      doc.setFillColor(15, 23, 42); doc.rect(0, 0, 210, 40, 'F');
      doc.setTextColor(255, 255, 255); doc.setFontSize(18); doc.text("CARMAGNE INSTAL", 105, 20, { align: 'center' });
      doc.setTextColor(0, 0, 0); doc.setFontSize(12); doc.text(`Trabajador: ${summary.workerName}`, 14, 50);
      const tableData = workerLogs.map(log => [log.dateStr, log.timeStr, log.type, log.siteName, log.workMode || '', log.workReport || '']);
      autoTable(doc, { startY: 60, head: [['Fecha', 'Hora', 'Acción', 'Obra', 'Modo', 'Reporte']], body: tableData });
      doc.save(`Reporte_${summary.workerName}.pdf`);
  };
  const msToTime = (d: number) => `${Math.floor(d/3600000)}h ${Math.floor((d%3600000)/60000)}m`;
  const logsByType = [{ name: 'Entrada', value: logs.filter(l => l.type === LogType.ENTRADA).length }, { name: 'Salida', value: logs.filter(l => l.type === LogType.SALIDA).length }, { name: 'Registros', value: logs.filter(l => l.type === LogType.REGISTRO).length }];
  const COLORS = ['#3b82f6', '#10b981', '#94a3b8'];

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 pb-20 font-sans selection:bg-blue-500/30">
      <ConfirmationModal isOpen={deleteTarget !== null} title="Eliminar" message="¿Seguro? Esta acción es irreversible." isDestructive={true} onCancel={() => setDeleteTarget(null)} onConfirm={confirmDelete} />

      <header className="bg-slate-900 p-4 sticky top-0 z-10 shadow-md flex justify-between items-center border-b border-slate-800">
        <div><h1 className="text-xl font-black tracking-tight text-white">CARMAGNE ADMIN</h1></div><button onClick={onBack} className="text-xs bg-slate-800 text-slate-300 border border-slate-700 px-4 py-2 rounded hover:bg-slate-700 hover:text-white transition">Volver App</button>
      </header>

      <div className="flex overflow-x-auto bg-slate-900 border-b border-slate-800">
        {[{ id: 'dashboard', label: 'Dashboard', icon: FileText }, { id: 'logs', label: 'Registros', icon: Database }, { id: 'reports', label: 'Informes', icon: ClipboardList }, { id: 'workers', label: 'Personal', icon: Users }, { id: 'sites', label: 'Obras', icon: MapPin }, { id: 'config', label: 'Config', icon: Settings }].map(tab => (
          <button key={tab.id} onClick={() => setActiveTab(tab.id as any)} className={`flex-1 min-w-[100px] py-4 flex flex-col items-center gap-1 text-sm font-medium transition-colors ${activeTab === tab.id ? 'text-blue-500 border-b-2 border-blue-500 bg-slate-800' : 'text-slate-500 hover:text-slate-300'}`}>
            <tab.icon size={20} />{tab.label}
          </button>
        ))}
      </div>

      <div className="p-6 max-w-7xl mx-auto">

        {/* DASHBOARD */}
        {activeTab === 'dashboard' && (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
             <div className="bg-slate-900 p-6 rounded-xl border border-slate-800"><h3>Total Registros</h3><p className="text-4xl font-black text-white mt-2">{logs.length}</p></div>
             <div className="bg-slate-900 p-6 rounded-xl border border-slate-800"><h3>Obras Activas</h3><p className="text-4xl font-black text-blue-500 mt-2">{sites.filter(s => s.active).length}</p></div>
             <div className="bg-slate-900 p-6 rounded-xl border border-slate-800"><h3>Trabajadores</h3><p className="text-4xl font-black text-emerald-500 mt-2">{workers.filter(w => w.active).length}</p></div>
             <div className="bg-slate-900 p-6 rounded-xl border border-slate-800 col-span-1 md:col-span-2 h-80">
                <h3 className="font-bold mb-6 text-slate-300">Actividad</h3>
                <ResponsiveContainer width="100%" height="100%"><PieChart><Pie data={logsByType} cx="50%" cy="50%" outerRadius={80} fill="#8884d8" dataKey="value" label>{logsByType.map((entry, index) => <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />)}</Pie><RechartsTooltip /></PieChart></ResponsiveContainer>
             </div>
             <div className="bg-slate-900 p-6 rounded-xl border border-slate-800">
               <h3 className="font-bold mb-4 text-slate-300">Acciones</h3>
               <button onClick={handleExport} className="w-full bg-emerald-600 text-white p-4 rounded-xl font-bold mb-4 flex items-center justify-center gap-2 hover:bg-emerald-500 transition"><Download/> Exportar CSV</button>
             </div>
          </div>
        )}

        {/* LOGS TAB */}
        {activeTab === 'logs' && (
          <div className="space-y-6">
            <div className="bg-slate-900 p-6 rounded-xl border border-slate-800 flex flex-col lg:flex-row gap-6 items-end shadow-lg">
               <div className="flex-1 w-full">
                 <label className="block text-xs font-bold text-slate-500 uppercase mb-2 tracking-wider flex items-center gap-2"><Users size={14} /> Trabajador</label>
                 <div className="relative"><select className="w-full bg-slate-950 border border-slate-700 text-white p-3 rounded-lg appearance-none focus:border-blue-500 outline-none cursor-pointer hover:border-slate-600 transition" value={filterWorker} onChange={(e) => setFilterWorker(e.target.value)}><option value="ALL">Todos los trabajadores</option>{workers.map(w => <option key={w.id} value={w.id}>{w.name}</option>)}</select><div className="absolute inset-y-0 right-0 flex items-center px-3 pointer-events-none text-slate-500">▼</div></div>
               </div>
               <div className="flex-1 w-full">
                 <label className="block text-xs font-bold text-slate-500 uppercase mb-2 tracking-wider flex items-center gap-2"><Calendar size={14} /> Fecha</label>
                 <div className="flex gap-2"><input type="date" className="w-full bg-slate-950 border border-slate-700 text-white p-3 rounded-lg focus:border-blue-500 outline-none cursor-pointer hover:border-slate-600 transition" value={filterDate} onChange={(e) => setFilterDate(e.target.value)}/>{filterDate && (<button onClick={() => setFilterDate('')} className="bg-slate-800 text-slate-400 p-3 rounded-lg hover:bg-slate-700 hover:text-white transition border border-slate-700" title="Limpiar fecha"><X size={20} /></button>)}</div>
               </div>
               <div className="flex-1 w-full">
                  <label className="block text-xs font-bold text-slate-500 uppercase mb-2 tracking-wider flex items-center gap-2"><Filter size={14} /> Tipo</label>
                  <div className="relative"><select className="w-full bg-slate-950 border border-slate-700 text-white p-3 rounded-lg appearance-none focus:border-blue-500 outline-none cursor-pointer hover:border-slate-600 transition" value={filterType} onChange={(e) => setFilterType(e.target.value)}><option value="ALL">Todas las acciones</option><option value={LogType.ENTRADA}>Entrada</option><option value={LogType.SALIDA}>Salida</option><option value="DESCANSO">Descansos</option><option value={LogType.REGISTRO}>Registros</option></select><div className="absolute inset-y-0 right-0 flex items-center px-3 pointer-events-none text-slate-500">▼</div></div>
               </div>
               <div className="pb-3 lg:pb-0 min-w-[100px] text-right"><span className="text-xs font-bold text-slate-500 uppercase tracking-wider block mb-1">Resultados</span><span className="text-3xl font-black text-white">{getFilteredLogs().length}</span></div>
            </div>
            <div className="bg-slate-900 rounded-xl overflow-hidden border border-slate-800 shadow-xl">
              <div className="overflow-x-auto">
                <table className="w-full text-sm text-left text-slate-300">
                  <thead className="bg-slate-950 text-slate-500 uppercase font-bold text-xs border-b border-slate-800"><tr><th className="p-4">Fecha/Hora</th><th className="p-4">Trabajador</th><th className="p-4">Obra/Evento</th><th className="p-4">Acción</th><th className="p-4">Info</th><th className="p-4">Ubicación</th></tr></thead>
                  <tbody className="divide-y divide-slate-800">
                    {getFilteredLogs().map(log => (
                      <tr key={log.id} className={`hover:bg-slate-800/50 transition-colors ${log.locationWarning ? 'bg-rose-950/10' : ''}`}>
                        <td className="p-4"><div className="font-bold text-white">{log.dateStr}</div><div className="text-xs text-slate-500 font-mono">{log.timeStr}</div></td>
                        <td className="p-4 font-medium text-white">{log.workerName}</td>
                        <td className="p-4 text-slate-400">{log.siteName}</td>
                        <td className="p-4"><span className={`px-2 py-1 rounded text-[10px] uppercase font-bold tracking-wide border ${log.type === LogType.ENTRADA ? 'bg-emerald-950/30 text-emerald-400 border-emerald-900/50' : log.type === LogType.SALIDA ? 'bg-rose-950/30 text-rose-400 border-rose-900/50' : log.type === LogType.REGISTRO ? 'bg-blue-950/30 text-blue-400 border-blue-900/50' : 'bg-amber-950/30 text-amber-400 border-amber-900/50'}`}>{log.type}</span></td>
                        <td className="p-4 max-w-xs text-xs text-slate-500 truncate" title={log.workReport}>{log.workReport || '-'}</td>
                        <td className="p-4">{log.location.latitude !== 0 ? (<a href={`https://www.google.com/maps?q=${log.location.latitude},${log.location.longitude}`} target="_blank" className="text-blue-400 hover:text-blue-300 hover:underline flex items-center gap-1 text-xs font-medium"><MapPin size={14}/> {log.location.latitude.toFixed(5)}, {log.location.longitude.toFixed(5)}</a>) : <span className="text-xs text-slate-600 italic">Sistema</span>}{log.locationWarning && <span className="block text-[10px] text-rose-500 font-bold mt-1">⚠️ Fuera de rango</span>}</td>
                      </tr>
                    ))}
                    {getFilteredLogs().length === 0 && <tr><td colSpan={6} className="p-12 text-center text-slate-500 italic">No se encontraron registros.</td></tr>}
                  </tbody>
                </table>
              </div>
            </div>
          </div>
        )}

        {/* WORKERS TAB */}
        {activeTab === 'workers' && (
          <div className="bg-slate-900 p-6 rounded-xl border border-slate-800">
            <div className="flex flex-col md:flex-row gap-4 mb-8 bg-slate-950 p-6 rounded-xl border border-slate-800">
              <div className="flex-1 space-y-2"><label className="text-xs font-bold uppercase text-slate-500 tracking-wide">Nombre</label><input type="text" placeholder="Nombre del trabajador" className="w-full bg-slate-900 border border-slate-700 p-3 rounded-lg focus:border-blue-500 outline-none text-white" value={newWorkerName} onChange={(e) => setNewWorkerName(e.target.value)}/></div>
              <div className="w-full md:w-48 space-y-2"><label className="text-xs font-bold uppercase text-slate-500 tracking-wide">Modo</label><select className="w-full bg-slate-900 border border-slate-700 p-3 rounded-lg text-white text-sm outline-none" value={newWorkerMode} onChange={(e) => setNewWorkerMode(e.target.value as WorkMode)}><option value="HORAS">Por Horas</option><option value="DESTAJO">A Destajo</option></select></div>
              <div className="w-full md:w-32 space-y-2"><label className="text-xs font-bold uppercase text-slate-500 tracking-wide">PIN</label><input type="text" placeholder="0000" className="w-full bg-slate-900 border border-slate-700 p-3 rounded-lg text-center tracking-widest outline-none text-white" value={newWorkerPin} maxLength={4} onChange={(e) => setNewWorkerPin(e.target.value.replace(/\D/g,''))}/></div>
              <div className="flex items-end"><button onClick={handleAddWorker} className="bg-blue-600 text-white px-6 py-3 rounded-lg hover:bg-blue-500 flex items-center justify-center font-bold shadow-lg transition"><Plus size={20} /></button></div>
            </div>
            <div className="grid gap-4">
              {workers.map(w => (
                <div key={w.id} className="flex flex-col md:flex-row items-center justify-between p-4 border border-slate-800 rounded-xl hover:bg-slate-800/50 transition gap-4 bg-slate-900">
                  <div className="flex items-center gap-4"><div className="bg-slate-800 p-3 rounded-full hidden md:block text-slate-500"><Users size={20}/></div><div><h3 className="font-bold text-lg text-white">{w.name}</h3><div className="flex flex-col gap-1 mt-1"><div className="flex gap-2 text-xs"><span className="bg-slate-800 px-2 py-0.5 rounded text-slate-500 font-mono">ID: {w.id}</span><span className={`px-2 py-0.5 rounded font-bold uppercase ${w.defaultMode === 'DESTAJO' ? 'bg-purple-900/30 text-purple-400' : 'bg-blue-900/30 text-blue-400'}`}>{w.defaultMode || 'HORAS'}</span></div>{w.phone && <span className="text-xs text-slate-500 flex items-center gap-1"><Phone size={10}/> {w.phone}</span>}</div></div></div>
                  <button onClick={() => initiateDeleteWorker(w)} className="text-slate-500 hover:text-rose-500 p-2 hover:bg-rose-900/20 rounded-lg transition"><Trash2 size={20} /></button>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* SITES TAB */}
        {activeTab === 'sites' && (
           <div className="bg-slate-900 p-6 rounded-xl border border-slate-800">
              <div className="flex gap-2 mb-6"><input type="text" placeholder="Nombre Obra" className="flex-1 bg-slate-950 border border-slate-700 p-3 rounded-lg text-white focus:border-blue-500 outline-none" value={newSiteName} onChange={(e)=>setNewSiteName(e.target.value)}/><input type="text" placeholder="Dirección" className="flex-1 bg-slate-950 border border-slate-700 p-3 rounded-lg text-white focus:border-blue-500 outline-none" value={newSiteAddress} onChange={(e)=>setNewSiteAddress(e.target.value)}/><button onClick={handleAddSite} className="bg-blue-600 text-white p-3 rounded-lg hover:bg-blue-500"><Plus/></button></div>
              <div className="grid gap-4">{sites.map(s => (<div key={s.id} className="flex justify-between p-5 border border-slate-800 rounded-xl hover:bg-slate-800/30 transition"><div><h3 className="font-bold text-white">{s.name}</h3><p className="text-xs text-slate-400">{s.address}</p></div><button onClick={() => initiateDeleteSite(s)} className="text-slate-500 hover:text-rose-500"><Trash2/></button></div>))}</div>
           </div>
        )}

        {activeTab === 'reports' && (
           <div className="bg-slate-900 p-6 rounded-xl border border-slate-800">
              <div className="flex items-center gap-4 mb-6"><label className="text-slate-400 font-bold">Mes:</label><input type="month" className="bg-slate-950 border border-slate-700 p-2 rounded text-white" value={reportMonth} onChange={(e)=>setReportMonth(e.target.value)}/></div>
              <table className="w-full text-sm text-left text-slate-300"><thead><tr className="bg-slate-950 text-slate-500 uppercase"><th>Trabajador</th><th>Días</th><th>Horas</th><th>Acción</th></tr></thead><tbody className="divide-y divide-slate-800">{generateMonthlyReport().map(r => (<tr key={r.workerId} className="hover:bg-slate-800/50"><td className="p-3 font-bold text-white">{r.workerName}</td><td className="p-3">{r.daysWorked}</td><td className="p-3 text-blue-400">{msToTime(r.netWorkMs)}</td><td className="p-3"><button onClick={() => handleDownloadPDF(r)} className="text-emerald-500 font-bold hover:underline">PDF</button></td></tr>))}</tbody></table>
           </div>
        )}

        {/* CONFIG TAB */}
        {activeTab === 'config' && (
           <div className="bg-slate-900 p-8 rounded-xl border border-slate-800 max-w-xl mx-auto space-y-8">
              <div>
                <h3 className="font-bold text-lg mb-4 flex items-center gap-2 text-white"><Lock size={20} className="text-blue-500"/> Seguridad Admin</h3>
                <div className="bg-slate-950 p-6 rounded-xl border border-slate-800">
                  <label className="block text-xs font-bold uppercase text-slate-500 tracking-wider mb-2">Nueva Contraseña Maestra</label>
                  <div className="flex gap-2"><input type="password" placeholder="••••••" className="flex-1 bg-slate-950 border border-slate-700 p-3 rounded-lg text-white outline-none focus:border-blue-500 transition" value={newAdminPassword} onChange={(e) => setNewAdminPassword(e.target.value)}/></div>
                  <p className="text-xs text-slate-500 mt-2 italic">Deje en blanco si no desea cambiarla.</p>
                </div>
              </div>
              <div>
                <h3 className="font-bold text-lg mb-4 flex items-center gap-2 text-white"><Settings size={20} className="text-blue-500"/> Conexiones</h3>
                <div className="mb-4">
                  <label className="block text-xs font-bold uppercase text-slate-500 tracking-wider mb-2">Google Sheet URL</label>
                  <input type="text" className="w-full bg-slate-950 border border-slate-700 p-3 rounded-lg text-white font-mono text-xs" value={config.googleSheetUrl} onChange={(e)=>setConfig({...config, googleSheetUrl: e.target.value})}/>
                </div>
              </div>
              <button onClick={saveConfig} className="w-full bg-blue-600 text-white p-4 rounded-xl font-bold hover:bg-blue-500 shadow-lg transition uppercase tracking-widest text-sm">Guardar Configuración</button>
           </div>
        )}

      </div>
    </div>
  );
};
